const defaultLiveWorkspaceUrl = "http://127.0.0.1:4173/";

function isStaticRuntime() {
  if (typeof window === "undefined") {
    return false;
  }

  const host = window.location?.hostname || "";
  const search = window.location?.search || "";
  const protocol = window.location?.protocol || "";

  return Boolean(
    window.CARE_NOVA_FORCE_STATIC_RUNTIME === true
    || /(?:^|[?&])static=1(?:&|$)/.test(search)
    || /\.github\.io$/i.test(host)
    || protocol === "file:"
  );
}

function getStaticRuntimeHealth() {
  return {
    ok: true,
    status: "static-ready",
    mode: "github-pages-static-parity",
    runtime: "github-pages-static-parity",
    version: "static-browser",
    timestamp: new Date().toISOString()
  };
}

function getPreferredLiveWorkspaceUrl() {
  if (typeof window === "undefined") {
    return defaultLiveWorkspaceUrl;
  }

  if (isStaticRuntime()) {
    return defaultLiveWorkspaceUrl;
  }

  try {
    return new URL("/", window.location.href).href;
  } catch {
    return window.location.origin || defaultLiveWorkspaceUrl;
  }
}

