const languagePhrasePacks = Object.fromEntries(
  Object.keys(languageCatalog).map((code) => [
    code,
    Object.fromEntries(mergedLanguagePhraseRows.map(([source, translations]) => [source, code === "en" ? source : translations[code] || source]))
  ])
);

const languageTermPacks = Object.fromEntries(
  Object.keys(languageCatalog).map((code) => [
    code,
    mergedLanguageTermRows
      .map(([source, translations]) => [source, code === "en" ? source : translations[code] || source])
      .filter(([source, target]) => source !== target)
      .sort((a, b) => b[0].length - a[0].length)
  ])
);

function mergeLanguageRows(...rowGroups) {
  const merged = new Map();

  for (const rows of rowGroups) {
    for (const [source, translations] of rows) {
      merged.set(source, {
        ...(merged.get(source) || {}),
        ...(translations || {})
      });
    }
  }

  return Array.from(merged.entries());
}

