function createDeferredTask(task, delay = 120) {
  let timer = null;

  const run = (...args) => {
    if (timer) {
      window.clearTimeout(timer);
    }

    timer = window.setTimeout(() => {
      timer = null;
      task(...args);
    }, delay);
  };

  run.flush = (...args) => {
    if (timer) {
      window.clearTimeout(timer);
      timer = null;
    }

    task(...args);
  };

  return run;
}

function getInterfaceDomCache() {
  if (!interfaceDomCache) {
    interfaceDomCache = {
      interfaceTabs: Array.from(document.querySelectorAll(".interface-tab")),
      commandButtons: Array.from(document.querySelectorAll(".command-button")),
      interfaceViews: Array.from(document.querySelectorAll("[data-interface-view]")),
      modelTabs: Array.from(document.querySelectorAll(".model-tab")),
      modelPanels: Array.from(document.querySelectorAll("[data-model-panel]")),
      tabAgentPanels: Array.from(document.querySelectorAll(".tab-agent-panel")),
      tabAgentCockpits: Array.from(document.querySelectorAll(".tab-agent-cockpit")),
      agentCards: Array.from(document.querySelectorAll(".autonomous-agent-card")),
      workspaceSearchForms: Array.from(document.querySelectorAll(".workspace-search")),
      specialtyViews: Object.fromEntries(
        Object.keys(specialtyWorkspaces).map((key) => [key, document.querySelector(`[data-specialty-key="${key}"]`)])
      )
    };
  }

  return interfaceDomCache;
}

function invalidateInterfaceDomCache() {
  interfaceDomCache = null;
}

function invalidateWorkspaceSectionDomCache(interfaceName = null) {
  if (interfaceName) {
    workspaceSectionDomCache.delete(interfaceName);
    return;
  }

  workspaceSectionDomCache.clear();
}

function normalizeInterfaceName(interfaceName, fallback = "advisor") {
  const normalized = String(interfaceName || "").trim().toLowerCase();
  return interfaceNames.includes(normalized) ? normalized : fallback;
}

function normalizeThemeName(themeName, fallback = "") {
  const normalized = String(themeName || "").trim().toLowerCase();

  if (!normalized) {
    return fallback;
  }

  if (normalized === "night") {
    return "dark";
  }

  if (normalized === "light") {
    return "clinical";
  }

  return ["clinical", "dark", "calm"].includes(normalized) ? normalized : fallback;
}

function readInterfaceNameFromLocation() {
  if (typeof window === "undefined") {
    return "";
  }

  try {
    const searchParams = new URLSearchParams(window.location.search || "");
    const queryInterface = normalizeInterfaceName(
      searchParams.get("interface") || searchParams.get("tab") || searchParams.get("view"),
      ""
    );

    if (queryInterface) {
      return queryInterface;
    }
  } catch {
    // Ignore malformed query strings and fall back to saved local state.
  }

  const rawHash = (window.location.hash || "").replace(/^#/, "").trim();

  if (!rawHash) {
    return "";
  }

  let hash = rawHash;
  try {
    hash = decodeURIComponent(rawHash);
  } catch {
    hash = rawHash;
  }

  const normalizedHash = hash.replace(/^\/+/, "").trim();
  const directInterface = normalizeInterfaceName(normalizedHash, "");

  if (directInterface) {
    return directInterface;
  }

  try {
    const hashParams = new URLSearchParams(normalizedHash);
    return normalizeInterfaceName(
      hashParams.get("interface") || hashParams.get("tab") || hashParams.get("view"),
      ""
    );
  } catch {
    return "";
  }
}

function readThemeNameFromLocation() {
  if (typeof window === "undefined") {
    return "";
  }

  try {
    const searchParams = new URLSearchParams(window.location.search || "");
    const queryTheme = normalizeThemeName(searchParams.get("theme"), "");

    if (queryTheme) {
      return queryTheme;
    }
  } catch {
    // Ignore malformed query strings and fall back to saved local state.
  }

  const rawHash = (window.location.hash || "").replace(/^#/, "").trim();

  if (!rawHash) {
    return "";
  }

  try {
    const hashParams = new URLSearchParams(rawHash.replace(/^\/+/, "").trim());
    return normalizeThemeName(hashParams.get("theme"), "");
  } catch {
    return "";
  }
}

function getInterfaceHistoryState() {
  if (typeof window === "undefined") {
    return {};
  }

  const state = window.history?.state;
  return state && typeof state === "object" ? state : {};
}

function replaceInterfaceRouteState(interfaceName) {
  if (typeof window === "undefined" || !window.history?.replaceState) {
    return;
  }

  try {
    window.history.replaceState(
      { ...getInterfaceHistoryState(), careNovaInterface: interfaceName },
      "",
      window.location.href
    );
  } catch {
    // Routing state is progressive enhancement; navigation still works without it.
  }
}

function pushInterfaceRouteState(interfaceName) {
  if (typeof window === "undefined" || !window.history?.pushState) {
    return;
  }

  try {
    const currentStateInterface = normalizeInterfaceName(getInterfaceHistoryState().careNovaInterface, "");
    const currentRouteInterface = readInterfaceNameFromLocation();
    if (currentStateInterface === interfaceName && currentRouteInterface === interfaceName) {
      return;
    }

    const nextUrl = new URL(window.location.href);
    nextUrl.hash = `tab=${encodeURIComponent(interfaceName)}`;
    window.history.pushState(
      { ...getInterfaceHistoryState(), careNovaInterface: interfaceName },
      "",
      nextUrl.href
    );
  } catch {
    // Ignore URL sync failures in constrained browser contexts.
  }
}

function resolveLaunchExitInterface(interfaceName = "") {
  const explicitInterface = normalizeInterfaceName(interfaceName, "");

  if (explicitInterface) {
    return explicitInterface;
  }

  return readInterfaceNameFromLocation() || currentInterfaceName || loadStartupInterfaceName();
}

function normalizeLaunchRouteState(interfaceName = resolveLaunchExitInterface()) {
  if (typeof window === "undefined" || !window.history?.replaceState) {
    return;
  }

  try {
    const safeInterface = normalizeInterfaceName(interfaceName);
    const nextUrl = new URL(window.location.href);
    nextUrl.searchParams.delete("landing");
    nextUrl.searchParams.delete("download");
    nextUrl.searchParams.delete("app");
    nextUrl.searchParams.delete("cacheReset");
    nextUrl.hash = safeInterface ? `tab=${encodeURIComponent(safeInterface)}` : "";
    window.history.replaceState(
      { ...getInterfaceHistoryState(), careNovaInterface: safeInterface || null },
      "",
      nextUrl.href
    );
  } catch {
    // Launch route cleanup is best effort only.
  }
}

function syncInterfaceNavigationMetadata(activeInterfaceName = currentInterfaceName || "advisor") {
  const { interfaceTabs, interfaceViews } = getInterfaceDomCache();
  const commandHub = document.querySelector(".interface-tabs.nova-command-hub");
  const isDesktop = typeof window !== "undefined"
    && typeof window.matchMedia === "function"
    && window.matchMedia("(min-width: 1024px)").matches;
  const tabsByInterface = new Map();

  if (commandHub) {
    commandHub.setAttribute("role", "tablist");
    commandHub.setAttribute("aria-orientation", isDesktop ? "vertical" : "horizontal");
  }

  for (const tab of interfaceTabs) {
    const interfaceName = normalizeInterfaceName(tab.dataset.interface, "");

    if (!interfaceName) {
      continue;
    }

    if (!tab.id) {
      tab.id = `${interfaceName}InterfaceTab`;
    }

    tab.setAttribute("role", "tab");
    if (!tab.getAttribute("aria-label")) {
      const title = tab.querySelector("strong")?.textContent?.trim() || interfaceName;
      const detail = tab.querySelector("small")?.textContent?.trim();
      const label = detail ? `${title}: ${detail}` : title;
      tab.setAttribute("aria-label", label);
      tab.setAttribute("title", label);
    }
    tabsByInterface.set(interfaceName, tab);
  }

  for (const view of interfaceViews) {
    const interfaceName = normalizeInterfaceName(view.dataset.interfaceView, "");

    if (!interfaceName) {
      continue;
    }

    if (!view.id) {
      view.id = `${interfaceName}Interface`;
    }

    view.setAttribute("role", "tabpanel");

    const tab = tabsByInterface.get(interfaceName);
    if (tab) {
      tab.setAttribute("aria-controls", view.id);
      view.setAttribute("aria-labelledby", tab.id);
    } else {
      view.removeAttribute("aria-labelledby");
    }
  }

  for (const tab of interfaceTabs) {
    const isActive = tab.dataset.interface === activeInterfaceName;
    tab.setAttribute("aria-selected", String(isActive));
    tab.tabIndex = isActive ? 0 : -1;

    if (isActive) {
      tab.setAttribute("aria-current", "page");
    } else {
      tab.removeAttribute("aria-current");
    }
  }
}

function getNavigationScrollBehavior() {
  if (
    typeof window !== "undefined"
    && typeof window.matchMedia === "function"
    && window.matchMedia("(prefers-reduced-motion: reduce)").matches
  ) {
    return "auto";
  }

  return "smooth";
}

function isCompactCommandHubViewport() {
  return typeof window !== "undefined"
    && typeof window.matchMedia === "function"
    && window.matchMedia("(max-width: 1023px)").matches;
}

function keepCompactCommandHubPageStart() {
  if (!isCompactCommandHubViewport()) {
    return;
  }

  const commandHub = document.querySelector(".interface-tabs.nova-command-hub");

  if (!commandHub || window.scrollY <= 0) {
    return;
  }

  window.scrollTo({ top: 0, behavior: "auto" });
}

function scheduleCompactCommandHubPageStart() {
  if (!isCompactCommandHubViewport()) {
    return;
  }

  requestAnimationFrame(keepCompactCommandHubPageStart);
  window.setTimeout(keepCompactCommandHubPageStart, 80);
  window.setTimeout(keepCompactCommandHubPageStart, 260);
}

function scrollControlIntoView(control) {
  if (!control || typeof window === "undefined") {
    return;
  }

  window.requestAnimationFrame(() => {
    if (!control.isConnected) {
      return;
    }

    if (control.closest?.(".interface-tabs.nova-command-hub")) {
      scrollActiveInterfaceTabIntoView(getNavigationScrollBehavior());
      return;
    }

    const rect = control.getBoundingClientRect();
    const headerOffset = Number.parseFloat(
      window.getComputedStyle(document.documentElement).getPropertyValue("--fixed-header-height")
    ) || 72;
    const viewportTop = Math.max(12, headerOffset + 12);
    const viewportBottom = window.innerHeight - 12;
    const fullyVisible = rect.top >= viewportTop
      && rect.bottom <= viewportBottom
      && rect.left >= 8
      && rect.right <= window.innerWidth - 8;

    if (fullyVisible) {
      return;
    }

    control.scrollIntoView({
      block: "nearest",
      inline: "nearest",
      behavior: getNavigationScrollBehavior()
    });
  });
}

function syncActiveInterfaceTabIntoView(interfaceName = currentInterfaceName || "advisor") {
  if (typeof window === "undefined") {
    return;
  }

  if (interfaceNavigationFrame) {
    window.cancelAnimationFrame(interfaceNavigationFrame);
  }

  interfaceNavigationFrame = window.requestAnimationFrame(() => {
    interfaceNavigationFrame = null;
    const activeTab = getInterfaceDomCache().interfaceTabs
      .find((tab) => tab.dataset.interface === interfaceName);
    scrollControlIntoView(activeTab);
  });
}

function getRouteInterfaceFromEvent(event) {
  const stateInterface = normalizeInterfaceName(event?.state?.careNovaInterface, "");
  return stateInterface || readInterfaceNameFromLocation() || currentInterfaceName || "advisor";
}

function ensureInterfaceRouteSynchronization() {
  if (interfaceRouteNavigationBound || typeof window === "undefined") {
    return;
  }

  const handleRouteChange = (event) => {
    const nextInterface = getRouteInterfaceFromEvent(event);
    if (nextInterface && nextInterface !== currentInterfaceName) {
      switchInterface(nextInterface, true, { syncRoute: false });
    }
  };

  window.addEventListener("popstate", handleRouteChange);
  window.addEventListener("hashchange", handleRouteChange);
  interfaceRouteNavigationBound = true;
}
