let interfaceNavigationBound = false;
let workspaceSectionNavigationBound = false;
let activeInterfaceRailSyncBound = false;

function ensureInterfaceNavigation() {
  if (interfaceNavigationBound) {
    return;
  }

  document.addEventListener(
    "click",
    (event) => {
      const target = event.target;

      if (!target || typeof target.closest !== "function") {
        return;
      }

      const trigger = target.closest(".interface-tab, .command-button, .jump-to-advisor");

      if (!trigger) {
        return;
      }

      const requestedInterface = trigger.classList.contains("jump-to-advisor")
        ? "advisor"
        : trigger.dataset.interface || trigger.dataset.commandInterface;

      if (!requestedInterface || !interfaceNames.includes(requestedInterface)) {
        return;
      }

      event.preventDefault();
      switchInterface(requestedInterface, true);
    },
    true
  );

  document.addEventListener("keydown", (event) => {
    const target = event.target;

    if (!target || typeof target.closest !== "function") {
      return;
    }

    const currentTab = target.closest(".interface-tab");
    const navigationKeys = ["ArrowUp", "ArrowDown", "ArrowLeft", "ArrowRight", "Home", "End"];

    if (!currentTab || !navigationKeys.includes(event.key)) {
      return;
    }

    const tabs = getInterfaceDomCache().interfaceTabs
      .filter((tab) => normalizeInterfaceName(tab.dataset.interface, "") && !tab.disabled);

    if (!tabs.length) {
      return;
    }

    const currentIndex = tabs.indexOf(currentTab);
    const lastIndex = tabs.length - 1;
    const nextIndex = event.key === "Home"
      ? 0
      : event.key === "End"
        ? lastIndex
        : event.key === "ArrowDown" || event.key === "ArrowRight"
          ? (currentIndex + 1 + tabs.length) % tabs.length
          : (currentIndex - 1 + tabs.length) % tabs.length;
    const nextTab = tabs[nextIndex];
    const requestedInterface = nextTab?.dataset.interface;

    if (!nextTab || !requestedInterface) {
      return;
    }

    event.preventDefault();
    nextTab.focus();
    switchInterface(requestedInterface, true);
  });

  ensureInterfaceRouteSynchronization();
  interfaceNavigationBound = true;
}

function ensureWorkspaceSectionNavigation() {
  if (workspaceSectionNavigationBound) {
    return;
  }

  document.addEventListener("click", (event) => {
    const target = event.target;

    if (!target || typeof target.closest !== "function") {
      return;
    }

    const button = target.closest("[data-workspace-section-button]");

    if (!button) {
      return;
    }

    const interfaceName = button.dataset.workspaceSectionInterface || currentInterfaceName || "advisor";
    const tabId = button.dataset.workspaceSectionButton;

    if (!tabId) {
      return;
    }

    event.preventDefault();
    activateWorkspaceSubtab(interfaceName, tabId, true);
  });

  document.addEventListener("keydown", (event) => {
    const target = event.target;

    if (!target || typeof target.closest !== "function") {
      return;
    }

    const button = target.closest("[data-workspace-section-button]");

    if (!button || !["ArrowLeft", "ArrowRight", "ArrowUp", "ArrowDown", "Home", "End"].includes(event.key)) {
      return;
    }

    const interfaceName = button.dataset.workspaceSectionInterface || currentInterfaceName || "advisor";
    const state = getWorkspaceSectionState(interfaceName);

    if (!state?.buttons.length) {
      return;
    }

    const currentIndex = state.buttons.indexOf(button);
    const lastIndex = state.buttons.length - 1;
    const nextIndex = event.key === "Home"
      ? 0
      : event.key === "End"
        ? lastIndex
        : event.key === "ArrowRight" || event.key === "ArrowDown"
          ? (currentIndex + 1 + state.buttons.length) % state.buttons.length
          : (currentIndex - 1 + state.buttons.length) % state.buttons.length;
    const nextButton = state.buttons[nextIndex];

    if (!nextButton) {
      return;
    }

    event.preventDefault();
    nextButton.focus();
    activateWorkspaceSubtab(interfaceName, nextButton.dataset.workspaceSectionButton, true);
  });

  workspaceSectionNavigationBound = true;
}

ensureInterfaceNavigation();
ensureWorkspaceSectionNavigation();

