  elements.clearInput.addEventListener("click", () => {
    clearInput();
    activateWorkspaceSubtab("advisor", "ask", true);
  });
  elements.exportReport.addEventListener("click", exportReport);
  elements.resetDemo.addEventListener("click", resetDemo);

  if (elements.addPatient) {
    elements.addPatient.addEventListener("click", addPatientRecord);
  }

  if (elements.savePatient) {
    elements.savePatient.addEventListener("click", () => {
      scheduleProfileDraftRefresh.flush();
      persistProfileFromForm({
        statusMessage: "Patient profile saved and agent context refreshed."
      });
    });
  }

  if (elements.deletePatient) {
    elements.deletePatient.addEventListener("click", deleteActivePatientRecord);
  }

  if (elements.profileCopyCard) {
    elements.profileCopyCard.addEventListener("click", copyProfileCareCard);
  }

  if (elements.profileDownloadCard) {
    elements.profileDownloadCard.addEventListener("click", downloadProfileCareCard);
  }

