atlasExtraGuides.push(...atlasAdvancedGuidePacks, ...atlasDeepClinicalGuidePacks, ...atlasReferenceExpansionPacks, ...atlasPrecisionGuidePacks);

for (const guide of atlasExtraGuides) {
  atlasGuideDetails[guide.title.toLowerCase()] = guide.detail;
}

function normalizeAtlasText(value) {
  return String(value || "").toLowerCase().replace(/\s+/g, " ").trim();
}

function isAtlasGuidedMode() {
  return (document.body.dataset.uiMode || "guided") !== "expert";
}

function hasAtlasAgentOutput(atlas = document.querySelector('[data-interface-view="atlas"]')) {
  const result = atlas?.querySelector("[data-atlas-agent-result]");
  return result?.classList.contains("atlas-output-ready") || result?.classList.contains("is-loading");
}

function getAtlasIdleFallbackSection(requestedSection = "") {
  const safeSection = String(requestedSection || "").trim();

  if (safeSection && safeSection !== "agent") {
    return safeSection;
  }

  return hasAtlasAgentOutput() ? (safeSection || "agent") : "guides";
}

function syncAtlasGuidedEntrySection() {
  const atlas = document.querySelector('[data-interface-view="atlas"]');

  if (!atlas) {
    return;
  }

  const activeSection = atlas.dataset.activeWorkspaceSection || "";
  const fallbackSection = getAtlasIdleFallbackSection(activeSection);

  if (fallbackSection !== activeSection) {
    activateWorkspaceSubtab("atlas", fallbackSection, false);
  }
}

function invalidateAtlasDomCache() {
  atlasDomCache = null;
}

function getAtlasDomCache() {
  if (atlasDomCache?.root?.isConnected) {
    return atlasDomCache;
  }

  const previousState = atlasDomCache?.state || { activeFilter: "all", running: false };
  const root = document.querySelector('[data-interface-view="atlas"]');

  if (!root) {
    atlasDomCache = {
      root: null,
      search: null,
      formType: null,
      formArea: null,
      formGoal: null,
      formAudience: null,
      formDepth: null,
      formQuery: null,
      formBuild: null,
      formAsk: null,
      formClear: null,
      grid: null,
      empty: null,
      resultSummary: null,
      showAll: null,
      topicToggle: null,
      totalGuides: null,
      visibleGuides: null,
      result: null,
      filters: [],
      guideEntries: [],
      formTopicButtons: [],
      topicButtons: [],
      state: previousState
    };
    return atlasDomCache;
  }

  const guideEntries = Array.from(root.querySelectorAll("[data-atlas-item]")).map((item) => {
    const categoryText = normalizeAtlasText(item.dataset.atlasCategory);
    const dataQuery = normalizeAtlasText(item.dataset.atlasQuery || "");
    const titleNode = item.querySelector(".atlas-topic-head strong");
    const subtitleNode = item.querySelector(".atlas-topic-head small");
    const title = normalizeAtlasText(titleNode?.textContent || "");
    const subtitle = normalizeAtlasText(subtitleNode?.textContent || "");
    const bodyText = normalizeAtlasText(item.textContent || "");

    return {
      item,
      categories: categoryText ? categoryText.split(" ") : [],
      dataQuery,
      title,
      subtitle,
      haystack: normalizeAtlasText(`${categoryText} ${dataQuery} ${bodyText}`),
      displayTitle: titleNode?.textContent?.trim() || "",
      displaySubtitle: subtitleNode?.textContent?.trim() || "",
      details: item.querySelector(".atlas-topic-details")
    };
  });

  atlasDomCache = {
    root,
    search: root.querySelector("[data-atlas-library-search]"),
    formType: root.querySelector("[data-atlas-form-type]"),
    formArea: root.querySelector("[data-atlas-form-area]"),
    formGoal: root.querySelector("[data-atlas-form-goal]"),
    formAudience: root.querySelector("[data-atlas-form-audience]"),
    formDepth: root.querySelector("[data-atlas-form-depth]"),
    formQuery: root.querySelector("[data-atlas-form-query]"),
    formBuild: root.querySelector("[data-atlas-form-build]"),
    formAsk: root.querySelector("[data-atlas-form-ask]"),
    formClear: root.querySelector("[data-atlas-form-clear]"),
    grid: root.querySelector("[data-atlas-library-grid]"),
    empty: root.querySelector("[data-atlas-empty]"),
    resultSummary: root.querySelector("[data-atlas-result-summary]"),
    showAll: root.querySelector("[data-atlas-show-all]"),
    topicToggle: root.querySelector("[data-atlas-topic-toggle]"),
    totalGuides: root.querySelector("[data-atlas-total-guides]"),
    visibleGuides: root.querySelector("[data-atlas-visible-guides]"),
    result: root.querySelector("[data-atlas-agent-result]"),
    filters: Array.from(root.querySelectorAll("[data-atlas-filter]")),
    guideEntries,
    formTopicButtons: Array.from(root.querySelectorAll("[data-atlas-form-topic]")),
    topicButtons: Array.from(root.querySelectorAll("[data-atlas-topic]")),
    state: previousState
  };

  return atlasDomCache;
}

function initializeAtlasLibrary() {
  const atlas = document.querySelector('[data-interface-view="atlas"]');

  if (!atlas || atlas.dataset.atlasLibraryReady === "true") {
    return;
  }

  renderExtraAtlasGuides(atlas);
  hydrateAtlasGuideDetails(atlas);

  const {
    search,
    formType,
    formArea,
    formGoal,
    formAudience,
    formDepth,
    formQuery,
    formBuild,
    formAsk,
    formClear,
    filters,
    guideEntries,
    empty,
    resultSummary,
    showAll,
    topicToggle,
    totalGuides,
    visibleGuides,
    state
  } = getAtlasDomCache();

  const resetAtlasLibrary = ({ keepAgent = true } = {}) => {
    for (const control of [formType, formArea, formGoal, formAudience, formDepth, formQuery, search].filter(Boolean)) {
      control.value = "";
    }
    setActiveFilter("all");
    activateWorkspaceSubtab("atlas", "guides", true);
    if (!keepAgent) {
      renderAtlasAgentIdle(atlas);
    }
  };

  const syncTopicChipVisibility = (expanded = false) => {
    const actions = atlas.querySelector(".atlas-form-actions");
    const chips = Array.from(atlas.querySelectorAll(".atlas-form-chip"));

    actions?.classList.toggle("is-chip-collapsed", !expanded);
    chips.forEach((chip, index) => {
      chip.hidden = !expanded && index >= 7;
    });
    if (topicToggle) {
      topicToggle.setAttribute("aria-expanded", String(expanded));
      topicToggle.textContent = expanded ? "Fewer topics" : "More topics";
    }
  };

  const applyLibraryFilter = () => {
    const query = normalizeAtlasText(search?.value);
    const terms = query ? query.split(" ") : [];
    const shouldLimitGuidedResults = isAtlasGuidedMode() && state.activeFilter === "all" && !query;
    const guidedLimit = shouldLimitGuidedResults ? 16 : Number.POSITIVE_INFINITY;
    let visibleCount = 0;
    let matchCount = 0;

    for (const entry of guideEntries) {
      const categoryMatches = state.activeFilter === "all" || entry.categories.includes(state.activeFilter);
      const queryMatches = terms.every((term) => entry.haystack.includes(term));
      const isMatch = categoryMatches && queryMatches;
      const isVisible = isMatch && visibleCount < guidedLimit;
      const shouldHide = !isVisible;

      if (entry.item.hidden !== shouldHide) {
        entry.item.hidden = shouldHide;
      }

      if (!isVisible || !isMatch) {
        if (entry.details?.open) {
          entry.details.open = false;
        }
        entry.item.dataset.atlasOpen = "false";
      }

      if (isMatch) {
        matchCount += 1;
      }

      if (isVisible) {
        visibleCount += 1;
      }
    }

    if (empty) {
      empty.hidden = visibleCount > 0;
    }

    const totalText = `${guideEntries.length} Guides`;
    const visibleText = shouldLimitGuidedResults && matchCount > visibleCount
      ? `${visibleCount} Featured`
      : `${visibleCount} Showing`;

    if (totalGuides && totalGuides.textContent !== totalText) {
      totalGuides.textContent = totalText;
    }

    if (visibleGuides && visibleGuides.textContent !== visibleText) {
      visibleGuides.textContent = visibleText;
    }

    if (resultSummary) {
      const filterLabel = state.activeFilter === "all"
        ? "all categories"
        : filters.find((option) => option.dataset.atlasFilter === state.activeFilter)?.textContent?.trim() || state.activeFilter;
      const queryLabel = query ? ` matching "${search.value.trim()}"` : "";
      resultSummary.textContent = visibleCount > 0
        ? `${visibleText} in ${filterLabel}${queryLabel}.`
        : `No guides found in ${filterLabel}${queryLabel}.`;
    }

    if (showAll) {
      const shouldHideShowAll = state.activeFilter === "all" && !query;
      showAll.hidden = shouldHideShowAll;
      if (shouldHideShowAll) {
        showAll.style.setProperty("display", "none", "important");
      } else {
        showAll.style.removeProperty("display");
      }
    }

    return visibleCount;
  };

  const setActiveFilter = (nextFilter = "all", shouldApply = true) => {
    state.activeFilter = nextFilter || "all";

    for (const option of filters) {
      const isActive = (option.dataset.atlasFilter || "all") === state.activeFilter;
      option.classList.toggle("is-active", isActive);
      option.setAttribute("aria-pressed", String(isActive));
    }

    if (shouldApply) {
      applyLibraryFilter();
    }
  };

  const scoreAtlasGuide = (entry, searchText = "") => {
    const query = normalizeAtlasText(searchText);
    const terms = query ? query.split(" ") : [];
    let score = 0;

    if (!query) {
      return score;
    }

    if (entry.title === query) {
      score += 140;
    }

    if (entry.title.includes(query)) {
      score += 90;
    }

    if (entry.dataQuery.includes(query)) {
      score += 60;
    }

    for (const term of terms) {
      if (entry.title.includes(term)) {
        score += 18;
      }
      if (entry.subtitle.includes(term)) {
        score += 10;
      }
      if (entry.dataQuery.includes(term)) {
        score += 8;
      }
      if (entry.haystack.includes(term)) {
        score += 2;
      }
    }

    return score;
  };

  const openBestVisibleGuide = () => {
    const visibleEntries = guideEntries.filter((entry) => !entry.item.hidden);

    if (!visibleEntries.length) {
      return;
    }

    const searchText = search?.value || "";
    const bestEntry = visibleEntries
      .map((entry) => ({ entry, score: scoreAtlasGuide(entry, searchText) }))
      .sort((left, right) => right.score - left.score)[0]?.entry || visibleEntries[0];
    const details = bestEntry.details || bestEntry.item.querySelector(".atlas-topic-details");

    if (details) {
      details.open = true;
    }
    bestEntry.item.scrollIntoView({ block: "start", behavior: "smooth" });
  };

  const runAtlasFormSearch = ({ activateGuides = true } = {}) => {
    const type = formType?.value || "";
    const area = formArea?.value || "";
    const goal = formGoal?.value || "";
    const audience = formAudience?.value || "";
    const depth = formDepth?.value || "";
    const libraryQuery = search?.value || "";
    const query = formQuery?.value || libraryQuery;
    const fallbackTerms = normalizeAtlasText(query)
      .split(" ")
      .filter((term) => term.length > 2 && !["and", "atlas", "care", "guide", "health", "match", "medical", "question", "questions", "with"].includes(term))
      .slice(0, 6);
    const searchOptions = [
      [query, area, goal, audience, depth],
      [query, area, goal],
      [query, area, audience],
      [query, goal, depth],
      [query],
      ...fallbackTerms.map((term) => [term]),
      [area],
      [goal],
      [audience],
      [depth]
    ]
      .map((parts) => parts.filter(Boolean).join(" ").trim())
      .filter(Boolean);

    if (formQuery && !formQuery.value && libraryQuery) {
      formQuery.value = libraryQuery;
    }

    setActiveFilter(type || "all", false);

    let visibleCount = 0;
    for (const searchText of searchOptions.length ? searchOptions : [""]) {
      if (search) {
        search.value = searchText;
      }
      visibleCount = applyLibraryFilter();
      if (visibleCount > 0) {
        break;
      }
    }

    if (visibleCount === 0 && type) {
      setActiveFilter("all", false);
      visibleCount = applyLibraryFilter();
    }

    if (visibleCount === 0 && search && query) {
      search.value = query;
      visibleCount = applyLibraryFilter();
    }

    if (activateGuides) {
      activateWorkspaceSubtab("atlas", "guides", true);
    }

    openBestVisibleGuide();
  };

  const scheduleLibraryFilter = createDeferredTask(applyLibraryFilter, 90);

  atlas.addEventListener("click", async (event) => {
    const target = event.target;

    if (!(target instanceof Element)) {
      return;
    }

    const filter = target.closest("[data-atlas-filter]");
    if (filter && atlas.contains(filter)) {
      activateWorkspaceSubtab("atlas", "guides", true);
      if (search?.value && search.offsetParent === null) {
        search.value = "";
      }
      setActiveFilter(filter.dataset.atlasFilter || "all");
      return;
    }

    const topicControl = target.closest("[data-atlas-form-topic]");
    if (topicControl && atlas.contains(topicControl)) {
      if (formQuery) {
        formQuery.value = topicControl.dataset.atlasFormTopic || "";
      }
      runAtlasFormSearch({ activateGuides: true });
      return;
    }

    const topicButton = target.closest("[data-atlas-topic]");
    if (topicButton && atlas.contains(topicButton)) {
      await runAtlasTopic(topicButton);
    }
  });

  search?.addEventListener("input", scheduleLibraryFilter);
  search?.addEventListener("keydown", (event) => {
    if (event.key === "Enter") {
      event.preventDefault();
      runAtlasFormSearch({ activateGuides: true });
    }
  });

  formBuild?.addEventListener("click", () => runAtlasFormSearch({ activateGuides: true }));
  formAsk?.addEventListener("click", async () => {
    runAtlasFormSearch({ activateGuides: false });
    await runAtlasAgent(collectAtlasFormRequest(atlas));
  });
  formQuery?.addEventListener("keydown", (event) => {
    if (event.key === "Enter") {
      event.preventDefault();
      runAtlasFormSearch({ activateGuides: false });
      runAtlasAgent(collectAtlasFormRequest(atlas));
    }
  });
  formClear?.addEventListener("click", () => {
    resetAtlasLibrary({ keepAgent: false });
  });
  showAll?.addEventListener("click", () => resetAtlasLibrary({ keepAgent: true }));
  topicToggle?.addEventListener("click", () => {
    const expanded = topicToggle.getAttribute("aria-expanded") !== "true";
    syncTopicChipVisibility(expanded);
  });

  atlas.dataset.atlasLibraryReady = "true";
  syncTopicChipVisibility(false);
  renderAtlasAgentIdle(atlas);
  applyLibraryFilter();
  syncAtlasGuidedEntrySection();
}

function renderExtraAtlasGuides(atlas) {
  const grid = atlas.querySelector("[data-atlas-library-grid]");

  if (!grid || grid.dataset.atlasExtraGuides === "true") {
    return;
  }

  const fragment = document.createDocumentFragment();

  for (const guide of atlasExtraGuides) {
    const card = document.createElement("article");
    const head = document.createElement("div");
    const icon = document.createElement("span");
    const titleWrap = document.createElement("div");
    const title = document.createElement("strong");
    const subtitle = document.createElement("small");
    const list = document.createElement("ul");
    const button = document.createElement("button");

    card.className = "atlas-topic-card";
    card.setAttribute("data-atlas-item", "");
    card.dataset.atlasCategory = guide.category;
    card.dataset.atlasQuery = guide.query;
    head.className = "atlas-topic-head";
    icon.className = `atlas-topic-icon${guide.danger ? " atlas-topic-danger" : ""}`;
    title.textContent = guide.title;
    subtitle.textContent = guide.subtitle;
    titleWrap.append(title, subtitle);
    icon.append(createIcon(guide.icon, "ui-icon"));
    head.append(icon, titleWrap);

    for (const item of guide.bullets) {
      const li = document.createElement("li");
      li.textContent = item;
      list.append(li);
    }

    button.className = "atlas-topic-action";
    button.type = "button";
    button.dataset.atlasTopic = guide.prompt;
    button.textContent = "Open guide";
    card.append(head, list, button);
    fragment.append(card);
  }

  grid.append(fragment);
  grid.dataset.atlasExtraGuides = "true";
  invalidateAtlasDomCache();
}

function hydrateAtlasGuideDetails(atlas) {
  let openDetails = null;
  const usedGuideDetailIds = new Set(
    Array.from(atlas.querySelectorAll(".atlas-topic-details[id]"))
      .map((details) => details.id)
  );

  for (const card of atlas.querySelectorAll("[data-atlas-item]")) {
    const title = card.querySelector(".atlas-topic-head strong")?.textContent?.trim().toLowerCase();
    const detail = atlasGuideDetails[title];

    if (!detail || card.querySelector(".atlas-topic-details")) {
      continue;
    }

    const details = document.createElement("details");
    const summary = document.createElement("summary");
    const grid = document.createElement("div");
    const slug = title.replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "") || "topic";
    const baseId = `atlas-guide-${slug}`;
    let safeId = baseId;
    let suffix = 2;

    while (usedGuideDetailIds.has(safeId)) {
      safeId = `${baseId}-${suffix}`;
      suffix += 1;
    }
    usedGuideDetailIds.add(safeId);

    details.className = "atlas-topic-details";
    details.id = safeId;
    card.dataset.atlasOpen = card.dataset.atlasOpen || "false";
    grid.className = "atlas-detail-grid";
    summary.append(createIcon("icon-layers", "chip-icon"), document.createTextNode("Open guide details"));
    details.append(summary, grid);

    for (const section of [
      ["Overview", detail.know],
      ["Symptoms & tracking", detail.track],
      ["Care options", detail.ask],
      ["Precautions", detail.safety]
    ]) {
      grid.append(createAtlasDetailColumn(section[0], section[1]));
    }

    const action = card.querySelector(".atlas-topic-action");
    if (action) {
      action.setAttribute("aria-controls", safeId);
      action.setAttribute("aria-expanded", String(details.open));
    }
    action?.before(details);

    details.addEventListener("toggle", () => {
      card.dataset.atlasOpen = details.open ? "true" : "false";
      action?.setAttribute("aria-expanded", String(details.open));

      if (!details.open) {
        if (openDetails === details) {
          openDetails = null;
        }
        return;
      }

      if (openDetails && openDetails !== details) {
        openDetails.open = false;
      }

      openDetails = details;
    });
  }

  invalidateAtlasDomCache();
}

function createAtlasDetailColumn(title, items = []) {
  const section = document.createElement("section");
  const heading = document.createElement("strong");
  const list = document.createElement("ul");

  section.className = "atlas-detail-section";
  heading.textContent = title;

  for (const item of items) {
    const li = document.createElement("li");
    li.textContent = item;
    list.append(li);
  }

  section.append(heading, list);
  return section;
}

async function runAtlasTopic(button) {
  if (getAtlasDomCache().state.running) {
    return;
  }

  const card = button.closest("[data-atlas-item]");
  const details = card?.querySelector(".atlas-topic-details");
  const message = (button.dataset.atlasTopic || "").trim();

  if (!message) {
    return;
  }

  switchInterface("atlas", true);

  if (details) {
    details.open = true;
    button.setAttribute("aria-expanded", "true");
    details.scrollIntoView({ block: "nearest", behavior: "smooth" });
    button.textContent = "Guide open";
    window.setTimeout(() => {
      button.textContent = "Open guide";
    }, 1200);
  }

  await runAtlasAgent(message, card);
}

function collectAtlasFormRequest(atlas) {
  const cache = getAtlasDomCache();
  const selectedText = (control) => control?.selectedOptions?.[0]?.textContent || "";
  const formType = selectedText(cache.formType);
  const formArea = selectedText(cache.formArea);
  const formGoal = selectedText(cache.formGoal);
  const formAudience = selectedText(cache.formAudience);
  const formDepth = selectedText(cache.formDepth);
  const formQuery = cache.formQuery?.value.trim() || "";
  const libraryQuery = cache.search?.value.trim() || "";
  const parts = [
    formQuery || libraryQuery || specialtyWorkspaces.atlas.template,
    formType && formType !== "Any topic" ? `Topic type: ${formType}` : "",
    formArea && formArea !== "All health areas" ? `Health area: ${formArea}` : "",
    formGoal && formGoal !== "Any goal" ? `Learning goal: ${formGoal}` : "",
    formAudience && formAudience !== "Anyone" ? `Reader: ${formAudience}` : "",
    formDepth && formDepth !== "Best match" ? `Guide style: ${formDepth}` : ""
  ].filter(Boolean);

  return parts.join(". ");
}

function buildAtlasAgentMessage(message, card = null) {
  const title = card?.querySelector(".atlas-topic-head strong")?.textContent?.trim() || "";
  const subtitle = card?.querySelector(".atlas-topic-head small")?.textContent?.trim() || "";
  const cardText = card
    ? Array.from(card.querySelectorAll(":scope > ul > li")).map((item) => item.textContent.trim()).filter(Boolean).join(" ")
    : "";
  const guideContext = title
    ? `Selected guide title: ${title}.\nSelected guide subtitle: ${subtitle || "Reference guide"}.\nSelected guide notes: ${cardText}`
    : "";

  return [
    `Medical atlas request: ${message}`,
    guideContext,
    "Return a medical-library answer with overview, what to track, care questions, precautions, and source coverage. Keep it educational, precise, and safe."
  ].filter(Boolean).join("\n\n");
}

function renderAtlasAgentLoading(message = "") {
  const { result: resultNode } = getAtlasDomCache();

  if (!resultNode) {
    return;
  }

  clearNode(resultNode);
  resultNode.classList.remove("is-idle", "atlas-output-ready");
  resultNode.classList.add("is-loading");
  resultNode.setAttribute("aria-busy", "true");

  const loadingLayout = document.createElement("div");
  const loadingCopy = document.createElement("div");
  const loadingTitle = document.createElement("strong");
  const loadingDetail = document.createElement("span");
  const steps = document.createElement("div");

  loadingLayout.className = "atlas-agent-loading-layout";
  loadingCopy.className = "atlas-agent-loading-copy";
  steps.className = "atlas-agent-loading-steps";
  loadingTitle.textContent = "Atlas Agent is matching local medical references...";
  loadingDetail.textContent = message ? `Topic: ${message.slice(0, 110)}` : "Building a focused medical-library answer.";
  loadingCopy.append(loadingTitle, loadingDetail);

  for (const step of ["Guide match", "Safety boundary", "Care questions"]) {
    const chip = document.createElement("span");
    chip.textContent = step;
    steps.append(chip);
  }

  loadingLayout.append(createIcon("icon-route", "atlas-agent-spinner"), loadingCopy, steps);
  resultNode.append(loadingLayout);
}

function renderAtlasAgentIdle(atlas = document.querySelector('[data-interface-view="atlas"]')) {
  const resultNode = getAtlasDomCache().result || atlas?.querySelector("[data-atlas-agent-result]");

  if (!resultNode) {
    return;
  }

  clearNode(resultNode);
  resultNode.classList.add("is-idle");
  resultNode.classList.remove("is-loading", "atlas-output-ready");
  resultNode.setAttribute("aria-busy", "false");
  const icon = document.createElement("span");
  const title = document.createElement("strong");
  const copy = document.createElement("span");

  icon.className = "atlas-agent-empty-icon";
  icon.append(createIcon("icon-health", "ui-icon"));
  title.textContent = "Choose a guide or ask the Atlas Agent.";
  copy.textContent = "Enter a disease, symptom, medicine, report, prevention topic, or warning sign above.";
  resultNode.append(icon, title, copy);
}

function renderAtlasAgentError(message = "The Atlas Agent could not process this request.") {
  const resultNode = getAtlasDomCache().result;

  if (!resultNode) {
    return;
  }

  clearNode(resultNode);
  resultNode.classList.add("is-idle");
  resultNode.classList.remove("is-loading", "atlas-output-ready");
  resultNode.setAttribute("aria-busy", "false");

  const icon = document.createElement("span");
  const title = document.createElement("strong");
  const copy = document.createElement("span");

  icon.className = "atlas-agent-empty-icon";
  icon.append(createIcon("icon-alert", "ui-icon"));
  title.textContent = "Atlas answer could not be created.";
  copy.textContent = message;
  resultNode.append(icon, title, copy);
}

async function runAtlasAgent(message, card = null) {
  const { state } = getAtlasDomCache();

  if (state.running) {
    return;
  }

  const cleanMessage = String(message || "").trim() || specialtyWorkspaces.atlas.template;
  const agentMessage = buildAtlasAgentMessage(cleanMessage, card);

  switchInterface("atlas", true);
  activateWorkspaceSubtab("atlas", "agent", true);
  prepareWorkspaceSearch("atlas", cleanMessage);
  state.running = true;
  setAtlasLoading(true);
  renderAtlasAgentLoading(cleanMessage);

  try {
    return await runAnalysis(agentMessage, {
      interfaceName: "atlas",
      singleAgentMode: true,
      preferredAgent: "RAG_AGENT",
      answerMode: "deep",
      context: {
        ...workspaceSearchConfig.atlas.context,
        careGoal: "understand"
      }
    });
  } finally {
    setAtlasLoading(false);
  }
}

function setAtlasLoading(isLoading) {
  const { root, formAsk, result, topicButtons, state } = getAtlasDomCache();

  state.running = isLoading;

  if (root) {
    root.classList.toggle("is-running", isLoading);
    root.setAttribute("aria-busy", String(isLoading));
  }

  if (result) {
    result.setAttribute("aria-busy", String(isLoading));
  }

  if (formAsk) {
    formAsk.disabled = isLoading;
    formAsk.textContent = isLoading ? "Asking Atlas..." : "Ask Atlas Agent";
  }

  for (const button of topicButtons) {
    button.disabled = isLoading;
  }
}

