function seedVitalsDemoReports() {
  const seedPlan = [
    { exampleId: "baseline", daysAgo: 6, hour: 7, minute: 25, note: "Stable fasting baseline after rest.", label: "Vitals demo - baseline day" },
    { exampleId: "fitness", daysAgo: 4, hour: 7, minute: 40, note: "Lifestyle review with BMI, steps, and hydration context.", label: "Vitals demo - BMI and daily routine" },
    { exampleId: "sugar", daysAgo: 3, hour: 20, minute: 10, note: "After-meal glucose pattern with home monitoring context.", label: "Vitals demo - glucose pattern review" },
    { exampleId: "fever", daysAgo: 2, hour: 18, minute: 5, note: "Temperature and oxygen review while unwell.", label: "Vitals demo - fever and oxygen check" },
    { exampleId: "high-bp", daysAgo: 0, hour: 21, minute: 15, note: "Evening blood pressure recheck with low sleep and hydration.", label: "Vitals demo - high BP follow-up" }
  ];
  const seededEntries = seedPlan
    .map((item) => {
      const date = new Date();
      date.setDate(date.getDate() - item.daysAgo);
      date.setHours(item.hour, item.minute, 0, 0);
      return {
        entry: createVitalsTrendEntryFromSeed(item.exampleId, date.toISOString(), item.note),
        label: item.label
      };
    })
    .filter((item) => item.entry);

  if (!seededEntries.length) {
    setVitalsRecordStatus("Could not build demo vitals reports.", "medium");
    return;
  }

  const trendById = new Map(loadVitalsTrendLog().map((entry) => [entry.id, entry]));
  for (const item of seededEntries) {
    trendById.set(item.entry.id, item.entry);
  }
  const nextTrendLog = Array.from(trendById.values())
    .sort((left, right) => new Date(right.createdAt).getTime() - new Date(left.createdAt).getTime())
    .slice(0, 180);

  saveVitalsTrendLog(nextTrendLog);

  const recordsById = new Map(loadPatientDataRecords().map((record) => [record.id, record]));
  for (const item of seededEntries) {
    const input = buildVitalsInputFromTrendEntry(item.entry);
    const assessments = buildVitalsAssessments(input);
    const bmi = calculateVitalsBmi(input.weight, input.height);
    const quality = buildVitalsQuality(input);
    const report = buildVitalsReportText(input, assessments, bmi, quality, buildVitalsTrendSummary(nextTrendLog, input), nextTrendLog);
    const record = buildVitalsRecordFromEntry(item.entry, report, item.label);
    const existingRecord = recordsById.get(record.id);

    record.correctionHistory = buildRecordCorrectionHistory(existingRecord, record);
    recordsById.set(record.id, record);
  }

  const latestSeed = seededEntries[seededEntries.length - 1];
  const selectedRecordId = `record-${latestSeed.entry.id}`;
  const nextRecords = sortPatientDataRecords(Array.from(recordsById.values())).slice(0, 300);

  applyVitalsExample("high-bp");
  savePatientDataRecordsLocal(nextRecords);
  setSelectedPatientDataRecordId(selectedRecordId);
  renderPatientDataRecords({ force: true });
  persistPatientDataRecords(nextRecords, selectedRecordId);
  renderVitalsReview();
  updateCareCompass();
  activateWorkspaceSubtab("vitals", "trends", true);
  setVitalsRecordStatus(`Loaded ${seededEntries.length} demo vitals reports and saved them locally for this patient.`, "low");
}

