function renderVitalsReview() {
  const cache = getVitalsDomCache();
  const rawInput = collectVitalsAgentInputs();
  const validationIssues = getVitalsValueValidationIssues(rawInput, cache);
  const input = sanitizeVitalsAgentInput(rawInput, validationIssues);
  const trendLog = loadVitalsTrendLog();

  applyVitalsValidationState(validationIssues, cache);

  const renderSignature = stringifyVitalsState({
    patient: getVitalsPatientKey(),
    profile: rawInput.profile,
    vitals: rawInput.vitals,
    context: rawInput.context,
    measurement: rawInput.measurement,
    qualityChecks: rawInput.qualityChecks,
    baseline: rawInput.baseline,
    validationIssues,
    trend: trendLog.map((entry) => ({
      id: entry.id,
      createdAt: entry.createdAt,
      updatedAt: entry.updatedAt,
      qualityScore: entry.qualityScore,
      priority: entry.priority,
      vitals: entry.vitals
    }))
  });

  if (vitalsRuntimeState.renderSignature === renderSignature && cache?.lists?.summary?.childElementCount) {
    refreshVitalsActionAvailability(rawInput);
    return;
  }

  const assessments = [
    ...buildVitalsValidationItems(validationIssues),
    ...buildVitalsAssessments(input)
  ];
  const bmi = calculateVitalsBmi(input.weight, input.height);
  const quality = buildVitalsQuality(input);
  const trend = buildVitalsTrendSummary(trendLog, input);
  const readiness = scoreVitalsReadiness(input, assessments, bmi, quality, trend);
  const enteredCount = countEnteredVitals(input);
  const alertCount = assessments.filter((item) => ["medium", "high", "critical"].includes(item.level)).length;

  saveVitalsDraftIfChanged(input);
  saveVitalsBaseline(input.baseline);
  updateVitalsScore(readiness, enteredCount, alertCount, bmi, assessments);
  renderVitalsSummary(input, assessments, bmi, quality, trend);
  renderVitalsDashboardList(cache?.lists?.quality, quality.items);
  renderVitalsDashboardList(cache?.lists?.protocol, buildVitalsMonitoringProtocol(input, assessments, quality, trend));
  renderVitalsDashboardList(cache?.lists?.review, assessments.length ? assessments : [{
    title: "Awaiting specialist readings",
    detail: "Add BP, glucose, pulse, oxygen, temperature, weight, height, sleep, steps, or hydration to start.",
    level: "none"
  }]);
  renderVitalsDashboardList(cache?.lists?.maintain, buildVitalsMaintenance(input, assessments, bmi, quality));
  renderVitalsDashboardList(cache?.lists?.bmi, buildBmiGuidance(input, bmi));
  renderVitalsDashboardList(cache?.lists?.trend, buildVitalsTrendPlan(input, trend));
  renderVitalsTrendLog(trendLog);
  renderVitalsDashboardList(cache?.lists?.actions, buildVitalsActions(input, assessments, bmi, quality, trend));
  setVitalsRecordStatus(trendLog.length ? `${trendLog.length} saved reading${trendLog.length === 1 ? "" : "s"} on this device and Records-ready.` : "Vitals stay local until saved to Records.");
  refreshVitalsActionAvailability(rawInput, enteredCount);
  vitalsRuntimeState.renderSignature = renderSignature;
}

function countEnteredVitals(input) {
  return [
    input.vitals.systolic,
    input.vitals.diastolic,
    input.vitals.bloodSugar,
    input.vitals.heartRate,
    input.vitals.temperatureC,
    input.vitals.oxygenSaturation,
    input.vitals.weightKg,
    input.vitals.heightCm,
    input.vitals.waistCm,
    input.vitals.sleepHours,
    input.vitals.stepsCount,
    input.vitals.waterCups
  ].filter(Boolean).length;
}

function scoreVitalsReadiness(input, assessments, bmi, quality = buildVitalsQuality(input), trend = { count: 0 }) {
  const enteredCount = countEnteredVitals(input);
  const redFlags = input.context.redFlags.length;
  const alertCount = assessments.filter((item) => ["medium", "high", "critical"].includes(item.level)).length;
  const hasCritical = assessments.some((item) => item.level === "critical");
  const hasHigh = assessments.some((item) => item.level === "high");
  let score = 18 + Math.min(enteredCount * 7, 52);

  if (input.profile.baselineBp || input.baseline.bp) score += 7;
  if (input.baseline.sugar || input.baseline.pulse || input.baseline.target) score += 6;
  if (input.measurement.bpTiming !== "not-sure" || input.measurement.glucoseTiming !== "not-sure") score += 5;
  if (input.measurement.readingStatus !== "single") score += 5;
  if (input.measurement.deviceNote) score += 4;
  if (input.context.duration && input.context.duration !== "not-sure") score += 6;
  if (input.context.lastMedicationTime) score += 5;
  if (bmi) score += 8;
  if (input.sleep !== null || input.steps !== null || input.water !== null) score += 8;
  score += Math.min(quality.score / 8, 10);
  if (trend.count >= 3) score += 5;
  if (trend.count >= 7) score += 5;
  if (redFlags) score -= 10;
  if (alertCount >= 3) score -= 6;
  if (hasCritical) score = Math.min(score, 46);
  if (hasHigh) score = Math.min(score, 68);

  return Math.max(0, Math.min(96, score));
}

function updateVitalsScore(score, enteredCount, alertCount, bmi, assessments = []) {
  const displayScore = Math.round(score);
  const cache = getVitalsDomCache();
  const scoreValue = cache?.scoreValue;
  const scoreLabel = cache?.scoreLabel;
  const scoreRing = cache?.scoreRing;
  const scoreCaption = cache?.scoreCaption;
  const enteredNode = cache?.enteredNode;
  const alertNode = cache?.alertNode;
  const bmiNode = cache?.bmiNode;
  const hasCritical = assessments.some((item) => item.level === "critical");
  const hasHigh = assessments.some((item) => item.level === "high");
  const level = hasCritical ? "critical" : hasHigh ? "high" : displayScore >= 78 ? "low" : displayScore >= 58 ? "medium" : "none";

  setVitalsText(scoreValue, hasCritical ? "Urgent" : `${displayScore}%`);
  if (scoreRing) {
    scoreRing.dataset.level = level;
    scoreRing.style.setProperty("--vitals-score", `${displayScore}%`);
  }
  setVitalsText(scoreCaption, hasCritical ? "review" : hasHigh ? "watch" : "ready");
  if (scoreLabel) {
    setVitalsText(scoreLabel, hasCritical
      ? "Urgent warning pattern. Focus on safety first, then save context for clinical review."
      : hasHigh
        ? "High-priority signal. Recheck correctly if safe and record symptoms, timing, and baseline."
        : displayScore >= 78
      ? "Good specialist snapshot. Use the trend plan and review any marked readings."
      : displayScore >= 58
        ? "Useful signal. Add timing, repeat status, symptoms, and daily context for a stronger review."
        : "Add core readings to build a reliable vital-specialist snapshot.");
  }
  setVitalsText(enteredNode, enteredCount);
  setVitalsText(alertNode, alertCount);
  setVitalsText(bmiNode, bmi ? bmi.value.toFixed(1) : "--");
}

function buildVitalsQuality(input) {
  const checks = new Set(input.qualityChecks || []);
  const items = [];
  const bpEntered = input.vitals.systolic || input.vitals.diastolic;
  const oxygenEntered = input.vitals.oxygenSaturation;
  const glucoseEntered = input.vitals.bloodSugar;
  let score = 12 + checks.size * 12;

  if (input.measurement.deviceNote) score += 8;
  if (input.measurement.readingStatus === "repeated" || input.measurement.readingStatus === "trend") score += 10;
  if (bpEntered && input.measurement.bpTiming !== "not-sure") score += 7;
  if (glucoseEntered && input.measurement.glucoseTiming !== "not-sure") score += 7;
  if (bpEntered && (!checks.has("rested") || !checks.has("heart-level"))) score -= 12;
  if (oxygenEntered && !checks.has("heart-level")) score -= 6;

  items.push({
    title: "Quality score",
    detail: `${Math.max(0, Math.min(100, Math.round(score)))}% reliable context. ${checks.size} of 6 measurement checks confirmed.`,
    level: score >= 76 ? "low" : score >= 48 ? "medium" : "none"
  });

  if (bpEntered) {
    const missing = [
      !checks.has("rested") ? "rest 5 minutes" : "",
      !checks.has("no-caffeine") ? "avoid caffeine/exercise before reading" : "",
      !checks.has("bare-arm") ? "use cuff on bare arm" : "",
      !checks.has("heart-level") ? "keep arm at heart level" : "",
      !checks.has("repeated") ? "take two readings" : "",
      !checks.has("validated-device") ? "use a clinically validated cuff" : ""
    ].filter(Boolean);

    items.push({
      title: "BP measurement coach",
      detail: missing.length ? `Improve accuracy: ${missing.slice(0, 4).join(", ")}.` : "BP measurement setup is well documented.",
      level: missing.length ? "medium" : "low"
    });
  }

  if (glucoseEntered) {
    items.push({
      title: "Glucose meaning",
      detail: input.measurement.glucoseTiming === "not-sure"
        ? "Choose fasting, before meal, after meal, random, or bedtime so the glucose number can be interpreted safely."
        : `Glucose timing captured: ${formatVitalsContext(input.measurement.glucoseTiming)}.`,
      level: input.measurement.glucoseTiming === "not-sure" ? "medium" : "low"
    });
  }

  if (oxygenEntered) {
    items.push({
      title: "Oxygen reading quality",
      detail: "Warm the hand, remove nail polish if possible, keep the finger still, and compare with symptoms instead of one number alone.",
      level: "low"
    });
  }

  items.push({
    title: "Personal baseline",
    detail: [input.baseline.bp ? `usual BP ${input.baseline.bp}` : "", input.baseline.sugar ? `usual glucose ${input.baseline.sugar}` : "", input.baseline.pulse ? `usual pulse ${input.baseline.pulse}` : "", input.baseline.target ? `target: ${input.baseline.target}` : ""].filter(Boolean).join("; ") || "Add usual BP, glucose, pulse, or clinician target to personalize the review.",
    level: input.baseline.bp || input.baseline.sugar || input.baseline.pulse || input.baseline.target ? "low" : "none"
  });

  return {
    score: Math.max(0, Math.min(100, Math.round(score))),
    items
  };
}

function getVitalsTrendLogStorageKey(targetPatientId = patientId) {
  return `${storageKeys.vitalsTrendLog}.${normalizePatientStorageId(targetPatientId)}`;
}

function loadVitalsTrendLog(targetPatientId = patientId) {
  const patientKey = getVitalsPatientKey(targetPatientId);

  if (vitalsRuntimeState.trendPatientKey === patientKey && Array.isArray(vitalsRuntimeState.trendLog)) {
    return vitalsRuntimeState.trendLog;
  }

  const entries = loadJson(getVitalsTrendLogStorageKey(targetPatientId), [])
    .map(normalizeVitalsTrendEntry)
    .filter(Boolean)
    .sort((left, right) => new Date(right.createdAt).getTime() - new Date(left.createdAt).getTime());

  vitalsRuntimeState.trendPatientKey = patientKey;
  vitalsRuntimeState.trendLog = entries;
  return entries;
}

function saveVitalsTrendLog(entries = [], targetPatientId = patientId, options = {}) {
  const normalized = entries
    .map(normalizeVitalsTrendEntry)
    .filter(Boolean)
    .sort((left, right) => new Date(right.createdAt).getTime() - new Date(left.createdAt).getTime())
    .slice(0, 180);

  saveJson(getVitalsTrendLogStorageKey(targetPatientId), normalized, {
    targetPatientId,
    reason: "vitals-update",
    ...options
  });
  vitalsRuntimeState.trendPatientKey = getVitalsPatientKey(targetPatientId);
  vitalsRuntimeState.trendLog = normalized;
  vitalsRuntimeState.renderSignature = "";
}

function normalizeVitalsTrendEntry(entry = {}) {
  const vitals = entry.vitals || {};

  if (!Object.values(vitals).some((value) => String(value || "").trim())) {
    return null;
  }

  return {
    id: entry.id || `vitals-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    patientId: entry.patientId || patientId || defaultProfile.id,
    createdAt: entry.createdAt || new Date().toISOString(),
    updatedAt: entry.updatedAt || new Date().toISOString(),
    vitals: {
      systolic: String(vitals.systolic || "").trim(),
      diastolic: String(vitals.diastolic || "").trim(),
      bloodSugar: String(vitals.bloodSugar || "").trim(),
      heartRate: String(vitals.heartRate || "").trim(),
      temperatureC: String(vitals.temperatureC || "").trim(),
      oxygenSaturation: String(vitals.oxygenSaturation || "").trim(),
      weightKg: String(vitals.weightKg || "").trim(),
      heightCm: String(vitals.heightCm || "").trim(),
      waistCm: String(vitals.waistCm || "").trim(),
      sleepHours: String(vitals.sleepHours || "").trim(),
      stepsCount: String(vitals.stepsCount || "").trim(),
      waterCups: String(vitals.waterCups || "").trim()
    },
    context: entry.context || {},
    measurement: entry.measurement || {},
    qualityChecks: Array.isArray(entry.qualityChecks)
      ? [...new Set(entry.qualityChecks.map((value) => String(value || "").trim()).filter(Boolean))]
      : [],
    baseline: {
      bp: String(entry.baseline?.bp || "").trim(),
      sugar: String(entry.baseline?.sugar || "").trim(),
      pulse: String(entry.baseline?.pulse || "").trim(),
      target: String(entry.baseline?.target || "").trim()
    },
    qualityScore: Number.isFinite(Number(entry.qualityScore)) ? Number(entry.qualityScore) : 0,
    priority: entry.priority || "routine",
    note: String(entry.note || "").trim()
  };
}

function saveCurrentVitalsReading() {
  const input = getValidatedVitalsActionInput();

  if (!input) {
    return;
  }

  if (!countEnteredVitals(input)) {
    setVitalsRecordStatus("Add at least one reading before saving.", "medium");
    return;
  }

  const assessments = buildVitalsAssessments(input);
  const quality = buildVitalsQuality(input);
  const priority = assessments.some((item) => item.level === "critical")
    ? "urgent"
    : assessments.some((item) => item.level === "high" || item.level === "medium")
      ? "watch"
      : "routine";
  const entry = normalizeVitalsTrendEntry({
    patientId,
    vitals: input.vitals,
    context: input.context,
    measurement: input.measurement,
    qualityChecks: input.qualityChecks,
    baseline: input.baseline,
    qualityScore: quality.score,
    priority,
    note: assessments[0]?.detail || ""
  });
  const next = [entry, ...loadVitalsTrendLog()].slice(0, 180);

  saveVitalsTrendLog(next);
  appendVitalsReportToPatientRecords(entry, buildVitalsReportText(input, assessments, calculateVitalsBmi(input.weight, input.height), quality, buildVitalsTrendSummary(next, input), next), "Vitals reading");
  setVitalsRecordStatus("Vitals saved locally and mirrored through Records.", "low");
  renderVitalsReview();
}

function deleteSavedVitalsReading(id) {
  saveVitalsTrendLog(loadVitalsTrendLog().filter((entry) => entry.id !== id));
  setVitalsRecordStatus("Saved vitals reading removed.", "low");
  renderVitalsReview();
}

function renderVitalsTrendLog(entries = loadVitalsTrendLog()) {
  const list = getVitalsDomCache()?.trendLogList;

  if (!list) {
    return;
  }

  if (!entries.length) {
    renderVitalsDashboardList(list, [{
      title: "No saved trend yet",
      detail: "Save readings for a 7-day BP, glucose, pulse, oxygen, sleep, and body-metric trend.",
      level: "none"
    }]);
    return;
  }

  const signature = stringifyVitalsState(entries.slice(0, 8).map((entry) => ({
    id: entry.id,
    createdAt: entry.createdAt,
    updatedAt: entry.updatedAt,
    priority: entry.priority,
    qualityScore: entry.qualityScore,
    vitals: entry.vitals
  })));

  if (list.dataset.renderSignature === signature && list.childElementCount) {
    return;
  }

  clearNode(list);

  for (const entry of entries.slice(0, 8)) {
    const item = document.createElement("li");
    const title = document.createElement("strong");
    const detail = document.createElement("span");
    const remove = document.createElement("button");

    item.dataset.level = entry.priority === "urgent" ? "critical" : entry.priority === "watch" ? "medium" : "low";
    item.className = "vitals-log-item";
    title.textContent = `${entry.priority === "urgent" ? "Urgent watch" : entry.priority === "watch" ? "Watch trend" : "Routine"} - ${formatRecordUpdatedAt(entry.createdAt)}`;
    detail.textContent = `${buildVitalsLabel(entry.vitals)}; quality ${entry.qualityScore || 0}%`;
    remove.type = "button";
    remove.dataset.deleteVitalReading = entry.id;
    remove.textContent = "Delete";
    item.append(createIcon("icon-activity", "chip-icon"), title, detail, remove);
    list.append(item);
  }

  list.dataset.renderSignature = signature;
}

function buildVitalsTrendSummary(entries = loadVitalsTrendLog(), input = collectVitalsAgentInputs()) {
  const cutoff = Date.now() - 7 * 24 * 60 * 60 * 1000;
  const recent = entries.filter((entry) => new Date(entry.createdAt).getTime() >= cutoff);
  const averages = {
    systolic: averageVitalsValue(recent, "systolic"),
    diastolic: averageVitalsValue(recent, "diastolic"),
    bloodSugar: averageVitalsValue(recent, "bloodSugar"),
    heartRate: averageVitalsValue(recent, "heartRate"),
    oxygenSaturation: averageVitalsValue(recent, "oxygenSaturation"),
    sleepHours: averageVitalsValue(recent, "sleepHours"),
    stepsCount: averageVitalsValue(recent, "stepsCount"),
    waterCups: averageVitalsValue(recent, "waterCups")
  };
  const labels = [];

  if (averages.systolic !== null || averages.diastolic !== null) {
    labels.push(`avg BP ${formatAverageNumber(averages.systolic)}/${formatAverageNumber(averages.diastolic)}`);
  }
  if (averages.bloodSugar !== null) labels.push(`avg glucose ${formatAverageNumber(averages.bloodSugar)}`);
  if (averages.heartRate !== null) labels.push(`avg pulse ${formatAverageNumber(averages.heartRate)}`);
  if (averages.oxygenSaturation !== null) labels.push(`avg oxygen ${formatAverageNumber(averages.oxygenSaturation)}%`);
  if (averages.sleepHours !== null) labels.push(`avg sleep ${formatAverageNumber(averages.sleepHours, 1)}h`);

  return {
    count: recent.length,
    totalCount: entries.length,
    averages,
    label: labels.length ? labels.join("; ") : "No 7-day averages yet",
    newest: entries[0] || null,
    hasCurrentReading: countEnteredVitals(input) > 0
  };
}

function averageVitalsValue(entries, key) {
  const values = entries
    .map((entry) => toNumber(entry.vitals?.[key]))
    .filter((value) => value !== null);

  if (!values.length) {
    return null;
  }

  return values.reduce((sum, value) => sum + value, 0) / values.length;
}

function formatAverageNumber(value, digits = 0) {
  return value === null ? "?" : value.toFixed(digits);
}

function buildVitalsAssessments(input) {
  const items = [];
  const systolic = toNumber(input.vitals.systolic);
  const diastolic = toNumber(input.vitals.diastolic);
  const sugar = toNumber(input.vitals.bloodSugar);
  const heartRate = toNumber(input.vitals.heartRate);
  const temperature = toNumber(input.vitals.temperatureC);
  const oxygen = input.oxygen;
  const redFlags = new Set(input.context.redFlags || []);
  const redFlagText = input.context.redFlags.join(" ");
  const hasUrgentFlag = ["chest-pain", "breathing-trouble", "fainting", "one-sided-weakness", "severe-allergy"]
    .some((flag) => redFlags.has(flag));
  const symptomSeverity = toNumber(input.context.severity) || 0;
  const partialBp = (systolic !== null && diastolic === null) || (systolic === null && diastolic !== null);
  const baselineBp = parseVitalsBp(input.baseline.bp || input.profile.baselineBp || "");
  const baselinePulse = toNumber(input.baseline.pulse);

  if (partialBp) {
    items.push({
      title: "BP pair incomplete",
      detail: "A vital specialist needs both systolic and diastolic values, plus time taken and whether it was repeated after rest.",
      level: "medium"
    });
  }

  if (systolic !== null || diastolic !== null) {
    const sys = systolic ?? 0;
    const dia = diastolic ?? 0;
    const severe = sys >= 180 || dia >= 120;
    const highStage2 = sys >= 160 || dia >= 100;
    const stage2 = sys >= 140 || dia >= 90;
    const stage1 = sys >= 130 || dia >= 80;
    const elevated = sys >= 120 && sys <= 129 && dia < 80;
    const low = (systolic !== null && systolic < 90) || (diastolic !== null && diastolic < 60);
    const baselineText = baselineBp
      ? ` Baseline difference: ${formatBpDifference(sys, dia, baselineBp)}.`
      : "";
    const timingText = input.measurement.bpTiming !== "not-sure" ? ` Timing: ${formatVitalsContext(input.measurement.bpTiming)}.` : "";
    const bpLevel = severe && hasUrgentFlag ? "critical" : severe || highStage2 ? "high" : stage2 || stage1 || elevated || low ? "medium" : "low";

    items.push({
      title: "Blood pressure",
      detail: severe
        ? hasUrgentFlag
          ? `BP ${input.vitals.systolic || "?"}/${input.vitals.diastolic || "?"} plus warning symptoms is an emergency warning pattern.${baselineText}${timingText}`
          : `BP ${input.vitals.systolic || "?"}/${input.vitals.diastolic || "?"} is in a very high range. Rest quietly if safe, repeat correctly, and seek prompt clinical guidance if it remains high.${baselineText}${timingText}`
        : highStage2
          ? `BP ${input.vitals.systolic || "?"}/${input.vitals.diastolic || "?"} is a high pattern. Recheck after rest if safe, compare with baseline, and record symptoms, medicines, salt-heavy meals, sleep, and stress.${baselineText}${timingText}`
          : stage2
            ? `BP ${input.vitals.systolic || "?"}/${input.vitals.diastolic || "?"} fits a stage-2 range by common adult categories and deserves trend review.${baselineText}${timingText}`
            : stage1
              ? `BP ${input.vitals.systolic || "?"}/${input.vitals.diastolic || "?"} fits a stage-1 range by common adult categories. Track a 7-day average and context.${baselineText}${timingText}`
              : elevated
                ? `BP ${input.vitals.systolic || "?"}/${input.vitals.diastolic || "?"} is elevated systolic with lower diastolic. Repeat trends matter more than one value.${baselineText}${timingText}`
            : low
              ? `BP ${input.vitals.systolic || "?"}/${input.vitals.diastolic || "?"} is low for many adults. Dizziness, faintness, dehydration, or medicine timing matters.${baselineText}${timingText}`
              : `BP ${input.vitals.systolic || "?"}/${input.vitals.diastolic || "?"} is captured for baseline and trend comparison.${baselineText}${timingText}`,
      level: bpLevel
    });
  }

  if (sugar !== null) {
    const glucoseTiming = formatVitalsContext(input.measurement.glucoseTiming);
    const glucoseTargetText = input.baseline.sugar ? ` Usual/target context: ${input.baseline.sugar}.` : "";
    const veryHighSugar = sugar >= 300;
    const lowSugar = sugar <= 70;
    const severeLowSugar = sugar <= 55;
    const sugarLevel = severeLowSugar || (veryHighSugar && (hasUrgentFlag || symptomSeverity >= 7))
      ? "critical"
      : veryHighSugar || lowSugar || sugar >= 240
        ? "high"
        : "low";

    items.push({
      title: "Blood sugar",
      detail: veryHighSugar
        ? `Glucose ${sugar} is very high. Timing: ${glucoseTiming}. Add medicines, hydration, illness, ketones if your care plan uses them, and symptoms.${glucoseTargetText}`
        : severeLowSugar
          ? `Glucose ${sugar} is very low. Shaking, sweating, confusion, fainting, or inability to eat is urgent.${glucoseTargetText}`
        : sugar >= 240
            ? `Glucose ${sugar} is elevated. Timing: ${glucoseTiming}. Record medicine timing, illness, hydration, meal, and activity.${glucoseTargetText}`
            : lowSugar
              ? `Glucose ${sugar} is low for many people. Note symptoms and follow your written diabetes plan if you have one.${glucoseTargetText}`
              : `Glucose ${sugar} is captured. Timing: ${glucoseTiming}; interpretation depends on personal targets.${glucoseTargetText}`,
      level: sugarLevel
    });
  }

  if (heartRate !== null) {
    const pulseDifference = baselinePulse !== null ? ` Baseline difference: ${heartRate - baselinePulse > 0 ? "+" : ""}${heartRate - baselinePulse} bpm.` : "";
    const pulseLevel = heartRate >= 140 && hasUrgentFlag
      ? "critical"
      : heartRate >= 130
        ? "high"
        : heartRate >= 115 || heartRate < 45
          ? "medium"
          : "low";

    items.push({
      title: "Heart rate",
      detail: heartRate >= 130
        ? `Pulse ${heartRate} is high. Fever, dehydration, pain, anxiety, medicines, caffeine, and rhythm issues can contribute.${pulseDifference}`
        : heartRate >= 115
          ? `Pulse ${heartRate} is elevated. Recheck after rest and connect it with fever, oxygen, hydration, and symptoms.${pulseDifference}`
          : heartRate < 45
            ? `Pulse ${heartRate} is low for many adults. Dizziness, fainting, chest symptoms, or weakness matters.${pulseDifference}`
            : `Pulse ${heartRate} bpm has been captured for today's trend.${pulseDifference}`,
      level: pulseLevel
    });
  }

  if (temperature !== null) {
    const feverLevel = temperature >= 40.6
      ? "critical"
      : temperature >= 39.4
        ? "high"
        : temperature >= 38 || temperature <= 35
          ? "medium"
          : "low";

    items.push({
      title: "Temperature",
      detail: temperature >= 40.6
        ? `Temperature ${temperature}C is very high. Pair it with confusion, breathing trouble, dehydration, stiff neck, rash, severe headache, or persistent vomiting.`
        : temperature >= 39.4
          ? `Temperature ${temperature}C is high. Pair it with oxygen, breathing, confusion, dehydration, rash, severe headache, or persistent vomiting.`
        : temperature >= 38
          ? `Temperature ${temperature}C suggests fever range for many adults. Hydration, duration, pulse, oxygen, and symptoms matter.`
          : temperature <= 35
            ? `Temperature ${temperature}C is low and should be interpreted carefully with symptoms and measurement quality.`
            : `Temperature ${temperature}C is captured.`,
      level: feverLevel
    });
  }

  if (oxygen !== null) {
    const oxygenLevel = oxygen <= 90 || (oxygen <= 92 && redFlags.has("breathing-trouble"))
      ? "critical"
      : oxygen <= 92
        ? "high"
        : oxygen < 95 || oxygen > 100
          ? "medium"
          : "low";

    items.push({
      title: "Oxygen saturation",
      detail: oxygen <= 90
        ? `Oxygen ${oxygen}% is low and should be treated seriously, especially with breathing trouble, chest pain, confusion, or blue lips.`
        : oxygen <= 92
          ? `Oxygen ${oxygen}% is below the expected range for many adults. Recheck finger fit and compare with breathing effort, chest symptoms, and confusion.`
        : oxygen < 95
          ? `Oxygen ${oxygen}% is below the usual normal range for many adults. Recheck finger fit, warm hands, and breathing symptoms.`
          : oxygen <= 100
            ? `Oxygen ${oxygen}% is captured. Compare with your normal baseline if you have lung or heart conditions.`
            : `Oxygen ${oxygen}% looks like an invalid entry; pulse oximeters usually report up to 100%.`,
      level: oxygenLevel
    });
  }

  if (oxygen !== null && heartRate !== null && temperature !== null && oxygen < 95 && heartRate >= 110 && temperature >= 38) {
    items.unshift({
      title: "Breathing-fever pattern",
      detail: `Oxygen ${oxygen}%, pulse ${heartRate}, and temperature ${temperature}C together need careful real-world context, especially with breathlessness, chest symptoms, confusion, or worsening weakness.`,
      level: oxygen <= 92 || heartRate >= 130 || temperature >= 39 ? "critical" : "high"
    });
  }

  if (systolic !== null && diastolic !== null && sugar !== null && heartRate !== null && (systolic >= 160 || diastolic >= 100) && sugar >= 240 && heartRate >= 100) {
    items.unshift({
      title: "Cardio-metabolic cluster",
      detail: "High BP, elevated glucose, and faster pulse together deserve a focused same-day context review, especially with illness, dehydration, missed medicine, chest symptoms, or weakness.",
      level: hasUrgentFlag ? "critical" : "high"
    });
  }

  if (input.context.redFlags.length) {
    items.unshift({
      title: "Urgent warning combination",
      detail: `Selected: ${redFlagText.replace(/-/g, " ")}. Vital specialist review prioritizes safety before routine trend tracking.`,
      level: "critical"
    });
  }

  if (input.sleep !== null && input.sleep < 6) {
    items.push({
      title: "Sleep signal",
      detail: `Sleep ${input.sleep}h can raise BP, pulse, glucose variability, fatigue, and symptom sensitivity for many people.`,
      level: "medium"
    });
  }

  if (input.steps !== null && input.steps < 3000) {
    items.push({
      title: "Activity signal",
      detail: `Steps ${input.steps} suggests a low-activity day. Compare readings with illness, pain, sleep, and usual activity.`,
      level: "medium"
    });
  }

  if (input.water !== null && input.water < 4) {
    items.push({
      title: "Hydration signal",
      detail: `Water ${input.water} cup(s) may affect pulse, dizziness, blood pressure, and glucose readings.`,
      level: "medium"
    });
  }

  return items;
}

function parseVitalsBp(value = "") {
  const match = String(value).match(/(\d{2,3})\s*\/\s*(\d{2,3})/);
  return match ? { systolic: Number(match[1]), diastolic: Number(match[2]) } : null;
}

function formatBpDifference(systolic, diastolic, baseline) {
  const sysDiff = systolic - baseline.systolic;
  const diaDiff = diastolic - baseline.diastolic;
  return `${sysDiff >= 0 ? "+" : ""}${sysDiff}/${diaDiff >= 0 ? "+" : ""}${diaDiff} from ${baseline.systolic}/${baseline.diastolic}`;
}

function formatVitalsContext(value) {
  const labels = {
    "not-sure": "not sure",
    morning: "morning",
    evening: "evening",
    "after-medicine": "after medicine",
    "before-medicine": "before medicine",
    "after-activity": "after activity",
    fasting: "fasting",
    "before-meal": "before meal",
    "after-meal": "1-2h after meal",
    random: "random",
    bedtime: "bedtime",
    single: "single reading",
    repeated: "repeated after rest",
    trend: "part of trend",
    unwell: "taken while unwell"
  };

  return labels[value] || formatContextValue(value);
}

function calculateVitalsBmi(weightKg, heightCm) {
  if (weightKg === null || heightCm === null || weightKg <= 0 || heightCm <= 0) {
    return null;
  }

  const heightM = heightCm / 100;
  const value = weightKg / (heightM * heightM);
  const category = value < 18.5
    ? "Below common adult range"
    : value < 25
      ? "Common target range"
      : value < 30
        ? "Above common target range"
        : "Higher-risk range";
  const level = value < 18.5 ? "medium" : value < 25 ? "low" : value < 30 ? "medium" : "high";

  return { value, category, level };
}

function renderVitalsSummary(input, assessments, bmi, quality = buildVitalsQuality(input), trend = buildVitalsTrendSummary()) {
  const priority = buildVitalsPriorityProfile(input, assessments, bmi, quality, trend);
  const items = [
    {
      title: priority.title,
      detail: priority.detail,
      level: priority.level
    },
    {
      title: "Recheck rule",
      detail: priority.recheck,
      level: priority.level === "critical" ? "critical" : priority.level === "high" ? "high" : "low"
    },
    {
      title: "Decision confidence",
      detail: priority.confidence,
      level: quality.score >= 76 && trend.count >= 3 ? "low" : quality.score >= 48 ? "medium" : "none"
    },
    {
      title: "Body metric view",
      detail: bmi ? `BMI ${bmi.value.toFixed(1)} - ${bmi.category}.` : "Enter weight and height to calculate BMI.",
      level: bmi?.level || "none"
    },
    {
      title: "Daily context",
      detail: buildVitalsDailyContext(input),
      level: input.sleep !== null || input.steps !== null || input.water !== null ? "low" : "none"
    }
  ];

  renderVitalsDashboardList(getVitalsDomCache()?.lists?.summary, items);
}

function buildVitalsPriorityProfile(input, assessments, bmi, quality, trend) {
  const critical = assessments.find((item) => item.level === "critical");
  const high = assessments.find((item) => item.level === "high");
  const medium = assessments.find((item) => item.level === "medium");
  const first = critical || high || medium || assessments[0];
  const hasReadings = countEnteredVitals(input) > 0;
  const repeated = input.measurement.readingStatus === "repeated" || input.measurement.readingStatus === "trend";
  const baseline = input.profile.baselineBp || input.baseline.bp || input.baseline.sugar || input.baseline.pulse;
  const timingKnown = input.measurement.bpTiming !== "not-sure" || input.measurement.glucoseTiming !== "not-sure" || Boolean(input.context.lastMedicationTime);

  if (critical) {
    return {
      title: "Urgent vital signal",
      detail: critical.detail,
      level: "critical",
      recheck: "If severe symptoms are present, do not wait for another reading. Use real-world urgent care support.",
      confidence: `Quality ${quality.score}%. ${repeated ? "Repeated reading captured." : "If safe, repeat the reading correctly and note the time."}`
    };
  }

  if (high) {
    return {
      title: "High-priority review",
      detail: high.detail,
      level: "high",
      recheck: "Rest quietly if safe, repeat unusual readings correctly, and save symptom, medicine, meal, activity, and device context.",
      confidence: `Quality ${quality.score}%. ${baseline ? "Baseline context available." : "Add usual BP/glucose/pulse targets for stronger comparison."}`
    };
  }

  if (medium) {
    return {
      title: "Focused trend review",
      detail: medium.detail,
      level: "medium",
      recheck: "Use the same device and timing, then compare 3 to 7 saved readings instead of judging one number.",
      confidence: `Quality ${quality.score}%. ${timingKnown ? "Timing context captured." : "Add reading timing to improve accuracy."}`
    };
  }

  return {
    title: hasReadings ? "Routine vital snapshot" : "Ready for specialist readings",
    detail: first ? first.detail : "Add BP, pulse, oxygen, temperature, glucose if relevant, and body metrics to start.",
    level: first?.level || "none",
    recheck: hasReadings ? "Save this reading if it represents today, then build a trend." : "Start with BP pair, pulse, temperature, oxygen, and glucose if relevant.",
    confidence: trend.count >= 3
      ? `${trend.count} recent saved readings available: ${trend.label}.`
      : `Quality ${quality.score}%. Save at least 3 readings for a stronger trend.`
  };
}

function buildVitalsDailyContext(input) {
  const details = [
    input.sleep !== null ? `sleep ${input.sleep}h` : "",
    input.steps !== null ? `steps ${input.steps}` : "",
    input.water !== null ? `water ${input.water} cup(s)` : "",
    input.context.lastMedicationTime ? `timing: ${input.context.lastMedicationTime}` : ""
  ].filter(Boolean);

  return details.length
    ? details.join(", ")
    : "Add sleep, steps, hydration, and medicine or meal timing for better specialist context.";
}

function buildVitalsMaintenance(input, assessments, bmi, quality = buildVitalsQuality(input)) {
  const bpAlert = assessments.find((item) => item.title === "Blood pressure" && ["medium", "high", "critical"].includes(item.level));
  const sugarAlert = assessments.find((item) => item.title === "Blood sugar" && ["medium", "high", "critical"].includes(item.level));
  const pulseAlert = assessments.find((item) => item.title === "Heart rate" && ["medium", "high"].includes(item.level));
  const oxygenAlert = assessments.find((item) => item.title === "Oxygen saturation" && ["medium", "high", "critical"].includes(item.level));
  const feverAlert = assessments.find((item) => item.title === "Temperature" && ["medium", "high", "critical"].includes(item.level));
  const items = [
    {
      title: "Reading quality",
      detail: `Quality ${quality.score}%. Use the same device, sit quietly, keep the BP cuff at heart level, warm fingers for oxygen, and record time, food, medicine, activity, stress, and symptoms.`,
      level: quality.score >= 76 ? "low" : quality.score >= 48 ? "medium" : "none"
    },
    {
      title: bpAlert ? "BP maintenance focus" : "BP routine",
      detail: bpAlert ? "Repeat after resting if safe, reduce salt-heavy meals, track sleep/stress, and compare a 7-day average." : "Track BP at consistent times and compare with baseline instead of judging one reading alone.",
      level: bpAlert ? bpAlert.level : "low"
    },
    {
      title: sugarAlert ? "Sugar maintenance focus" : "Sugar routine",
      detail: sugarAlert ? "Note meal timing, hydration, medicine timing, illness, and activity. Short walks after meals can help many routines." : "If tracking sugar, label fasting/random/post-meal timing so the number has meaning.",
      level: sugarAlert ? sugarAlert.level : "low"
    },
    {
      title: pulseAlert ? "Pulse and oxygen focus" : "Pulse and oxygen routine",
      detail: pulseAlert || oxygenAlert ? "Rest, check finger fit for oxygen, note fever/pain/caffeine/hydration, and pair pulse with breathing symptoms." : "Pulse and oxygen are more useful when recorded with activity level and breathing symptoms.",
      level: pulseAlert?.level || oxygenAlert?.level || "low"
    },
    {
      title: feverAlert ? "Fever context" : "Temperature routine",
      detail: feverAlert ? "Track temperature with hydration, pulse, oxygen, rash, breathing, severe headache, confusion, vomiting, and duration." : "Temperature is easier to interpret when paired with symptoms, duration, pulse, and oxygen.",
      level: feverAlert ? feverAlert.level : "low"
    },
    {
      title: "Specialist pattern check",
      detail: "One reading is a signal; repeated readings plus baseline, symptoms, timing, and trend make the review more reliable.",
      level: "low"
    }
  ];

  if (bmi && bmi.level !== "low") {
    items.push({
      title: "Body metric focus",
      detail: "Use gradual changes: balanced meals, walking, resistance activity, sleep, waist tracking, and clinician targets if you have chronic conditions.",
      level: bmi.level
    });
  }

  return items;
}

function buildBmiGuidance(input, bmi) {
  return [
    {
      title: "BMI calculation",
      detail: bmi ? `${input.weight} kg and ${input.height} cm gives BMI ${bmi.value.toFixed(1)} (${bmi.category}).` : "Enter weight in kg and height in cm for BMI.",
      level: bmi?.level || "none"
    },
    {
      title: "Waist context",
      detail: input.waist !== null ? `${input.waist} cm waist added. Waist trend can help track abdominal risk alongside BMI.` : "Add waist measurement for a better lifestyle snapshot.",
      level: input.waist !== null && input.waist >= 102 ? "medium" : input.waist !== null ? "low" : "none"
    },
    {
      title: "Daily body metric habit",
      detail: "Use weekly averages, not daily emotion. Track weight, waist, steps, sleep, and energy at the same time of day.",
      level: "low"
    },
    {
      title: "Interpret carefully",
      detail: "BMI is a screening signal, not a diagnosis. Age, muscle, pregnancy, fluid retention, ethnicity, and clinician targets can change interpretation.",
      level: "low"
    }
  ];
}

function buildVitalsTrendPlan(input, trend = buildVitalsTrendSummary()) {
  const items = [
    {
      title: trend.count ? "7-day average" : "Start 7-day trend",
      detail: trend.count ? `${trend.count} recent reading${trend.count === 1 ? "" : "s"}: ${trend.label}.` : "Save repeat readings for BP, glucose, pulse, oxygen, sleep, steps, and hydration.",
      level: trend.count >= 3 ? "low" : "none"
    },
    {
      title: "Morning baseline",
      detail: "Before caffeine or heavy activity: BP, pulse, oxygen if needed, weight if tracking, and symptoms.",
      level: "low"
    },
    {
      title: "Evening comparison",
      detail: "Record BP/pulse plus steps, water, medicine timing, stress, and sleep plan.",
      level: "low"
    },
    {
      title: "7-day specialist view",
      detail: "Use 7-day averages for BP, sugar notes, weight, waist, steps, and sleep. Bring the trend to visits.",
      level: "low"
    },
    {
      title: "Pattern labels",
      detail: "Mark each reading as resting, after activity, after meal, before medicine, after medicine, illness day, or stress day.",
      level: "low"
    },
    {
      title: "Missing context",
      detail: input.context.duration === "not-sure" ? "Add when symptoms started so the reading has better meaning." : `Duration captured: ${formatContextValue(input.context.duration)}.`,
      level: input.context.duration === "not-sure" ? "none" : "low"
    }
  ];

  if (trend.newest) {
    items.push({
      title: "Last saved reading",
      detail: `${formatRecordUpdatedAt(trend.newest.createdAt)} - ${buildVitalsLabel(trend.newest.vitals)}.`,
      level: trend.newest.priority === "urgent" ? "critical" : trend.newest.priority === "watch" ? "medium" : "low"
    });
  }

  return items;
}

function buildVitalsMonitoringProtocol(input, assessments = [], quality = buildVitalsQuality(input), trend = buildVitalsTrendSummary()) {
  const hasBp = input.vitals.systolic || input.vitals.diastolic;
  const hasSugar = input.vitals.bloodSugar;
  const hasOxygen = input.vitals.oxygenSaturation;
  const hasFever = input.vitals.temperatureC;
  const hasBodyMetrics = input.vitals.weightKg || input.vitals.heightCm || input.vitals.waistCm;
  const highPriority = assessments.some((item) => ["critical", "high"].includes(item.level));
  const watchPriority = assessments.some((item) => item.level === "medium");
  const protocol = [];

  protocol.push({
    title: "Measure with context",
    detail: quality.score >= 76
      ? "Quality checks look strong. Keep using the same device, timing, body position, and notes."
      : "Improve the reading first: rest, correct cuff or sensor position, repeat unusual values, and record time, food, medicine, activity, stress, and symptoms.",
    level: quality.score >= 76 ? "low" : "medium"
  });

  if (hasBp) {
    protocol.push({
      title: "BP specialist protocol",
      detail: "For routine tracking, use morning/evening readings. For unusual values, rest quietly if safe, repeat correctly, and compare with usual BP or clinician target.",
      level: highPriority ? "high" : watchPriority ? "medium" : "low"
    });
  }

  if (hasSugar) {
    protocol.push({
      title: "Glucose specialist protocol",
      detail: "Label fasting, before meal, 1-2h after meal, bedtime, or random. Add meal, medicine, illness, hydration, symptoms, and personal target if known.",
      level: watchPriority || highPriority ? "medium" : "low"
    });
  }

  if (hasOxygen || hasFever) {
    protocol.push({
      title: "Breathing and fever protocol",
      detail: "Pair temperature, pulse, oxygen, breathing effort, fluids, urination, cough, chest symptoms, confusion, rash, and duration.",
      level: highPriority ? "high" : "low"
    });
  }

  if (hasBodyMetrics) {
    protocol.push({
      title: "Body metric protocol",
      detail: "Use weekly weight and waist trends with sleep, steps, hydration, and BP/glucose patterns. Avoid reacting to one day only.",
      level: "low"
    });
  }

  protocol.push({
    title: trend.count >= 3 ? "Trend confidence" : "Trend target",
    detail: trend.count >= 3
      ? `${trend.count} saved reading${trend.count === 1 ? "" : "s"} available. Use trend labels before changing routines.`
      : "Save at least 3 readings to detect a pattern; 7 days is stronger for routine BP or body-metric review.",
    level: trend.count >= 3 ? "low" : "none"
  });

  protocol.push({
    title: "Stop and escalate",
    detail: "Chest pain, breathing trouble, fainting, stroke-like signs, severe allergy, confusion, blue lips, or rapid worsening overrides routine tracking.",
    level: highPriority ? "critical" : "low"
  });

  return protocol.slice(0, 7);
}

function buildVitalsActions(input, assessments, bmi, quality = buildVitalsQuality(input), trend = buildVitalsTrendSummary()) {
  const critical = assessments.find((item) => item.level === "critical");
  const high = assessments.find((item) => item.level === "high");
  const medium = assessments.find((item) => item.level === "medium");
  const actions = [];

  if (critical) {
    actions.push({
      title: "Safety first",
      detail: "If severe symptoms are active, do not wait for another app result. Use local urgent care or emergency support.",
      level: "critical"
    });
  } else if (high) {
    actions.push({
      title: "Focused recheck",
      detail: "Rest if safe, repeat the measurement correctly, and record symptoms, timing, and medicines.",
      level: "high"
    });
  } else if (medium) {
    actions.push({
      title: "Build a clean trend",
      detail: "Repeat at a consistent time, label the context, and compare several readings with baseline before changing routines.",
      level: "medium"
    });
  } else {
    actions.push({
      title: "Build routine",
      detail: "Keep a simple daily vitals log and compare trends with your baseline.",
      level: "low"
    });
  }

  actions.push({
    title: "Specialist handoff",
    detail: `Share ${buildVitalsLabel(input.vitals)} plus duration, severity ${input.context.severity}/10, symptoms, meal or medicine timing, quality ${quality.score}%, and whether values were repeated.`,
    level: "low"
  });
  actions.push({
    title: trend.count >= 3 ? "Trend ready" : "Save trend",
    detail: trend.count >= 3 ? `Use the saved trend: ${trend.label}.` : "Save at least 3 readings before judging a pattern; 7 days is stronger.",
    level: trend.count >= 3 ? "low" : "none"
  });
  actions.push({
    title: "Daily maintenance",
    detail: "Prioritize sleep, hydration, walking, balanced meals, medicine consistency, and follow-up for repeated abnormal trends.",
    level: bmi?.level === "high" ? "medium" : "low"
  });

  return actions;
}

function buildVitalsReportText(
  input = collectVitalsAgentInputs(),
  assessments = buildVitalsAssessments(input),
  bmi = calculateVitalsBmi(input.weight, input.height),
  quality = buildVitalsQuality(input),
  trend = buildVitalsTrendSummary(loadVitalsTrendLog(), input),
  trendLog = loadVitalsTrendLog()
) {
  const profile = input.profile || collectProfile();
  const topAssessments = assessments.slice(0, 8);
  const baselineParts = [
    input.baseline?.bp ? `usual BP ${input.baseline.bp}` : "",
    input.baseline?.sugar ? `usual glucose ${input.baseline.sugar}` : "",
    input.baseline?.pulse ? `usual pulse ${input.baseline.pulse}` : "",
    input.baseline?.target ? `target ${input.baseline.target}` : ""
  ].filter(Boolean);
  const measurementParts = [
    `BP timing: ${formatVitalsContext(input.measurement?.bpTiming || "not-sure")}`,
    `Glucose timing: ${formatVitalsContext(input.measurement?.glucoseTiming || "not-sure")}`,
    `Status: ${formatVitalsContext(input.measurement?.readingStatus || "single")}`,
    input.measurement?.deviceNote ? `Device: ${input.measurement.deviceNote}` : ""
  ].filter(Boolean);
  const contextParts = [
    `Duration: ${formatContextValue(input.context?.duration || "not-sure")}`,
    `Goal: ${formatContextValue(input.context?.careGoal || "understand")}`,
    `Support: ${formatContextValue(input.context?.supportNow || "with-someone")}`,
    `Severity: ${input.context?.severity || "0"}/10`,
    input.context?.lastMedicationTime ? `Medicine/meal timing: ${input.context.lastMedicationTime}` : ""
  ].filter(Boolean);
  const recentLines = trendLog.slice(0, 6).map((entry) => `- ${formatRecordUpdatedAt(entry.createdAt)}: ${buildVitalsLabel(entry.vitals)}; quality ${entry.qualityScore || 0}%; ${entry.priority}.`);

  const lines = [
    "Care Nova AI - Vitals Specialist Report",
    `Generated: ${new Date().toLocaleString()}`,
    "",
    "Patient",
    `- ${buildPatientLabel(profile)}`,
    profile.medications ? `- Medicines: ${profile.medications}` : "- Medicines: not entered",
    profile.allergies ? `- Allergies: ${profile.allergies}` : "- Allergies: not entered",
    "",
    "Current Reading",
    `- ${buildVitalsLabel(input.vitals) || "No current vitals entered."}`,
    bmi ? `- BMI: ${bmi.value.toFixed(1)} (${bmi.category})` : "- BMI: not calculated",
    "",
    "Measurement Context",
    ...measurementParts.map((part) => `- ${part}`),
    "",
    "Personal Baseline",
    `- ${baselineParts.join("; ") || "No baseline added yet."}`,
    "",
    "Symptom Context",
    ...contextParts.map((part) => `- ${part}`),
    input.context?.redFlags?.length ? `- Warning signs: ${input.context.redFlags.map(formatContextValue).join(", ")}` : "- Warning signs: none selected",
    "",
    "Specialist Findings",
    ...(topAssessments.length ? topAssessments.map((item) => `- [${item.level}] ${item.title}: ${item.detail}`) : ["- No specialist findings yet."]),
    "",
    "Quality And Trend",
    `- Reading quality: ${quality.score}%.`,
    `- 7-day trend: ${trend.count ? trend.label : "not enough saved readings yet"}.`,
    ...(recentLines.length ? ["", "Recent Saved Readings", ...recentLines] : []),
    "",
    "Next Safe Moves",
    ...buildVitalsActions(input, assessments, bmi, quality, trend).slice(0, 5).map((item) => `- ${item.title}: ${item.detail}`),
    "",
    "Safety Boundary",
    "- This app organizes health information and flags safety patterns. It does not diagnose, prescribe, calculate dosage, or replace a qualified clinician."
  ];

  return lines.join("\n");
}

async function copyVitalsReport() {
  const input = getValidatedVitalsActionInput();

  if (!input) {
    return;
  }

  const assessments = buildVitalsAssessments(input);
  const bmi = calculateVitalsBmi(input.weight, input.height);
  const quality = buildVitalsQuality(input);
  const trendLog = loadVitalsTrendLog();
  const copied = await copyText(buildVitalsReportText(input, assessments, bmi, quality, buildVitalsTrendSummary(trendLog, input), trendLog));

  setVitalsRecordStatus(copied ? "Vitals doctor note copied." : "Copy failed. Use Download report instead.", copied ? "low" : "medium");
}

function downloadVitalsReport() {
  const input = getValidatedVitalsActionInput();

  if (!input) {
    return;
  }

  const assessments = buildVitalsAssessments(input);
  const bmi = calculateVitalsBmi(input.weight, input.height);
  const quality = buildVitalsQuality(input);
  const trendLog = loadVitalsTrendLog();
  const report = buildVitalsReportText(input, assessments, bmi, quality, buildVitalsTrendSummary(trendLog, input), trendLog);

  downloadLocalFile(report, getPatientReportFilename("vitals-specialist-report", "txt"), "text/plain;charset=utf-8");
  setVitalsRecordStatus("Vitals report downloaded from this device.", "low");
}

function saveVitalsReportToRecords() {
  const input = getValidatedVitalsActionInput();

  if (!input) {
    return;
  }

  const assessments = buildVitalsAssessments(input);
  const quality = buildVitalsQuality(input);
  const bmi = calculateVitalsBmi(input.weight, input.height);
  const trendLog = loadVitalsTrendLog();
  const entry = normalizeVitalsTrendEntry({
    patientId,
    vitals: input.vitals,
    context: input.context,
    measurement: input.measurement,
    qualityChecks: input.qualityChecks,
    baseline: input.baseline,
    qualityScore: quality.score,
    priority: assessments.some((item) => item.level === "critical")
      ? "urgent"
      : assessments.some((item) => item.level === "high" || item.level === "medium")
        ? "watch"
        : "routine",
    note: assessments[0]?.detail || "Vitals specialist report"
  });

  if (!countEnteredVitals(input)) {
    setVitalsRecordStatus("Add at least one vital reading before saving a report.", "medium");
    return;
  }

  appendVitalsReportToPatientRecords(
    entry,
    buildVitalsReportText(input, assessments, bmi, quality, buildVitalsTrendSummary(trendLog, input), trendLog),
    "Vitals specialist report"
  );
  setVitalsRecordStatus("Vitals report saved to Records and queued for localhost mirror.", "low");
}

function appendVitalsReportToPatientRecords(entry, report, episode = "Vitals specialist report") {
  const profile = collectProfile();
  const existingRecords = loadPatientDataRecords();
  const existingRecord = existingRecords.find((record) => record.id === `record-${entry.id}`);
  const record = normalizePatientDataRecordForClient({
    id: `record-${entry.id}`,
    createdAt: entry.createdAt || new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    patientName: profile.name || defaultProfile.name,
    age: profile.age || "",
    type: "vitals",
    date: formatDateForInput(new Date(entry.createdAt || Date.now())),
    episode,
    tags: ["vitals", entry.priority || "routine", formatVitalsContext(entry.measurement?.readingStatus || "single")],
    source: "Vitals Specialist Agent",
    documentCategory: "vitals-specialist-report",
    documentName: "Vitals specialist review",
    conditions: profile.conditions || "",
    allergies: profile.allergies || "",
    medicines: profile.medications || "",
    vitals: buildVitalsLabel(entry.vitals || {}),
    labs: "",
    notes: report,
    followUp: entry.priority === "urgent"
      ? "Use urgent real-world care if severe symptoms are active."
      : "Review repeated abnormal trends or concerning symptom combinations with a clinician.",
    versionNote: "Saved from Vitals Specialist Agent."
  });

  record.correctionHistory = buildRecordCorrectionHistory(existingRecord, record);

  const nextRecords = [
    record,
    ...existingRecords.filter((item) => item.id !== record.id)
  ].slice(0, 300);

  savePatientDataRecordsLocal(nextRecords);
  setSelectedPatientDataRecordId(record.id);
  renderPatientDataRecords();
  persistPatientDataRecords(nextRecords, record.id);
}

function setVitalsRecordStatus(message, level = "low") {
  const status = getVitalsDomCache()?.recordStatus;

  if (!status) {
    return;
  }

  setVitalsText(status, message);
  if (status.dataset.level !== level) {
    status.dataset.level = level;
  }
}

function initializeMedicineAgent() {
  const medicine = document.querySelector("#medicationsInterface");

  if (!medicine || medicine.dataset.medicineReady === "true") {
    return;
  }

  applyMedicineValues(readMedicineDraft());

  const refreshMedicine = (options = {}) => {
    latestMedicineAgentResult = null;
    saveMedicineDraft();
    renderMedicineReview(options);
  };
  const scheduleMedicineReview = createDeferredTask(() => refreshMedicine({ scope: "active" }), 160);

  for (const selector of ["#medicineNameInput", "#medicineStrengthInput", "#medicineFormSelect", "#medicineRouteSelect", "#medicineReviewType", "#medicineDiseaseSelect", "#medicineDoseInput", "#medicineFrequencySelect", "#medicineLastTakenInput", "#medicineConcernInput", "#medicineStatusSelect", "#medicineStartDateInput", "#medicinePrescriberInput", "#medicinePharmacyInput", "#medicineOtcInput", "#medicineAllergyInput", "#medicineBodyContext", "#medicineSideEffectInput", "#medicineSideEffectSeverity", "#medicineStorageSelect", "#medicineSourceSelect"]) {
    const control = medicine.querySelector(selector);

    if (!control) {
      continue;
    }

    if (control.matches("select, input[type='date']")) {
      control.addEventListener("change", () => refreshMedicine({ scope: "active" }));
    } else {
      control.addEventListener("input", scheduleMedicineReview);
    }
  }

  medicine.querySelector("#medicineVaultSearch")?.addEventListener("input", createDeferredTask(renderMedicineVault, 90));

  for (const control of medicine.querySelectorAll(".medicine-alert-check")) {
    control.addEventListener("change", () => refreshMedicine({ scope: "active" }));
  }

  for (const button of [medicine.querySelector("#medicineAnalyzeButton"), medicine.querySelector("#medicineAnalyzeTop")].filter(Boolean)) {
    button.addEventListener("click", () => runMedicineSpecialistReview(button));
  }

  medicine.querySelector("#medicineClearButton")?.addEventListener("click", resetMedicineAgent);
  medicine.querySelector("#medicineLookupButton")?.addEventListener("click", lookupMedicineEvidenceOnline);
  medicine.querySelector("#medicineSaveVaultButton")?.addEventListener("click", saveCurrentMedicineToVault);
  medicine.querySelector("#medicineSaveSideEffectButton")?.addEventListener("click", saveCurrentMedicineSideEffect);
  medicine.querySelector("#medicineSeedTestKitButton")?.addEventListener("click", seedMedicineTestKit);
  medicine.querySelector("#medicineCopyPacketButton")?.addEventListener("click", copyMedicinePacket);
  medicine.querySelector("#medicineDownloadPacketButton")?.addEventListener("click", downloadMedicinePacket);
  medicine.querySelector("#medicineSavePacketButton")?.addEventListener("click", saveMedicinePacketToRecords);
  medicine.querySelector("#medicineUseProfile")?.addEventListener("click", () => {
    loadProfileMedicinesIntoMedicineAgent();
    refreshMedicine({ full: true });
  });
  for (const jumpButton of medicine.querySelectorAll("[data-medicine-jump]")) {
    jumpButton.addEventListener("click", () => {
      const section = jumpButton.dataset.medicineJump || "intake";
      activateWorkspaceSubtab("medications", section, true);
      const target = section === "intake"
        ? medicine.querySelector(".medicine-search-card")
        : medicine.querySelector(`[data-workspace-section-button="${section}"]`);

      if (target && typeof target.scrollIntoView === "function") {
        target.scrollIntoView({ behavior: "smooth", block: "start" });
      }
    });
  }

  medicine.querySelector("#medicineVaultList")?.addEventListener("click", (event) => {
    const openButton = event.target.closest("[data-open-medicine]");
    const deleteButton = event.target.closest("[data-delete-medicine]");

    if (openButton) {
      openSavedMedicine(openButton.dataset.openMedicine);
    } else if (deleteButton) {
      deleteSavedMedicine(deleteButton.dataset.deleteMedicine);
    }
  });

  medicine.querySelector("#medicineSideEffectTimeline")?.addEventListener("click", (event) => {
    const deleteButton = event.target.closest("[data-delete-side-effect]");

    if (deleteButton) {
      deleteMedicineSideEffect(deleteButton.dataset.deleteSideEffect);
    }
  });

  for (const button of medicine.querySelectorAll("[data-medicine-example]")) {
    button.addEventListener("click", () => {
      applyMedicineExample(button.dataset.medicineExample || "profile");
      refreshMedicine({ full: true });
    });
  }

  medicine.dataset.medicineReady = "true";
  renderMedicineReview({ full: true });
}

function collectMedicineInputs() {
  return {
    name: document.querySelector("#medicineNameInput")?.value.trim() || "",
    strength: document.querySelector("#medicineStrengthInput")?.value.trim() || "",
    form: document.querySelector("#medicineFormSelect")?.value || "",
    route: document.querySelector("#medicineRouteSelect")?.value || "",
    reviewType: document.querySelector("#medicineReviewType")?.value || "general",
    disease: document.querySelector("#medicineDiseaseSelect")?.value || "all",
    dose: document.querySelector("#medicineDoseInput")?.value.trim() || "",
    frequency: document.querySelector("#medicineFrequencySelect")?.value || "",
    lastTaken: document.querySelector("#medicineLastTakenInput")?.value.trim() || "",
    concern: document.querySelector("#medicineConcernInput")?.value.trim() || "",
    status: document.querySelector("#medicineStatusSelect")?.value || "active",
    startDate: document.querySelector("#medicineStartDateInput")?.value || "",
    prescriber: document.querySelector("#medicinePrescriberInput")?.value.trim() || "",
    pharmacy: document.querySelector("#medicinePharmacyInput")?.value.trim() || "",
    otc: document.querySelector("#medicineOtcInput")?.value.trim() || "",
    allergy: document.querySelector("#medicineAllergyInput")?.value.trim() || "",
    bodyContext: document.querySelector("#medicineBodyContext")?.value || "",
    sideEffect: document.querySelector("#medicineSideEffectInput")?.value.trim() || "",
    sideEffectSeverity: document.querySelector("#medicineSideEffectSeverity")?.value || "",
    storage: document.querySelector("#medicineStorageSelect")?.value || "",
    sourceChecked: document.querySelector("#medicineSourceSelect")?.value || "",
    alertChecks: Array.from(document.querySelectorAll(".medicine-alert-check:checked")).map((input) => input.value),
    profile: collectProfile()
  };
}

function readMedicineDraft() {
  try {
    return JSON.parse(localStorage.getItem(storageKeys.medicineDraft) || "{}") || {};
  } catch {
    return {};
  }
}

function saveMedicineDraft(input = collectMedicineInputs()) {
  const draft = {
    name: input.name || "",
    strength: input.strength || "",
    form: input.form || "",
    route: input.route || "",
    reviewType: input.reviewType || "general",
    disease: input.disease || "all",
    dose: input.dose || "",
    frequency: input.frequency || "",
    lastTaken: input.lastTaken || "",
    concern: input.concern || "",
    status: input.status || "active",
    startDate: input.startDate || "",
    prescriber: input.prescriber || "",
    pharmacy: input.pharmacy || "",
    otc: input.otc || "",
    allergy: input.allergy || "",
    bodyContext: input.bodyContext || "",
    sideEffect: input.sideEffect || "",
    sideEffectSeverity: input.sideEffectSeverity || "",
    storage: input.storage || "",
    sourceChecked: input.sourceChecked || "",
    alertChecks: Array.isArray(input.alertChecks) ? input.alertChecks : []
  };

  saveJson(storageKeys.medicineDraft, draft);
}

async function runMedicineSpecialistReview(button) {
  const input = collectMedicineInputs();
  const message = buildMedicineSpecialistMessage(input);

  saveMedicineDraft(input);
  renderMedicineReview({ scope: "active" });
  setMedicineRunButtonsLoading(true);
  setMedicinePacketStatus("Medicine Specialist Agent is checking label context, interactions, warning signs, and pharmacist questions.", "low");

  try {
    const result = await runAnalysis(message, {
      interfaceName: "medications",
      singleAgentMode: true,
      preferredAgent: "PHARMACY_AGENT",
      answerMode: getActiveAnswerMode("medications"),
      context: {
        careGoal: "medicine-safety",
        lastMedicationTime: input.lastTaken || "",
        severity: input.sideEffectSeverity === "urgent" ? "8" : input.sideEffectSeverity === "severe" ? "7" : input.sideEffectSeverity === "moderate" ? "5" : "4",
        redFlags: input.alertChecks || []
      }
    });

    if (result) {
      latestMedicineAgentResult = result;
      renderMedicineReview({ full: true });
      activateWorkspaceSubtab("medications", "safety", true);
      setMedicinePacketStatus("Medicine Specialist Agent completed. Review the priority, next step, and pharmacist packet below.", "low");
    }
  } catch (error) {
    console.warn("Medicine Specialist Agent review failed.", error);
    setMedicinePacketStatus("Medicine Specialist Agent could not complete this review. Your local medicine guidance remains available.", "medium");
  } finally {
    setMedicineRunButtonsLoading(false);
  }
}

function buildMedicineSpecialistMessage(input) {
  const profile = input.profile || collectProfile();
  const sections = [
    `Medicine question: ${input.concern || "Review medicine safety, interactions, side effects, and safe next steps."}`,
    `Medicine entered: ${input.name || profile.medications || "not entered"}`,
    `Strength/form/route: ${[input.strength, input.form ? formatMedicineContext(input.form) : "", input.route ? formatMedicineContext(input.route) : ""].filter(Boolean).join(" / ") || "not entered"}`,
    `Review type: ${formatMedicineContext(input.reviewType)}; disease area: ${formatMedicineArea(input.disease || "all")}`,
    `Label instruction: ${input.dose || "not entered"}; frequency: ${input.frequency ? formatMedicineContext(input.frequency) : "not entered"}; last taken: ${input.lastTaken || "not entered"}`,
    `Status/source: ${[input.status ? formatMedicineContext(input.status) : "", input.prescriber, input.pharmacy].filter(Boolean).join(" / ") || "not entered"}`,
    `OTC/supplements/foods: ${input.otc || "not entered"}`,
    `Allergies or past reactions: ${input.allergy || profile.allergies || "not recorded"}`,
    `Body context: ${input.bodyContext ? formatMedicineContext(input.bodyContext) : "not entered"}`,
    `Side-effect diary: ${input.sideEffect || "not entered"}${input.sideEffectSeverity ? ` (${formatMedicineContext(input.sideEffectSeverity)})` : ""}`,
    `High-alert checks: ${input.alertChecks.length ? input.alertChecks.map(formatMedicineContext).join(", ") : "none selected"}`,
    `Patient context: ${profile.name || "Patient"}${profile.age ? `, ${profile.age}` : ""}; conditions: ${profile.conditions || "not recorded"}.`
  ];

  return sections.join("\n");
}

function setMedicineRunButtonsLoading(isLoading) {
  for (const button of [document.querySelector("#medicineAnalyzeButton"), document.querySelector("#medicineAnalyzeTop")].filter(Boolean)) {
    setMedicineRunButtonLoading(button, isLoading);
  }
}

function setMedicineRunButtonLoading(button, isLoading) {
  if (!button) {
    return;
  }

  button.disabled = isLoading;
  clearNode(button);
  button.append(createIcon(isLoading ? "icon-gauge" : "icon-send", "button-icon"), document.createTextNode(isLoading ? "Reviewing" : button.id === "medicineAnalyzeTop" ? "Run Specialist" : "Review Safely"));
}

function resetMedicineAgent() {
  latestMedicineAgentResult = null;

  for (const selector of ["#medicineNameInput", "#medicineStrengthInput", "#medicineDoseInput", "#medicineLastTakenInput", "#medicineConcernInput", "#medicineStartDateInput", "#medicinePrescriberInput", "#medicinePharmacyInput", "#medicineOtcInput", "#medicineAllergyInput", "#medicineSideEffectInput"]) {
    const control = document.querySelector(selector);
    if (control) control.value = "";
  }

  const form = document.querySelector("#medicineFormSelect");
  const route = document.querySelector("#medicineRouteSelect");
  const disease = document.querySelector("#medicineDiseaseSelect");
  const reviewType = document.querySelector("#medicineReviewType");
  const frequency = document.querySelector("#medicineFrequencySelect");
  const status = document.querySelector("#medicineStatusSelect");
  const bodyContext = document.querySelector("#medicineBodyContext");
  const sideEffectSeverity = document.querySelector("#medicineSideEffectSeverity");
  const storage = document.querySelector("#medicineStorageSelect");
  const sourceChecked = document.querySelector("#medicineSourceSelect");

  if (form) form.value = "";
  if (route) route.value = "";
  if (disease) disease.value = "all";
  if (reviewType) reviewType.value = "general";
  if (frequency) frequency.value = "";
  if (status) status.value = "active";
  if (bodyContext) bodyContext.value = "";
  if (sideEffectSeverity) sideEffectSeverity.value = "";
  if (storage) storage.value = "";
  if (sourceChecked) sourceChecked.value = "";

  for (const control of document.querySelectorAll(".medicine-alert-check")) {
    control.checked = false;
  }

  removeLocalStorageValue(storageKeys.medicineDraft);
  renderMedicineReview({ full: true });
}

