function getMedicineExampleValue(example = "profile") {
  const examples = getMedicineExamplePresets();
  return examples[example] || examples.profile;
}

function seedMedicineTestKit() {
  const now = new Date();
  const examples = ["test-amlodipine", "test-losartan", "test-metformin"]
    .map((key, index) => normalizeMedicineVaultEntry({
      ...getMedicineExampleValue(key),
      patientId,
      id: `medicine-demo-${key}`,
      createdAt: new Date(now.getTime() - (index + 1) * 60000).toISOString(),
      updatedAt: new Date(now.getTime() - (index + 1) * 60000).toISOString()
    }))
    .filter(Boolean);

  saveMedicineVault(mergeMedicineVaultEntries(loadMedicineVault(), examples));
  activateWorkspaceSubtab("medications", "interactions", true);
  setMedicinePacketStatus("3 testing cases added to Saved medicine. Open them from the vault list.", "low");
  renderMedicineReview({ full: true });
}

function applyMedicineExample(example) {
  const value = getMedicineExampleValue(example);
  applyMedicineValues(value);
  setMedicinePacketStatus("Testing scenario loaded. Run the review or save it to the local medicine vault.", "low");
}

function applyMedicineValues(value = {}) {
  const defaults = {
    name: "",
    strength: "",
    form: "",
    route: "",
    reviewType: "general",
    disease: "all",
    dose: "",
    frequency: "",
    lastTaken: "",
    concern: "",
    status: "active",
    startDate: "",
    prescriber: "",
    pharmacy: "",
    otc: "",
    allergy: "",
    bodyContext: "",
    sideEffect: "",
    sideEffectSeverity: "",
    storage: "",
    sourceChecked: ""
  };
  const controls = {
    name: document.querySelector("#medicineNameInput"),
    strength: document.querySelector("#medicineStrengthInput"),
    form: document.querySelector("#medicineFormSelect"),
    route: document.querySelector("#medicineRouteSelect"),
    reviewType: document.querySelector("#medicineReviewType"),
    disease: document.querySelector("#medicineDiseaseSelect"),
    dose: document.querySelector("#medicineDoseInput"),
    frequency: document.querySelector("#medicineFrequencySelect"),
    lastTaken: document.querySelector("#medicineLastTakenInput"),
    concern: document.querySelector("#medicineConcernInput"),
    status: document.querySelector("#medicineStatusSelect"),
    startDate: document.querySelector("#medicineStartDateInput"),
    prescriber: document.querySelector("#medicinePrescriberInput"),
    pharmacy: document.querySelector("#medicinePharmacyInput"),
    otc: document.querySelector("#medicineOtcInput"),
    allergy: document.querySelector("#medicineAllergyInput"),
    bodyContext: document.querySelector("#medicineBodyContext"),
    sideEffect: document.querySelector("#medicineSideEffectInput"),
    sideEffectSeverity: document.querySelector("#medicineSideEffectSeverity"),
    storage: document.querySelector("#medicineStorageSelect"),
    sourceChecked: document.querySelector("#medicineSourceSelect")
  };

  for (const [key, control] of Object.entries(controls)) {
    if (control) {
      control.value = value[key] || defaults[key] || "";
    }
  }

  for (const control of document.querySelectorAll(".medicine-alert-check")) {
    control.checked = (value.alertChecks || []).includes(control.value);
  }
}

const medicineRenderSectionsByTab = {
  intake: new Set(["score"]),
  safety: new Set(["score", "identity", "evidence", "guidance"]),
  interactions: new Set(["vault", "dose", "interactions", "sideeffects"]),
  library: new Set(["library", "disease"]),
  passport: new Set(["schedule", "passport", "packet", "questions"])
};

function getMedicineRenderScope(options = {}) {
  if (options.full || options.scope === "all") {
    return "all";
  }

  if (options.scope && options.scope !== "active") {
    return options.scope;
  }

  const view = document.querySelector("#medicationsInterface");

  if (!view?.querySelector(".workspace-section-tabs")) {
    return "all";
  }

  return view.dataset.activeWorkspaceSection || "intake";
}

function shouldRenderMedicineSection(section, scope) {
  if (scope === "all") {
    return true;
  }

  return medicineRenderSectionsByTab[scope]?.has(section) || false;
}

function scheduleMedicineSectionRender(scope = "active") {
  if (typeof window === "undefined") {
    renderMedicineReview({ scope });
    return;
  }

  if (medicineSectionRenderFrame) {
    window.cancelAnimationFrame(medicineSectionRenderFrame);
  }

  medicineSectionRenderFrame = window.requestAnimationFrame(() => {
    medicineSectionRenderFrame = null;
    renderMedicineReview({ scope });
  });
}

function renderMedicineReview(options = {}) {
  const scope = getMedicineRenderScope(options);
  const shouldRender = (section) => shouldRenderMedicineSection(section, scope);
  const input = collectMedicineInputs();
  const profileMedicines = splitMedicineNames(input.profile.medications);
  const matches = findMedicineMatches(input, profileMedicines);
  const vault = loadMedicineVault();
  const readiness = scoreMedicineReadiness(input, matches, profileMedicines);
  const warningItems = buildMedicineWarnings(input, matches);
  const interactionItems = buildMedicineInteractionItems(input, matches, vault);
  const watchCount = interactionItems.filter((item) => item.level !== "none" && item.title !== "Warning sign").length;
  const evidence = shouldRender("identity") || shouldRender("evidence") || shouldRender("packet")
    ? getCachedMedicineEvidence(input)
    : null;
  const sideEffects = shouldRender("sideeffects") || shouldRender("packet")
    ? loadMedicineSideEffects()
    : [];

  if (shouldRender("score")) {
    updateMedicineScore(readiness, matches.length, warningItems.length, watchCount);
  }
  if (shouldRender("vault")) {
    renderMedicineVault(vault);
  }
  if (shouldRender("identity")) {
    renderMedicineIdentity(input, matches, evidence);
  }
  if (shouldRender("evidence")) {
    renderMedicineEvidence(evidence, input, matches);
  }
  if (shouldRender("guidance")) {
    renderMedicineGuidance(input, matches, readiness);
  }
  if (shouldRender("library")) {
    renderMedicineLibrary(matches, input);
  }
  if (shouldRender("disease")) {
    renderMedicineDiseaseGuide(input.disease);
  }
  if (shouldRender("dose")) {
    renderMedicineDoseGuidance(input, matches);
  }
  if (shouldRender("interactions")) {
    renderDashboardList(document.querySelector("#medicineInteractionList"), interactionItems);
  }
  if (shouldRender("sideeffects")) {
    renderMedicineSideEffectTimeline(sideEffects);
  }
  if (shouldRender("schedule")) {
    renderMedicineSchedule(input, profileMedicines);
  }
  if (shouldRender("passport")) {
    renderMedicinePassport(input, matches, warningItems, interactionItems, readiness);
  }
  if (shouldRender("packet")) {
    const packet = buildMedicinePharmacistPacket(input, matches, warningItems, interactionItems, readiness, evidence, vault, sideEffects);
    renderMedicinePacket(packet);
  }
  if (shouldRender("questions")) {
    renderMedicineQuestions(input, matches);
  }
}

function getMedicineVaultStorageKey(targetPatientId = patientId) {
  return `${storageKeys.medicineVault}.${normalizePatientStorageId(targetPatientId)}`;
}

function getMedicineSideEffectStorageKey(targetPatientId = patientId) {
  return `${storageKeys.medicineSideEffects}.${normalizePatientStorageId(targetPatientId)}`;
}

const medicineVaultRecordContextKeys = {
  forms: ["tablet", "capsule", "liquid", "inhaler", "injection", "cream", "drops", "patch"],
  routes: ["oral", "inhaled", "injection", "skin", "eye-ear", "nasal"],
  statuses: ["active", "new", "changed", "stopped", "as-needed", "unknown"],
  frequencies: ["once-daily", "twice-daily", "three-times", "weekly", "as-needed", "other"],
  reviewTypes: ["general", "missed-dose", "overdose-or-duplicate", "side-effects", "interactions", "allergy", "label-use", "pharmacist"],
  bodyContexts: ["kidney", "liver", "pregnancy", "older-adult", "procedure", "dehydration"],
  storage: ["stored-correctly", "expired", "heat-light", "fridge-question"],
  alertChecks: ["blood-thinner", "insulin", "antibiotic", "steroid", "sedating", "duplicate", "opioid", "narrow-index", "organ-risk"]
};

function loadMedicineVault(targetPatientId = patientId) {
  const storageKey = getMedicineVaultStorageKey(targetPatientId);
  const hasStoredVault = typeof localStorage !== "undefined" && localStorage.getItem(storageKey) !== null;
  const storedEntries = loadJson(storageKey, [])
    .map(normalizeMedicineVaultEntry)
    .filter(Boolean)
    .sort((left, right) => new Date(right.updatedAt).getTime() - new Date(left.updatedAt).getTime());

  if (hasStoredVault && !storedEntries.length) {
    return storedEntries;
  }

  return mergeMedicineVaultEntries(storedEntries, loadMedicineVaultFromRecords(targetPatientId));
}

function loadMedicineVaultFromRecords(targetPatientId = patientId) {
  return loadPatientDataRecords(targetPatientId)
    .filter((record) => record?.type === "medicine" && (record.source === "Medicine tab" || record.documentCategory === "prescription-note"))
    .map((record) => normalizeMedicineRecordToVaultEntry(record, targetPatientId))
    .filter(Boolean)
    .sort((left, right) => new Date(right.updatedAt).getTime() - new Date(left.updatedAt).getTime());
}

function mergeMedicineVaultEntries(primary = [], secondary = []) {
  const merged = [];
  const seen = new Set();

  for (const entry of [...primary, ...secondary].filter(Boolean)) {
    const matchKey = normalizeMedicineText(`${entry.name || ""} ${entry.strength || ""}`) || entry.id;

    if (seen.has(matchKey)) {
      continue;
    }

    seen.add(matchKey);
    merged.push(entry);
  }

  return merged.sort((left, right) => new Date(right.updatedAt).getTime() - new Date(left.updatedAt).getTime());
}

function normalizeMedicineRecordToVaultEntry(record = {}, targetPatientId = patientId) {
  const packetLines = getMedicinePacketLines(record.notes);
  const medicineFields = String(record.medicines || "")
    .split(";")
    .map((item) => item.trim())
    .filter(Boolean);
  const tags = Array.isArray(record.tags)
    ? record.tags.map((tag) => String(tag || "").trim()).filter(Boolean)
    : String(record.tags || "")
      .split(/[,;\n]+/)
      .map((tag) => tag.trim())
      .filter(Boolean);
  const identity = parseMedicineRecordIdentity(getMedicinePacketSingleLine(packetLines, "Strength/form/route"));
  const statusSource = parseMedicineRecordStatusSource(getMedicinePacketSingleLine(packetLines, "Status/source"), record);
  const label = parseMedicineRecordLabel(getMedicinePacketSingleLine(packetLines, "Written label"));
  const name = cleanMedicineRecordValue(getMedicinePacketSingleLine(packetLines, "Name"))
    || cleanMedicineRecordValue(medicineFields[0])
    || cleanMedicineRecordValue(String(record.documentName || "").replace(/\s+safety review$/i, ""));

  if (!name) {
    return null;
  }

  return normalizeMedicineVaultEntry({
    id: String(record.id || "").replace(/^record-medicine-/, "").trim() || `medicine-record-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    patientId: targetPatientId,
    name,
    strength: identity.strength || cleanMedicineRecordValue(medicineFields[1]),
    form: identity.form,
    route: identity.route,
    disease: "all",
    reviewType: pickMedicineRecordTag(tags, medicineVaultRecordContextKeys.reviewTypes) || "general",
    dose: label.dose || cleanMedicineRecordValue(medicineFields[2]),
    frequency: label.frequency || parseMedicineContextKey(cleanMedicineRecordValue(medicineFields[3]), medicineVaultRecordContextKeys.frequencies),
    status: statusSource.status || pickMedicineRecordTag(tags, medicineVaultRecordContextKeys.statuses) || "active",
    startDate: record.date || "",
    lastTaken: label.lastTaken,
    prescriber: statusSource.prescriber,
    pharmacy: statusSource.pharmacy,
    storage: parseMedicineContextKey(getMedicinePacketSingleLine(packetLines, "Storage"), medicineVaultRecordContextKeys.storage),
    bodyContext: parseMedicineContextKey(getMedicinePacketSingleLine(packetLines, "Body context"), medicineVaultRecordContextKeys.bodyContexts),
    otc: cleanMedicineRecordValue(getMedicinePacketSingleLine(packetLines, "OTC/supplements")),
    allergy: cleanMedicineRecordValue(record.allergies),
    concern: cleanMedicineRecordValue(getMedicinePacketSection(packetLines, "Review Request")),
    sideEffect: "",
    sideEffectSeverity: "",
    alertChecks: parseMedicineRecordAlertChecks(getMedicinePacketSingleLine(packetLines, "High-alert flags")),
    createdAt: record.createdAt || record.updatedAt || new Date().toISOString(),
    updatedAt: record.updatedAt || record.createdAt || new Date().toISOString()
  });
}

function getMedicinePacketLines(text = "") {
  return String(text || "")
    .split(/\r?\n/)
    .map((line) => line.trim());
}

function getMedicinePacketSingleLine(linesOrText, label) {
  const lines = Array.isArray(linesOrText) ? linesOrText : getMedicinePacketLines(linesOrText);
  const prefix = `${label}:`;
  const match = lines.find((line) => line.startsWith(prefix));
  return match ? match.slice(prefix.length).trim() : "";
}

function getMedicinePacketSection(linesOrText, heading) {
  const lines = Array.isArray(linesOrText) ? linesOrText : getMedicinePacketLines(linesOrText);
  const sectionIndex = lines.findIndex((line) => line === heading);

  if (sectionIndex === -1) {
    return "";
  }

  const sectionLines = [];

  for (let index = sectionIndex + 1; index < lines.length; index += 1) {
    const line = lines[index];

    if (!line) {
      break;
    }

    sectionLines.push(line);
  }

  return sectionLines.join(" ").trim();
}

function cleanMedicineRecordValue(value = "") {
  const text = String(value || "").trim();

  if (!text || /^(not entered|not checked|not recorded|none selected|no specific question entered\.?|frequency not entered)$/i.test(text)) {
    return "";
  }

  return text;
}

function pickMedicineRecordTag(tags = [], allowedKeys = []) {
  const normalizedAllowed = new Set(allowedKeys.map((key) => normalizeMedicineText(key)));
  const match = tags.find((tag) => normalizedAllowed.has(normalizeMedicineText(tag)));
  return match ? allowedKeys.find((key) => normalizeMedicineText(key) === normalizeMedicineText(match)) || "" : "";
}

function parseMedicineContextKey(value = "", allowedKeys = []) {
  const normalizedValue = normalizeMedicineText(cleanMedicineRecordValue(value));

  if (!normalizedValue) {
    return "";
  }

  return allowedKeys.find((key) => normalizeMedicineText(formatMedicineContext(key)) === normalizedValue || normalizeMedicineText(key) === normalizedValue) || "";
}

function splitTrailingMedicineContextValue(value = "", allowedKeys = []) {
  const text = String(value || "").trim();
  const sortedKeys = allowedKeys.slice().sort((left, right) => formatMedicineContext(right).length - formatMedicineContext(left).length);

  for (const key of sortedKeys) {
    const label = formatMedicineContext(key);

    if (text === label) {
      return { remainder: "", key };
    }

    const suffix = ` / ${label}`;

    if (text.endsWith(suffix)) {
      return {
        remainder: text.slice(0, -suffix.length).trim(),
        key
      };
    }
  }

  return {
    remainder: text,
    key: ""
  };
}

function parseMedicineRecordIdentity(line = "") {
  const cleanedLine = cleanMedicineRecordValue(line);

  if (!cleanedLine) {
    return {
      strength: "",
      form: "",
      route: ""
    };
  }

  const routePart = splitTrailingMedicineContextValue(cleanedLine, medicineVaultRecordContextKeys.routes);
  const formPart = splitTrailingMedicineContextValue(routePart.remainder, medicineVaultRecordContextKeys.forms);

  return {
    strength: cleanMedicineRecordValue(formPart.remainder),
    form: formPart.key,
    route: routePart.key
  };
}

function parseMedicineRecordStatusSource(line = "", record = {}) {
  const cleanedLine = cleanMedicineRecordValue(line);
  const parts = cleanedLine
    ? cleanedLine.split(/\s*\/\s*/).map((item) => item.trim()).filter(Boolean)
    : [];
  const status = parseMedicineContextKey(parts[0], medicineVaultRecordContextKeys.statuses);
  const details = status ? parts.slice(1) : parts;

  return {
    status,
    prescriber: cleanMedicineRecordValue(details[0]) || (record.source && record.source !== "Medicine tab" ? String(record.source).trim() : ""),
    pharmacy: cleanMedicineRecordValue(details.slice(1).join(" / "))
  };
}

function parseMedicineRecordLabel(line = "") {
  const cleanedLine = cleanMedicineRecordValue(line);

  if (!cleanedLine) {
    return {
      dose: "",
      frequency: "",
      lastTaken: ""
    };
  }

  const match = cleanedLine.match(/^(.*?)(?:;\s*frequency:\s*([^;]+))?(?:;\s*last taken:\s*(.+))?$/i);

  return {
    dose: cleanMedicineRecordValue(match?.[1] || cleanedLine),
    frequency: parseMedicineContextKey(match?.[2] || "", medicineVaultRecordContextKeys.frequencies),
    lastTaken: cleanMedicineRecordValue(match?.[3] || "")
  };
}

function parseMedicineRecordAlertChecks(value = "") {
  return cleanMedicineRecordValue(value)
    .split(/\s*,\s*/)
    .map((item) => parseMedicineContextKey(item, medicineVaultRecordContextKeys.alertChecks))
    .filter(Boolean);
}

function saveMedicineVault(entries = [], targetPatientId = patientId, options = {}) {
  saveJson(getMedicineVaultStorageKey(targetPatientId), entries.map(normalizeMedicineVaultEntry).filter(Boolean).slice(0, 120), {
    targetPatientId,
    reason: "medicine-update",
    ...options
  });
}

function normalizeMedicineVaultEntry(entry = {}) {
  const name = String(entry.name || "").trim();

  if (!name) {
    return null;
  }

  const now = new Date().toISOString();
  const id = entry.id || `medicine-${Date.now()}-${Math.random().toString(16).slice(2)}`;

  return {
    id,
    patientId: entry.patientId || patientId || defaultProfile.id,
    name,
    strength: String(entry.strength || "").trim(),
    form: entry.form || "",
    route: entry.route || "",
    disease: entry.disease || "all",
    reviewType: entry.reviewType || "general",
    dose: String(entry.dose || "").trim(),
    frequency: entry.frequency || "",
    status: entry.status || "active",
    startDate: entry.startDate || "",
    lastTaken: String(entry.lastTaken || "").trim(),
    prescriber: String(entry.prescriber || "").trim(),
    pharmacy: String(entry.pharmacy || "").trim(),
    sourceChecked: entry.sourceChecked || "",
    storage: entry.storage || "",
    bodyContext: entry.bodyContext || "",
    otc: String(entry.otc || "").trim(),
    allergy: String(entry.allergy || "").trim(),
    concern: String(entry.concern || "").trim(),
    sideEffect: String(entry.sideEffect || "").trim(),
    sideEffectSeverity: entry.sideEffectSeverity || "",
    alertChecks: Array.isArray(entry.alertChecks) ? entry.alertChecks.slice(0, 12) : [],
    createdAt: entry.createdAt || now,
    updatedAt: entry.updatedAt || now
  };
}

function saveCurrentMedicineToVault() {
  const input = collectMedicineInputs();

  if (!input.name) {
    setMedicinePacketStatus("Add a medicine name before saving.", "medium");
    return;
  }

  const entry = normalizeMedicineVaultEntry({
    ...input,
    patientId,
    updatedAt: new Date().toISOString()
  });
  const existing = loadMedicineVault();
  const matchKey = normalizeMedicineText(`${entry.name} ${entry.strength}`);
  const previous = existing.find((item) => normalizeMedicineText(`${item.name} ${item.strength}`) === matchKey);
  const nextEntry = previous
    ? { ...entry, id: previous.id, createdAt: previous.createdAt || entry.createdAt }
    : entry;
  const next = [nextEntry, ...existing.filter((item) => item.id !== nextEntry.id)].slice(0, 120);
  const profileMedicines = splitMedicineNames(input.profile.medications);
  const matches = findMedicineMatches(input, profileMedicines);
  const warningItems = buildMedicineWarnings(input, matches);
  const interactionItems = buildMedicineInteractionItems(input, matches, next);
  const readiness = scoreMedicineReadiness(input, matches, profileMedicines);
  const packet = buildMedicinePharmacistPacket(
    input,
    matches,
    warningItems,
    interactionItems,
    readiness,
    getCachedMedicineEvidence(input),
    next,
    loadMedicineSideEffects()
  );

  saveMedicineVault(next);
  appendMedicineReviewToPatientRecords(nextEntry, packet, "Medicine reconciliation");
  setMedicinePacketStatus("Medicine saved locally and mirrored through Records.", "low");
  renderMedicineReview({ full: true });
}

function renderMedicineVault(entries = loadMedicineVault()) {
  const list = document.querySelector("#medicineVaultList");

  if (!list) {
    return;
  }

  const query = normalizeMedicineText(document.querySelector("#medicineVaultSearch")?.value || "");
  const filtered = entries.filter((entry) => !query || normalizeMedicineText(`${entry.name} ${entry.strength} ${entry.status} ${entry.prescriber}`).includes(query));
  clearNode(list);

  if (!filtered.length) {
    const item = document.createElement("li");
    const profileMedicines = splitMedicineNames(collectProfile().medications);
    const detail = profileMedicines.length
      ? `Profile has ${profileMedicines.join(", ")}. Load profile or save the current review.`
      : "No saved medicines yet. Add a medicine name and save it here.";

    item.append(createIcon("icon-memory", "chip-icon"), document.createElement("strong"), document.createElement("span"));
    item.querySelector("strong").textContent = "No saved medicine in this view";
    item.querySelector("span").textContent = detail;
    list.append(item);
    return;
  }

  for (const entry of filtered.slice(0, 18)) {
    const item = document.createElement("li");
    const title = document.createElement("strong");
    const detail = document.createElement("span");
    const actions = document.createElement("div");
    const open = document.createElement("button");
    const remove = document.createElement("button");

    item.className = "medicine-vault-item";
    title.textContent = `${entry.name}${entry.strength ? ` ${entry.strength}` : ""}`;
    detail.textContent = [
      formatMedicineContext(entry.status),
      entry.form ? formatMedicineContext(entry.form) : "",
      entry.route ? formatMedicineContext(entry.route) : "",
      entry.frequency ? formatMedicineContext(entry.frequency) : "",
      entry.prescriber ? `Source: ${entry.prescriber}` : ""
    ].filter(Boolean).join(" - ") || "Saved medicine entry";
    actions.className = "medicine-vault-item-actions";
    open.type = "button";
    open.dataset.openMedicine = entry.id;
    open.textContent = "Open";
    remove.type = "button";
    remove.dataset.deleteMedicine = entry.id;
    remove.textContent = "Delete";

    actions.append(open, remove);
    item.append(createIcon("icon-pill", "chip-icon"), title, detail, actions);
    list.append(item);
  }
}

function openSavedMedicine(id) {
  const entry = loadMedicineVault().find((item) => item.id === id);

  if (!entry) {
    return;
  }

  applyMedicineValues(entry);
  setMedicinePacketStatus("Saved medicine loaded into the review.", "low");
  renderMedicineReview({ full: true });
}

function deleteSavedMedicine(id) {
  saveMedicineVault(loadMedicineVault().filter((entry) => entry.id !== id));
  setMedicinePacketStatus("Saved medicine removed from this patient vault.", "low");
  renderMedicineReview({ full: true });
}

function loadMedicineSideEffects(targetPatientId = patientId) {
  return loadJson(getMedicineSideEffectStorageKey(targetPatientId), [])
    .map(normalizeMedicineSideEffectEntry)
    .filter(Boolean)
    .sort((left, right) => new Date(right.at).getTime() - new Date(left.at).getTime());
}

function saveMedicineSideEffects(entries = [], targetPatientId = patientId, options = {}) {
  saveJson(getMedicineSideEffectStorageKey(targetPatientId), entries.map(normalizeMedicineSideEffectEntry).filter(Boolean).slice(0, 160), {
    targetPatientId,
    reason: "medicine-side-effect-update",
    ...options
  });
}

function normalizeMedicineSideEffectEntry(entry = {}) {
  const symptom = String(entry.symptom || entry.sideEffect || "").trim();

  if (!symptom) {
    return null;
  }

  const now = new Date().toISOString();

  return {
    id: entry.id || `medicine-effect-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    patientId: entry.patientId || patientId || defaultProfile.id,
    medicine: String(entry.medicine || entry.name || "").trim() || "Medicine not named",
    symptom,
    severity: entry.severity || "",
    timing: String(entry.timing || entry.lastTaken || "").trim(),
    status: entry.status || "watch",
    at: entry.at || now
  };
}

function saveCurrentMedicineSideEffect() {
  const input = collectMedicineInputs();

  if (!input.sideEffect) {
    setMedicinePacketStatus("Add a side-effect note before saving it.", "medium");
    return;
  }

  const entry = normalizeMedicineSideEffectEntry({
    patientId,
    medicine: input.name || splitMedicineNames(input.profile.medications)[0] || "Medicine not named",
    symptom: input.sideEffect,
    severity: input.sideEffectSeverity,
    timing: input.lastTaken,
    status: /urgent|severe/i.test(input.sideEffectSeverity) ? "urgent" : "watch"
  });
  const next = [entry, ...loadMedicineSideEffects()].slice(0, 160);

  saveMedicineSideEffects(next);
  setMedicinePacketStatus("Side-effect timeline updated locally.", "low");
  renderMedicineReview({ full: true });
}

function renderMedicineSideEffectTimeline(entries = loadMedicineSideEffects()) {
  const list = document.querySelector("#medicineSideEffectTimeline");

  if (!list) {
    return;
  }

  clearNode(list);

  if (!entries.length) {
    const item = document.createElement("li");
    item.append(createIcon("icon-alert", "chip-icon"), document.createElement("strong"), document.createElement("span"));
    item.querySelector("strong").textContent = "No side effects saved";
    item.querySelector("span").textContent = "Save symptom timing, severity, and medicine name when a reaction or side effect is being tracked.";
    list.append(item);
    return;
  }

  for (const entry of entries.slice(0, 10)) {
    const item = document.createElement("li");
    const title = document.createElement("strong");
    const detail = document.createElement("span");
    const actions = document.createElement("div");
    const remove = document.createElement("button");

    item.className = "medicine-vault-item";
    title.textContent = `${entry.medicine} - ${formatMedicineContext(entry.severity || entry.status)}`;
    detail.textContent = `${formatRecordUpdatedAt(entry.at)} - ${entry.symptom}${entry.timing ? `; timing: ${entry.timing}` : ""}`;
    actions.className = "medicine-vault-item-actions";
    remove.type = "button";
    remove.dataset.deleteSideEffect = entry.id;
    remove.textContent = "Delete";
    actions.append(remove);
    item.append(createIcon(entry.status === "urgent" ? "icon-alert" : "icon-pill", "chip-icon"), title, detail, actions);
    list.append(item);
  }
}

function deleteMedicineSideEffect(id) {
  saveMedicineSideEffects(loadMedicineSideEffects().filter((entry) => entry.id !== id));
  setMedicinePacketStatus("Side-effect entry removed.", "low");
  renderMedicineReview({ full: true });
}

function getMedicineEvidenceCache() {
  return loadJson(storageKeys.medicineEvidenceCache, {});
}

function saveMedicineEvidenceCache(cache) {
  saveJson(storageKeys.medicineEvidenceCache, cache || {});
}

function buildMedicineLookupQuery(input = collectMedicineInputs()) {
  const firstName = splitMedicineNames(input.name)[0] || splitMedicineNames(input.profile?.medications)[0] || "";
  return firstName
    .replace(/\b\d+(?:\.\d+)?\s*(mg|mcg|g|ml|iu|units?)\b/gi, " ")
    .replace(/[^\p{L}\p{N}\s+./-]/gu, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function getMedicineEvidenceCacheKey(query) {
  return normalizeMedicineText(query).replace(/\s+/g, "-").slice(0, 80);
}

function getCachedMedicineEvidence(input = collectMedicineInputs()) {
  const query = buildMedicineLookupQuery(input);
  const key = getMedicineEvidenceCacheKey(query);
  const cache = getMedicineEvidenceCache();
  return key && cache[key] ? cache[key] : null;
}

async function lookupMedicineEvidenceOnline() {
  const input = collectMedicineInputs();
  const query = buildMedicineLookupQuery(input);
  const button = document.querySelector("#medicineLookupButton");

  if (!query) {
    setMedicinePacketStatus("Add a medicine name before checking label evidence.", "medium");
    return;
  }

  if (button) {
    button.disabled = true;
    button.textContent = "Checking...";
  }
  setMedicinePacketStatus("Checking online sources or local cache.", "low");

  if (isStaticRuntime()) {
    setMedicinePacketStatus("GitHub mode is using the local medicine guide. Open the local server for optional online label lookup.", "medium");
    if (button) {
      clearNode(button);
      button.disabled = false;
      button.append(createIcon("icon-shield", "button-icon"), document.createTextNode("Check label"));
    }
    renderMedicineReview({ full: true });
    return;
  }

  try {
    const response = await fetch(`/api/medicine/lookup?q=${encodeURIComponent(query)}&refresh=true`);
    const payload = await response.json();

    if (!response.ok || !payload.ok) {
      throw new Error(payload.message || payload.lookup?.message || "Label check failed.");
    }

    const cache = getMedicineEvidenceCache();
    cache[getMedicineEvidenceCacheKey(query)] = payload.lookup;
    saveMedicineEvidenceCache(cache);
    setMedicinePacketStatus(payload.lookup.fetchedOnline ? "Online label evidence cached locally." : "Using local medicine evidence cache.", "low");
  } catch {
    setMedicinePacketStatus("Online label check is unavailable. Local medicine guide is still active.", "medium");
  } finally {
    if (button) {
      clearNode(button);
      button.disabled = false;
      button.append(createIcon("icon-shield", "button-icon"), document.createTextNode("Check label"));
    }
    renderMedicineReview({ full: true });
  }
}

function renderMedicineIdentity(input, matches, evidence) {
  const items = [];
  const rx = evidence?.evidence?.rxNorm || evidence?.rxNorm || null;
  const label = evidence?.evidence?.openFda || evidence?.openFda || null;

  items.push({
    title: input.name ? "Entered medicine" : "Medicine needed",
    detail: input.name
      ? [
        input.name,
        input.strength ? `strength ${input.strength}` : "strength not entered",
        input.form ? formatMedicineContext(input.form) : "form not entered",
        input.route ? formatMedicineContext(input.route) : "route not entered"
      ].join(" - ")
      : "Enter brand, generic, or active ingredient.",
    level: input.name ? "low" : "medium"
  });

  items.push({
    title: matches.length ? "Local library match" : "Local match",
    detail: matches.length
      ? matches.slice(0, 3).map((medicine) => `${medicine.name} (${medicine.className})`).join("; ")
      : "No local match yet. Confirm spelling and use pharmacist review.",
    level: matches.length ? "low" : "medium"
  });

  if (rx?.found) {
    items.push({
      title: "RxNorm identity",
      detail: `${rx.name || input.name}${rx.rxcui ? ` - RxCUI ${rx.rxcui}` : ""}${rx.tty ? ` - ${rx.tty}` : ""}`,
      level: "low"
    });
  }

  if (label?.found) {
    items.push({
      title: "Label identity",
      detail: [
        label.genericNames?.length ? `Generic: ${label.genericNames.slice(0, 3).join(", ")}` : "",
        label.brandNames?.length ? `Brand: ${label.brandNames.slice(0, 3).join(", ")}` : "",
        label.route?.length ? `Route: ${label.route.slice(0, 2).join(", ")}` : ""
      ].filter(Boolean).join(" - ") || "openFDA label match available.",
      level: "low"
    });
  }

  const missing = [
    ["strength", input.strength],
    ["form", input.form],
    ["route", input.route],
    ["written label source", input.sourceChecked],
    ["allergy history", input.allergy]
  ].filter(([, value]) => !value).map(([labelText]) => labelText);

  items.push({
    title: "Precision gaps",
    detail: missing.length ? `Add ${missing.slice(0, 4).join(", ")} for a cleaner pharmacist check.` : "Core identity and safety fields are ready.",
    level: missing.length ? "medium" : "low"
  });

  renderDashboardList(document.querySelector("#medicineIdentityList"), items);
}

function renderMedicineEvidence(evidence, input, matches) {
  const status = document.querySelector("#medicineEvidenceStatus");
  const list = document.querySelector("#medicineEvidenceList");
  const lookup = evidence?.lookup || evidence;
  const evidencePayload = lookup?.evidence || lookup || {};
  const rx = evidencePayload.rxNorm || {};
  const label = evidencePayload.openFda || {};
  const items = [];

  if (status) {
    status.textContent = lookup
      ? `${lookup.mode || "local cache"} - ${lookup.fetchedOnline ? "fresh online evidence saved locally" : lookup.cacheHit ? "cached local evidence" : "local evidence"}`
      : "Local guide ready. Use Check label when internet is available.";
  }

  if (rx.found) {
    items.push({
      title: "RxNorm normalized name",
      detail: `${rx.name || input.name}${rx.rxcui ? `; RxCUI ${rx.rxcui}` : ""}. Products found: ${rx.products?.length || 0}.`,
      level: "low"
    });
  }

  if (label.found) {
    for (const section of (label.sections || []).slice(0, 4)) {
      items.push({
        title: section.label,
        detail: section.text,
        level: /warning|contra|do not|boxed/i.test(section.label) ? "medium" : "low"
      });
    }
  }

  if (!items.length) {
    items.push({
      title: matches.length ? "Local evidence active" : "Evidence pending",
      detail: matches.length
        ? "Care Nova is using its offline medicine library. Run Check label to add official online identity and label sections to the local cache."
        : "Enter a medicine name to match the local library or run an online label check.",
      level: matches.length ? "low" : "none"
    });
  }

  renderDashboardList(list, items.slice(0, 6));
}

function buildMedicinePharmacistPacket(input, matches, warningItems, interactionItems, readiness, evidence, vault, sideEffects) {
  const profile = input.profile || collectProfile();
  const lookup = evidence?.lookup || evidence || {};
  const evidencePayload = lookup.evidence || lookup || {};
  const rx = evidencePayload.rxNorm || {};
  const label = evidencePayload.openFda || {};
  const medicineNames = splitMedicineNames(input.name).length ? splitMedicineNames(input.name) : splitMedicineNames(profile.medications);
  const relatedVault = vault
    .filter((entry) => medicineNames.some((name) => normalizeMedicineText(entry.name).includes(normalizeMedicineText(name)) || normalizeMedicineText(name).includes(normalizeMedicineText(entry.name))))
    .slice(0, 4);
  const relatedEffects = sideEffects
    .filter((entry) => medicineNames.some((name) => normalizeMedicineText(entry.medicine).includes(normalizeMedicineText(name)) || normalizeMedicineText(name).includes(normalizeMedicineText(entry.medicine))))
    .slice(0, 5);
  const lines = [
    "Care Nova AI - Pharmacist Medicine Packet",
    `Generated: ${new Date().toLocaleString()}`,
    `Patient: ${profile.name || "Patient"}${profile.age ? `, ${profile.age}` : ""}`,
    `Conditions: ${profile.conditions || "not recorded"}`,
    `Allergies: ${input.allergy || profile.allergies || "not recorded"}`,
    "",
    "Medicine Identity",
    `Name: ${input.name || profile.medications || "not entered"}`,
    `Strength/form/route: ${[input.strength, input.form ? formatMedicineContext(input.form) : "", input.route ? formatMedicineContext(input.route) : ""].filter(Boolean).join(" / ") || "not entered"}`,
    `Status/source: ${[formatMedicineContext(input.status || "active"), input.prescriber, input.pharmacy].filter(Boolean).join(" / ") || "not entered"}`,
    `Written label: ${input.dose || "not entered"}; frequency: ${input.frequency ? formatMedicineContext(input.frequency) : "not entered"}; last taken: ${input.lastTaken || "not entered"}`,
    "",
    "Review Request",
    input.concern || "No specific question entered.",
    "",
    "Local Match",
    matches.length ? matches.slice(0, 5).map((medicine) => `- ${medicine.name}: ${medicine.className}; ${medicine.uses}`).join("\n") : "- No exact local medicine match.",
    "",
    "Evidence Check",
    rx.found ? `- RxNorm: ${rx.name || input.name}${rx.rxcui ? ` (RxCUI ${rx.rxcui})` : ""}` : "- RxNorm: not checked or no match.",
    label.found ? `- openFDA label sections: ${(label.sections || []).map((section) => section.label).slice(0, 6).join(", ")}` : "- openFDA label: not checked or no match.",
    "",
    "Safety Context",
    `OTC/supplements: ${input.otc || "not entered"}`,
    `Body context: ${input.bodyContext ? formatMedicineContext(input.bodyContext) : "not entered"}`,
    `Storage: ${input.storage ? formatMedicineContext(input.storage) : "not checked"}`,
    `High-alert flags: ${input.alertChecks.length ? input.alertChecks.map(formatMedicineContext).join(", ") : "none selected"}`,
    "",
    "Watch Items",
    warningItems.length ? warningItems.slice(0, 7).map((item) => `- ${item}`).join("\n") : "- No specific warning item detected from the entry.",
    "",
    "Interaction Matrix",
    interactionItems.length ? interactionItems.slice(0, 8).map((item) => `- ${item.title}: ${item.detail}`).join("\n") : "- Add other medicines, OTC products, and supplements for screening.",
    "",
    "Saved Medicine Context",
    relatedVault.length ? relatedVault.map((entry) => `- ${entry.name}${entry.strength ? ` ${entry.strength}` : ""}: ${formatMedicineContext(entry.status)}; ${entry.frequency ? formatMedicineContext(entry.frequency) : "frequency not entered"}`).join("\n") : "- No saved matching medicine entry yet.",
    "",
    "Side-effect Timeline",
    relatedEffects.length ? relatedEffects.map((entry) => `- ${formatRecordUpdatedAt(entry.at)}: ${entry.medicine}; ${entry.symptom}; ${formatMedicineContext(entry.severity || entry.status)}`).join("\n") : "- No matching side-effect entry saved.",
    "",
    "Questions To Ask",
    buildMedicineQuestionList(input, matches).slice(0, 6).map((question) => `- ${question}`).join("\n"),
    "",
    `Readiness: ${readiness}%`,
    "Boundary: This packet organizes medicine safety questions. It does not prescribe, calculate dosage, change treatment, or replace the prescription label, pharmacist, or clinician."
  ];

  return lines.join("\n");
}

function buildMedicineQuestionList(input, matches) {
  const questions = new Set([
    "Is the medicine name, strength, form, route, and timing correct on my written label?",
    "What should I do if I miss or take this medicine late?",
    "Which side effects are expected, and which warning signs need urgent care?",
    "Do my other medicines, OTC products, supplements, allergies, kidney/liver status, or pregnancy status change safety?"
  ]);

  for (const medicine of matches.slice(0, 4)) {
    for (const question of medicine.questions || []) {
      questions.add(question);
    }
  }

  if (input.sideEffect) {
    questions.add(`Could this symptom be connected to the medicine or an interaction: ${compactText(input.sideEffect, 90)}?`);
  }
  if (input.otc) {
    questions.add(`Can you screen these OTC/supplement products for duplicates or interactions: ${compactText(input.otc, 90)}?`);
  }
  if (/miss|late|skip|forgot/i.test(`${input.lastTaken} ${input.concern}`)) {
    questions.add("For this exact medicine, should I take it now, skip it, or resume the next scheduled time?");
  }

  return Array.from(questions);
}

function renderMedicinePacket(packet) {
  const node = document.querySelector("#medicinePacketText");

  if (node) {
    node.textContent = packet || "Add a medicine name and question to build a pharmacist-ready packet.";
  }
}

async function copyMedicinePacket() {
  const packet = document.querySelector("#medicinePacketText")?.textContent || "";
  const copied = await copyText(packet);
  setMedicinePacketStatus(copied ? "Pharmacist packet copied." : "Copy failed. Packet text is still visible.", copied ? "low" : "medium");
}

function downloadMedicinePacket() {
  const packet = document.querySelector("#medicinePacketText")?.textContent || "";

  if (!packet || /Add a medicine name/.test(packet)) {
    setMedicinePacketStatus("Build a packet before downloading.", "medium");
    return;
  }

  downloadLocalFile(packet, getPatientReportFilename("medicine-pharmacist-packet", "txt"), "text/plain;charset=utf-8");
  setMedicinePacketStatus("Medicine packet downloaded.", "low");
}

function saveMedicinePacketToRecords() {
  const input = collectMedicineInputs();
  const profileMedicines = splitMedicineNames(input.profile.medications);
  const matches = findMedicineMatches(input, profileMedicines);
  const warningItems = buildMedicineWarnings(input, matches);
  const vault = loadMedicineVault();
  const packet = buildMedicinePharmacistPacket(
    input,
    matches,
    warningItems,
    buildMedicineInteractionItems(input, matches, vault),
    scoreMedicineReadiness(input, matches, profileMedicines),
    getCachedMedicineEvidence(input),
    vault,
    loadMedicineSideEffects()
  );

  appendMedicineReviewToPatientRecords(normalizeMedicineVaultEntry({ ...input, name: input.name || input.profile.medications || "Medicine review" }) || { name: input.name || "Medicine review" }, packet, "Pharmacist packet");
  setMedicinePacketStatus("Medicine packet saved to Records.", "low");
}

function appendMedicineReviewToPatientRecords(entry, packet, episode = "Medicine review") {
  try {
    const profile = collectProfile();
    const record = normalizePatientDataRecordForClient({
      id: `record-medicine-${entry.id || Date.now()}`,
      createdAt: entry.createdAt || new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      patientName: profile.name || defaultProfile.name,
      age: profile.age || "",
      type: "medicine",
      date: formatDateForInput(new Date()),
      episode,
      tags: ["medicine", entry.status || "active", entry.reviewType || "review"].filter(Boolean).join(", "),
      source: "Medicine tab",
      documentCategory: "prescription-note",
      documentName: `${entry.name || "Medicine"} safety review`,
      conditions: profile.conditions || "",
      allergies: entry.allergy || profile.allergies || "",
      medicines: [
        entry.name,
        entry.strength,
        entry.dose,
        entry.frequency ? formatMedicineContext(entry.frequency) : ""
      ].filter(Boolean).join("; ") || profile.medications || "",
      vitals: summarizeVitalsForRecord(collectVitals()),
      labs: "",
      notes: packet,
      followUp: "Confirm medicine-specific instructions with a pharmacist or clinician before changing any dose or schedule.",
      versionNote: "Saved from Medicine Specialist Agent."
    });
    const records = [record, ...loadPatientDataRecords().filter((item) => item.id !== record.id)].slice(0, 300);

    record.correctionHistory = buildRecordCorrectionHistory(null, record);
    savePatientDataRecordsLocal(records);
    setSelectedPatientDataRecordId(record.id);
    renderPatientDataRecords();
    persistPatientDataRecords(records, record.id);
  } catch {
    // Medicine vault and packet remain browser-local if Records sync is unavailable.
  }
}

function setMedicinePacketStatus(message, level = "low") {
  const status = document.querySelector("#medicinePacketStatus");

  if (status) {
    status.textContent = message;
    status.dataset.level = level;
  }
}

function splitMedicineNames(value) {
  return String(value || "")
    .split(/[,;\n]+/)
    .map((item) => item.trim())
    .filter(Boolean);
}

function normalizeMedicineText(value) {
  return String(value || "").toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
}

function findMedicineMatches(input, profileMedicines = []) {
  const area = input.disease || "all";
  const directTerms = splitMedicineNames(input.name || (!input.name ? profileMedicines.join(", ") : ""));
  const queryTokens = tokenizeMedicineSearch(`${input.concern} ${input.otc} ${input.sideEffect} ${input.allergy} ${input.bodyContext} ${input.alertChecks.join(" ")}`);
  const scored = medicineKnowledgeBase
    .map((medicine) => ({
      medicine,
      score: scoreMedicineCandidate(medicine, { area, directTerms, queryTokens, hasName: Boolean(input.name) })
    }))
    .filter((entry) => entry.score > 0)
    .sort((a, b) => b.score - a.score || a.medicine.name.localeCompare(b.medicine.name));

  if (scored.length) {
    return scored.slice(0, 6).map((entry) => entry.medicine);
  }

  if (area !== "all") {
    return medicineKnowledgeBase.filter((medicine) => medicine.areas.includes(area)).slice(0, 6);
  }

  return medicineKnowledgeBase.slice(0, 6);
}

function tokenizeMedicineSearch(value) {
  const stopWords = new Set(["about", "after", "before", "with", "from", "this", "that", "medicine", "medication", "tablet", "dose", "doses", "take", "taken", "safe", "review", "question", "questions"]);

  return normalizeMedicineText(value)
    .split(" ")
    .filter((token) => token.length > 3 && !stopWords.has(token));
}

function scoreMedicineCandidate(medicine, { area, directTerms, queryTokens, hasName }) {
  const areaMatch = area === "all" || medicine.areas.includes(area);

  if (!areaMatch) {
    return 0;
  }

  const nameText = normalizeMedicineText(`${medicine.name} ${medicine.generic}`);
  const fullText = normalizeMedicineText([
    medicine.name,
    medicine.generic,
    medicine.className,
    medicine.uses,
    medicine.doseEducation,
    ...(medicine.commonEffects || []),
    ...(medicine.warnings || []),
    ...(medicine.interactions || []),
    ...(medicine.questions || [])
  ].join(" "));
  let score = area === "all" ? 4 : 16;

  for (const term of directTerms) {
    const termText = normalizeMedicineText(term);

    if (termText.length < 3) {
      continue;
    }

    if (nameText === termText) {
      score += 100;
    } else if (new RegExp(`\\b${escapeRegExp(termText)}\\b`, "i").test(nameText)) {
      score += 78;
    } else if (nameText.includes(termText) || termText.includes(nameText)) {
      score += 54;
    } else if (fullText.includes(termText)) {
      score += 28;
    }
  }

  if (!hasName && queryTokens.length) {
    score += Math.min(queryTokens.filter((token) => fullText.includes(token)).length * 6, 30);
  }

  return score;
}

function escapeRegExp(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function scoreMedicineReadiness(input, matches, profileMedicines) {
  let score = 30;

  if (input.name) score += 20;
  if (input.strength) score += 7;
  if (input.form) score += 4;
  if (input.route) score += 4;
  if (input.reviewType && input.reviewType !== "general") score += 8;
  if (input.disease !== "all") score += 8;
  if (input.dose) score += 10;
  if (input.frequency) score += 8;
  if (input.lastTaken) score += 10;
  if (input.status && input.status !== "unknown") score += 4;
  if (input.prescriber) score += 4;
  if (input.pharmacy) score += 3;
  if (input.concern.length >= 12) score += 10;
  if (input.otc) score += 5;
  if (input.allergy) score += 5;
  if (input.sideEffect) score += 6;
  if (input.sideEffectSeverity) score += 3;
  if (input.bodyContext) score += 6;
  if (input.storage) score += 4;
  if (input.sourceChecked) score += 6;
  if (input.alertChecks.length) score += 4;
  if (profileMedicines.length) score += 8;
  if (matches.length) score += 6;

  const text = normalizeMedicineText(`${input.name} ${input.lastTaken} ${input.concern} ${input.sideEffect} ${input.allergy} ${input.alertChecks.join(" ")}`);

  if (/allergy|rash|swelling|breathing|faint|black stool|blood|chest pain|confusion/.test(text) || input.reviewType === "allergy") {
    score -= 10;
  }

  if (/expired|heat-light|fridge-question/.test(input.storage)) {
    score -= 3;
  }

  return Math.max(0, Math.min(96, score));
}

function updateMedicineScore(score, matchCount, warningCount, interactionCount) {
  const scoreValue = document.querySelector("#medicineSafetyScore");
  const scoreLabel = document.querySelector("#medicineSafetyLabel");
  const scoreRing = document.querySelector("#medicineSafetyRing");
  const matchNode = document.querySelector("#medicineMatchCount");
  const warningNode = document.querySelector("#medicineWarningCount");
  const interactionNode = document.querySelector("#medicineInteractionCount");
  const level = score >= 78 ? "low" : score >= 58 ? "medium" : "none";

  if (scoreValue) scoreValue.textContent = `${score}%`;
  if (scoreLabel) {
    scoreLabel.textContent = score >= 78
      ? "Strong medicine context. Review the output and confirm with label or pharmacist."
      : score >= 58
        ? "Good start. Add label timing, last taken, and symptoms for stronger guidance."
        : "Add a medicine name, label instruction, and question to begin.";
  }
  if (scoreRing) {
    scoreRing.dataset.level = level;
    scoreRing.style.setProperty("--medicine-score", `${score}%`);
  }
  if (matchNode) matchNode.textContent = String(matchCount);
  if (warningNode) warningNode.textContent = String(warningCount);
  if (interactionNode) interactionNode.textContent = String(interactionCount);
}

function renderMedicineProfileList(profileMedicines) {
  const list = document.querySelector("#medicineProfileList");

  if (!list) {
    return;
  }

  clearNode(list);

  if (!profileMedicines.length) {
    const item = document.createElement("li");
    item.textContent = "No medicines saved in profile.";
    list.append(item);
    return;
  }

  for (const medicine of profileMedicines) {
    const item = document.createElement("li");
    const match = medicineKnowledgeBase.find((entry) => normalizeMedicineText(`${entry.name} ${entry.generic}`).includes(normalizeMedicineText(medicine)));
    const title = document.createElement("strong");
    const detail = document.createElement("span");

    title.textContent = medicine;
    detail.textContent = match ? `${match.className} - ${match.uses}` : "Not in local library yet; use pharmacist review for exact details.";
    item.append(createIcon("icon-pill", "chip-icon"), title, detail);
    list.append(item);
  }
}

function renderMedicineGuidance(input, matches, readiness) {
  const guidance = document.querySelector("#medicineGuidance");

  if (!guidance) {
    return;
  }

  clearNode(guidance);

  const articles = [
    ...buildMedicineAgentGuidanceArticles(),
    {
      title: matches.length ? `Matched ${matches.length} medicine reference${matches.length === 1 ? "" : "s"}` : "No exact match yet",
      detail: matches.length ? matches.map((medicine) => medicine.name).slice(0, 4).join(", ") : "Type a medicine name or choose a disease area.",
      level: matches.length ? "low" : "none"
    },
    {
      title: "Review focus",
      detail: getMedicineReviewTypeDetail(input.reviewType),
      level: input.reviewType === "allergy" ? "medium" : "low"
    },
    {
      title: "Dose boundary",
      detail: input.dose ? `I can organize the label instruction: ${input.dose}. I cannot prescribe, increase, reduce, or calculate a dose.` : "Add what your prescription or package label says. This app will not create a new dose.",
      level: input.dose ? "low" : "medium"
    },
    {
      title: "Safety context",
      detail: buildMedicineContextSummary(input),
      level: input.otc || input.allergy || input.bodyContext || input.sideEffect || input.alertChecks.length ? "low" : "medium"
    },
    {
      title: readiness >= 78 ? "Ready for pharmacist discussion" : "More context helps",
      detail: readiness >= 78 ? "The medicine, condition area, timing, and question are enough for a focused review." : "Add last taken, frequency, label instruction, symptoms, allergies, supplements, kidney/liver history, or current conditions.",
      level: readiness >= 78 ? "low" : "medium"
    }
  ];

  for (const articleData of articles) {
    const article = document.createElement("article");
    const title = document.createElement("strong");
    const detail = document.createElement("span");

    article.dataset.level = articleData.level;
    title.textContent = articleData.title;
    detail.textContent = articleData.detail;
    article.append(createIcon(articleData.level === "medium" ? "icon-alert" : "icon-pill", "section-icon"), title, detail);
    guidance.append(article);
  }
}

function getLatestMedicineAgentOutput() {
  const result = latestMedicineAgentResult;
  const agent = result?.agentResults?.find((item) => item.id === "PHARMACY_AGENT");

  if (!result || !agent) {
    return null;
  }

  return {
    result,
    agent,
    output: agent.output || {}
  };
}

function buildMedicineAgentGuidanceArticles() {
  const latest = getLatestMedicineAgentOutput();

  if (!latest) {
    return [];
  }

  const { result, output } = latest;
  const priority = output.priority || result.risk?.label || "medicine review";
  const decision = output.decisionProfile || {};
  const firstAction = output.nextSafeSteps?.[0]
    || output.pharmacyActions?.[0]
    || result.finalResponse?.whatToDoNow?.[0]
    || "Review the medicine label and ask a pharmacist before changing any dose.";
  const gaps = Array.isArray(output.reviewGaps) && output.reviewGaps.length
    ? `Missing for higher precision: ${output.reviewGaps.slice(0, 4).join(", ")}.`
    : "Core review details are enough for a focused pharmacy conversation.";
  const highRisk = Array.isArray(decision.highRiskMatches) && decision.highRiskMatches.length
    ? `High-risk category detected: ${decision.highRiskMatches.slice(0, 3).join(", ")}.`
    : "No high-risk medicine family was clearly detected from this entry.";
  const level = /urgent/i.test(priority) || result.risk?.level === "CRITICAL" || result.risk?.level === "HIGH"
    ? "medium"
    : "low";

  return [
    {
      title: `Agent priority: ${formatContextValue(priority)}`,
      detail: output.summary || result.finalResponse?.summary || "Medicine Specialist Agent completed the focused review.",
      level
    },
    {
      title: "Next safe step",
      detail: firstAction,
      level
    },
    {
      title: "Precision check",
      detail: `${highRisk} ${gaps}`,
      level: output.reviewGaps?.length ? "medium" : "low"
    }
  ];
}

function getMedicineReviewTypeDetail(reviewType) {
  const details = {
    general: "Builds a balanced medicine safety review: use, timing, warnings, interactions, and pharmacist questions.",
    "missed-dose": "Focuses on late or missed medicine safety without telling you to double or change the dose.",
    "overdose-or-duplicate": "Focuses on extra-dose, duplicate-dose, accidental use, or overdose wording and escalates to real-world support when needed.",
    "side-effects": "Focuses on expected effects, concerning effects, timing, and what to report.",
    interactions: "Focuses on medicine pairs, supplements, alcohol, food, kidney/liver context, and duplicate ingredients.",
    allergy: "Focuses on allergy warning signs such as swelling, breathing trouble, hives, fainting, and severe rash.",
    "label-use": "Focuses on the written prescription or package label: timing, spacing, duration, storage, and special instructions.",
    pharmacist: "Creates a concise question packet for pharmacist or clinician review."
  };

  return details[reviewType] || details.general;
}

function buildMedicineContextSummary(input) {
  const pieces = [];

  if (input.strength || input.form || input.route) {
    pieces.push(`Identity: ${[input.strength, input.form ? formatMedicineContext(input.form) : "", input.route ? formatMedicineContext(input.route) : ""].filter(Boolean).join(" / ")}`);
  }
  if (input.status || input.frequency) {
    pieces.push(`Plan: ${[input.status ? formatMedicineContext(input.status) : "", input.frequency ? formatMedicineContext(input.frequency) : ""].filter(Boolean).join(" / ")}`);
  }
  if (input.prescriber || input.pharmacy) {
    pieces.push(`Source: ${[compactText(input.prescriber, 44), compactText(input.pharmacy, 44)].filter(Boolean).join(" / ")}`);
  }
  if (input.otc) pieces.push(`OTC/supplements: ${compactText(input.otc, 70)}`);
  if (input.allergy) pieces.push(`Allergy history: ${compactText(input.allergy, 70)}`);
  if (input.bodyContext) pieces.push(`Body context: ${formatMedicineContext(input.bodyContext)}`);
  if (input.sideEffect) pieces.push(`Side-effect diary: ${compactText(input.sideEffect, 70)}${input.sideEffectSeverity ? ` (${formatMedicineContext(input.sideEffectSeverity)})` : ""}`);
  if (input.alertChecks.length) pieces.push(`High-alert flags: ${input.alertChecks.map(formatMedicineContext).join(", ")}`);

  return pieces.length
    ? pieces.join(" | ")
    : "Add OTC products, supplements, allergy history, side-effect timing, and kidney/liver/pregnancy/fall-risk context when relevant.";
}

