function renderMedicineLibrary(matches, input) {
  const list = document.querySelector("#medicineLibraryList");

  if (!list) {
    return;
  }

  clearNode(list);

  if (!matches.length) {
    const empty = document.createElement("article");
    empty.className = "medicine-library-item";
    empty.textContent = input.name ? "No local match found. Use the pharmacist questions below." : "Search or choose a disease area to browse the library.";
    list.append(empty);
    return;
  }

  for (const medicine of matches) {
    const article = document.createElement("article");
    const header = document.createElement("div");
    const title = document.createElement("strong");
    const klass = document.createElement("span");
    const uses = document.createElement("p");
    const tags = document.createElement("div");

    article.className = "medicine-library-item";
    header.className = "medicine-library-header";
    title.textContent = medicine.name;
    klass.textContent = medicine.className;
    uses.textContent = medicine.uses;
    tags.className = "medicine-tag-row";

    for (const area of medicine.areas.slice(0, 3)) {
      const tag = document.createElement("span");
      tag.textContent = formatMedicineArea(area);
      tags.append(tag);
    }

    header.append(createIcon("icon-pill", "section-icon"), title, klass);
    article.append(header, uses, tags);
    list.append(article);
  }
}

function formatMedicineArea(area) {
  const labels = {
    hypertension: "Hypertension",
    heart: "Heart",
    kidney: "Kidney",
    diabetes: "Diabetes",
    cholesterol: "Cholesterol",
    "pain-fever": "Pain / fever",
    asthma: "Asthma",
    infection: "Infection",
    thyroid: "Thyroid",
    "acid-reflux": "Acid reflux",
    allergy: "Allergy",
    "mental-wellness": "Mental wellness",
    lab: "Lab context",
    blood: "Blood health",
    bone: "Bone health"
  };

  return labels[area] || formatContextValue(area);
}

function renderMedicineDiseaseGuide(area) {
  const guide = medicineDiseaseGuides[area] || medicineDiseaseGuides.all;
  renderDashboardList(document.querySelector("#medicineDiseaseGuide"), guide.points.map((point, index) => ({
    title: index === 0 ? guide.title : `Guide ${index + 1}`,
    detail: point,
    level: index === 2 ? "medium" : "low"
  })));
}

function renderMedicineDoseGuidance(input, matches) {
  const firstMatch = matches[0];
  const items = [
    {
      title: "Use the written label",
      detail: input.dose ? `Entered label instruction: ${input.dose}` : "Enter the exact prescription or product-label instruction if available.",
      level: input.dose ? "low" : "medium"
    },
    {
      title: "No dose calculation",
      detail: "This app explains and organizes medicine safety. It does not prescribe, calculate amount, or change consumption.",
      level: "low"
    },
    {
      title: firstMatch ? `${firstMatch.name} use note` : "Use note",
      detail: firstMatch?.doseEducation || "Search a medicine to see use and timing education.",
      level: firstMatch ? "low" : "none"
    }
  ];

  if (/miss|late|skip|forgot/i.test(`${input.lastTaken} ${input.concern}`)) {
    items.push({
      title: "Missed or late medicine",
      detail: "Do not double the next dose from this app. Check the label or call a pharmacist for medicine-specific missed-dose instructions.",
      level: "medium"
    });
  }

  if (input.reviewType === "label-use") {
    items.push({
      title: "Label checklist",
      detail: "Confirm strength, amount, timing, with/without food, spacing from supplements, duration, storage, refills, and what to do if late.",
      level: "low"
    });
  }

  if (input.sourceChecked) {
    items.push({
      title: "Source checked",
      detail: formatMedicineContext(input.sourceChecked),
      level: "low"
    });
  }

  if (input.storage) {
    items.push({
      title: "Storage and expiry",
      detail: input.storage === "stored-correctly"
        ? "Storage looks clear from your entry. Keep following the label instructions."
        : `${formatMedicineContext(input.storage)}. Confirm with a pharmacist before relying on medicine that may be expired, heat damaged, moisture exposed, or cold-chain uncertain.`,
      level: input.storage === "stored-correctly" ? "low" : "medium"
    });
  }

  if (input.reviewType === "missed-dose") {
    items.push({
      title: "Missed-dose question",
      detail: "Ask: should I take it now, skip it, resume next scheduled time, or call because this medicine is high-risk?",
      level: "medium"
    });
  }

  renderDashboardList(document.querySelector("#medicineDoseGuideList"), items);
}

function buildMedicineWarnings(input, matches) {
  const warningSet = new Set();
  const text = normalizeMedicineText(`${input.name} ${input.concern} ${input.lastTaken} ${input.otc} ${input.allergy} ${input.sideEffect} ${input.bodyContext} ${input.alertChecks.join(" ")}`);

  for (const medicine of matches) {
    for (const warning of medicine.warnings || []) {
      warningSet.add(warning);
    }
  }

  if (/rash|allergy|swelling|breathing|hives/.test(text) || input.reviewType === "allergy") {
    warningSet.add("possible allergy symptoms");
  }

  if (/chest pain|faint|confusion|black stool|blood|overdose|double dose/.test(text)) {
    warningSet.add("urgent warning symptom mentioned");
  }

  if (input.reviewType === "interactions") {
    warningSet.add("interaction screening requested");
  }

  if (input.alertChecks.includes("blood-thinner")) warningSet.add("blood thinner or bleeding-risk medicine");
  if (input.alertChecks.includes("insulin")) warningSet.add("low-sugar risk medicine");
  if (input.alertChecks.includes("sedating")) warningSet.add("sleepiness or fall-risk medicine");
  if (input.alertChecks.includes("duplicate")) warningSet.add("duplicate ingredient concern");
  if (input.alertChecks.includes("opioid")) warningSet.add("opioid or strong pain medicine needs sedation and breathing-risk review");
  if (input.alertChecks.includes("narrow-index")) warningSet.add("narrow-index or specialist-monitored medicine needs exact label and lab context");
  if (input.alertChecks.includes("organ-risk")) warningSet.add("kidney, liver, transplant, or pregnancy context can change medicine safety");
  if (input.bodyContext) warningSet.add(`${formatMedicineContext(input.bodyContext).toLowerCase()} can change medicine safety`);
  if (input.storage && input.storage !== "stored-correctly") warningSet.add(`${formatMedicineContext(input.storage).toLowerCase()} needs pharmacy confirmation`);

  return Array.from(warningSet);
}

function buildMedicineInteractionItems(input, matches, vault = loadMedicineVault()) {
  const vaultText = vault.map((entry) => `${entry.name} ${entry.strength} ${entry.status} ${entry.otc}`).join(" ");
  const profileText = normalizeMedicineText(`${input.profile.conditions} ${input.profile.medications} ${input.profile.allergies} ${vaultText} ${input.concern} ${input.otc} ${input.allergy} ${input.sideEffect} ${input.bodyContext} ${input.alertChecks.join(" ")}`);
  const warningItems = buildMedicineWarnings(input, matches).slice(0, 3).map((warning) => ({
    title: "Warning sign",
    detail: warning,
    level: /urgent|breathing|faint|chest|black stool|blood/i.test(warning) ? "high" : "medium"
  }));
  const interactionItems = [];
  const duplicateItems = buildMedicineDuplicateIngredientItems(input, matches, vault);

  interactionItems.push(...duplicateItems);

  for (const medicine of matches.slice(0, 4)) {
    const interactions = (medicine.interactions || []).filter((interaction) => {
      const interactionText = normalizeMedicineText(interaction);
      return interactionText.split(" ").some((token) => token.length > 4 && profileText.includes(token))
        || /blood|kidney|alcohol|allergy|pain|nsaid|supplement|grapefruit|stomach/.test(interactionText);
    }).slice(0, 2);

    for (const interaction of interactions) {
      interactionItems.push({
        title: `${medicine.name} watch`,
        detail: `Review with pharmacist: ${interaction}.`,
        level: /blood thinner|kidney|allergy|breathing|black stool/i.test(interaction) ? "medium" : "low"
      });
    }

    if (medicine.commonEffects?.length) {
      interactionItems.push({
        title: `${medicine.name} common effects`,
        detail: medicine.commonEffects.slice(0, 3).join(", "),
        level: "low"
      });
    }

    if (input.reviewType === "side-effects" && medicine.warnings?.length) {
      interactionItems.push({
        title: `${medicine.name} report urgently`,
        detail: medicine.warnings.slice(0, 3).join(", "),
        level: "medium"
      });
    }
  }

  if (input.reviewType === "interactions") {
    interactionItems.unshift({
      title: "Interaction intake",
      detail: "Include prescriptions, OTC medicines, vitamins, herbs, alcohol, grapefruit, kidney/liver history, allergies, and duplicate active ingredients.",
      level: "medium"
    });
  }

  if (input.otc) {
    interactionItems.unshift({
      title: "OTC and supplement check",
      detail: `Review with pharmacist: ${compactText(input.otc, 120)}.`,
      level: /ibuprofen|naproxen|diclofenac|aspirin|alcohol|herb|supplement|grapefruit|cold|flu/i.test(input.otc) ? "medium" : "low"
    });
  }

  if (vault.length) {
    interactionItems.unshift({
      title: "Saved medicine vault",
      detail: `${vault.length} saved medicine entr${vault.length === 1 ? "y" : "ies"} will be considered. Keep stopped, changed, as-needed, and supplement entries updated.`,
      level: "low"
    });
  }

  if (input.allergy) {
    interactionItems.unshift({
      title: "Allergy record",
      detail: `Confirm this allergy or reaction history: ${compactText(input.allergy, 120)}.`,
      level: /swelling|breath|hives|anaphyl|rash/i.test(input.allergy) ? "medium" : "low"
    });
  }

  if (input.sideEffect) {
    interactionItems.unshift({
      title: "Side-effect diary",
      detail: `Track timing against each dose: ${compactText(input.sideEffect, 120)}.`,
      level: /chest|breath|faint|black stool|blood|confusion|severe/i.test(input.sideEffect) ? "medium" : "low"
    });
  }

  const combined = [...warningItems, ...interactionItems].slice(0, 8);
  return combined.length
    ? combined
    : [
      {
        title: "No interaction clue yet",
        detail: "Add current medicines, supplements, allergies, alcohol use, kidney/liver history, or symptoms.",
        level: "none"
      }
    ];
}

function buildMedicineDuplicateIngredientItems(input, matches, vault = []) {
  const items = [];
  const allText = normalizeMedicineText([
    input.name,
    input.otc,
    input.profile.medications,
    vault.map((entry) => entry.name).join(" ")
  ].join(" "));
  const duplicateFamilies = [
    {
      title: "Acetaminophen / paracetamol duplicate",
      terms: ["acetaminophen", "paracetamol", "cold", "flu"],
      detail: "Cold/flu and pain products can share the same active ingredient. Confirm the active ingredient list before combining products."
    },
    {
      title: "NSAID duplicate",
      terms: ["ibuprofen", "naproxen", "diclofenac", "aspirin", "nsaid"],
      detail: "Multiple NSAID pain relievers can raise stomach, kidney, BP, and bleeding risk. Ask before combining."
    },
    {
      title: "Sedation stack",
      terms: ["cetirizine", "alprazolam", "clonazepam", "gabapentin", "pregabalin", "sleep", "alcohol"],
      detail: "Sedating medicines, alcohol, and nerve-pain medicines can increase sleepiness, falls, confusion, and breathing risk."
    },
    {
      title: "Bleeding-risk stack",
      terms: ["warfarin", "apixaban", "rivaroxaban", "clopidogrel", "aspirin", "ibuprofen", "naproxen"],
      detail: "Blood thinners, antiplatelets, NSAIDs, and some supplements need pharmacist review for bleeding risk."
    },
    {
      title: "Potassium / kidney review",
      terms: ["lisinopril", "losartan", "potassium", "salt substitute", "spironolactone", "kidney"],
      detail: "BP medicines, potassium products, kidney status, dehydration, and NSAIDs can change potassium or kidney safety."
    }
  ];

  for (const family of duplicateFamilies) {
    const hits = family.terms.filter((term) => allText.includes(normalizeMedicineText(term)));
    if (hits.length >= 2 || input.alertChecks.includes("duplicate")) {
      items.push({
        title: family.title,
        detail: family.detail,
        level: /bleeding|sedating|kidney/i.test(family.detail) ? "medium" : "low"
      });
    }
  }

  for (const medicine of matches.slice(0, 4)) {
    const similarSaved = vault.find((entry) => entry.id && normalizeMedicineText(entry.name) !== normalizeMedicineText(medicine.name) && (
      normalizeMedicineText(medicine.generic).split(" ").some((token) => token.length > 4 && normalizeMedicineText(entry.name).includes(token))
      || normalizeMedicineText(entry.name).split(" ").some((token) => token.length > 4 && normalizeMedicineText(medicine.generic).includes(token))
    ));

    if (similarSaved) {
      items.push({
        title: `${medicine.name} duplicate check`,
        detail: `Saved medicine "${similarSaved.name}" may overlap by ingredient or class. Ask a pharmacist to confirm there is no duplicate therapy.`,
        level: "medium"
      });
    }
  }

  return items.slice(0, 4);
}

function renderMedicineSchedule(input, profileMedicines) {
  const frequencyLabels = {
    "once-daily": "Once daily",
    "twice-daily": "Twice daily",
    "three-times": "Three times daily",
    weekly: "Weekly",
    "as-needed": "Only when needed",
    other: "Other label instruction"
  };
  const items = [
    {
      title: "Timing source",
      detail: input.frequency ? `${frequencyLabels[input.frequency] || input.frequency} from the label or your entry.` : "Add how often the label says to take it.",
      level: input.frequency ? "low" : "none"
    },
    {
      title: "Last taken",
      detail: input.lastTaken || "Add when it was last taken to support missed-dose questions.",
      level: /miss|late|skip|forgot/i.test(input.lastTaken) ? "medium" : input.lastTaken ? "low" : "none"
    },
    {
      title: "Profile list",
      detail: profileMedicines.length ? `${profileMedicines.length} medicine${profileMedicines.length === 1 ? "" : "s"} saved in profile.` : "Add medicines in Profile or use this tab search.",
      level: profileMedicines.length ? "low" : "none"
    }
  ];

  renderDashboardList(document.querySelector("#medicineScheduleList"), items);
}

function renderMedicinePassport(input, matches, warningItems, interactionItems, readiness) {
  const passport = [];
  const matchedNames = matches.map((medicine) => medicine.name).slice(0, 4);
  const highAlerts = input.alertChecks.map(formatMedicineContext);
  const safetyWarnings = warningItems.slice(0, 3);
  const sourceParts = [
    input.sourceChecked ? formatMedicineContext(input.sourceChecked) : "No written source selected",
    input.storage ? formatMedicineContext(input.storage) : "Storage not checked"
  ];

  passport.push({
    title: "Medicine identity",
    detail: matchedNames.length
      ? `${matchedNames.join(", ")} matched in the local library.`
      : input.name
        ? `${input.name} entered but not matched exactly. Confirm spelling, brand/generic name, and strength with a pharmacist.`
        : "Add medicine name, brand, generic, or active ingredient.",
    level: matchedNames.length ? "low" : "medium"
  });

  passport.push({
    title: "Label source",
    detail: sourceParts.join("; "),
    level: input.sourceChecked && (!input.storage || input.storage === "stored-correctly") ? "low" : "medium"
  });

  passport.push({
    title: "Safety context",
    detail: buildMedicineContextSummary(input),
    level: input.otc || input.allergy || input.bodyContext || input.sideEffect || highAlerts.length ? "low" : "none"
  });

  passport.push({
    title: "Main watch area",
    detail: safetyWarnings.length
      ? safetyWarnings.join(", ")
      : interactionItems.find((item) => item.level !== "none")?.detail || "No specific warning found yet. Add symptoms, allergies, and other medicines for a stronger review.",
    level: safetyWarnings.length ? "medium" : "none"
  });

  passport.push({
    title: "Review strength",
    detail: readiness >= 78
      ? "Ready for a focused pharmacist or clinician conversation."
      : "Add source, timing, side effects, OTC/supplements, allergy history, and body context to improve precision.",
    level: readiness >= 78 ? "low" : "medium"
  });

  renderDashboardList(document.querySelector("#medicinePassportList"), passport);
}

function renderMedicineQuestions(input, matches) {
  const questions = [];
  const addQuestion = (question) => {
    const clean = compactText(question, 180);
    if (clean && !questions.includes(clean)) {
      questions.push(clean);
    }
  };
  const latest = getLatestMedicineAgentOutput();

  for (const question of latest?.output?.pharmacistQuestions || []) {
    addQuestion(question);
  }

  const focusedQuestions = {
    "missed-dose": [
      "For this exact medicine, should I take the missed dose now or wait until the next scheduled dose?",
      "Is this medicine high-risk if missed, such as insulin, seizure medicine, blood thinner, steroid, heart medicine, or antibiotic?"
    ],
    "side-effects": [
      "Which side effects are common and which mean same-day review?",
      "Could my symptom be from the medicine, the condition, or an interaction?"
    ],
    interactions: [
      "Do any of my medicines, supplements, foods, or alcohol interact with this?",
      "Are there duplicate active ingredients across my prescription and OTC products?"
    ],
    allergy: [
      "Do my symptoms suggest allergy, and which signs require urgent care?",
      "Should this allergy be added to my medical record?"
    ],
    "label-use": [
      "Should I take this with food, away from supplements, or at a specific time?",
      "How long should I use it, and what storage or refill instructions matter?"
    ],
    "overdose-or-duplicate": [
      "What should I do now after an extra, duplicate, or accidental dose?",
      "Which symptoms mean I need urgent care or poison-control support immediately?"
    ],
    pharmacist: [
      "Can you review my full medicine list for interactions and duplicate ingredients?",
      "Can you explain the safest way to use this medicine in plain language?"
    ]
  };

  for (const question of focusedQuestions[input.reviewType] || []) {
    addQuestion(question);
  }

  for (const medicine of matches.slice(0, 3)) {
    for (const question of medicine.questions || []) {
      addQuestion(question);
    }
  }

  if (input.concern) {
    addQuestion(`Can this concern be related to the medicine: ${compactText(input.concern, 90)}?`);
  }

  if (input.otc) {
    addQuestion(`Can you check this OTC/supplement list for interactions or duplicate ingredients: ${compactText(input.otc, 90)}?`);
  }

  if (input.allergy) {
    addQuestion(`Should this allergy or past reaction be added to my medical record: ${compactText(input.allergy, 90)}?`);
  }

  if (input.bodyContext) {
    addQuestion(`Does ${formatMedicineContext(input.bodyContext).toLowerCase()} change how this medicine should be reviewed?`);
  }

  if (input.storage && input.storage !== "stored-correctly") {
    addQuestion(`Is the medicine still safe to use if there is a ${formatMedicineContext(input.storage).toLowerCase()}?`);
  }

  [
    "Is the medicine name, strength, timing, and duration correct on my label?",
    "What should I do if I miss or take a dose late?",
    "Which side effects mean I should stop and call for help?",
    "Do my conditions, allergies, supplements, or other medicines create interaction risks?"
  ].forEach(addQuestion);

  renderDashboardList(document.querySelector("#medicineQuestionsList"), questions.slice(0, 11).map((question, index) => ({
    title: index === 0 && latest ? "Agent question" : index === 0 ? "Start here" : `Question ${index + 1}`,
    detail: question,
    level: index < 2 ? "low" : /urgent|extra|duplicate|overdose|breathing|bleeding|swelling|faint/i.test(question) ? "high" : "medium"
  })));
}

function getLabDomCache() {
  if (!labDomCache) {
    const controls = {
      panelType: document.querySelector("#labPanelType"),
      reportDate: document.querySelector("#labReportDate"),
      fastingStatus: document.querySelector("#labFastingStatus"),
      trendStatus: document.querySelector("#labTrendStatus"),
      clinicalContext: document.querySelector("#labClinicalContext"),
      symptoms: document.querySelector("#labSymptomsInput"),
      medicines: document.querySelector("#labMedicinesInput")
    };

    labDomCache = {
      root: document.querySelector("#labsInterface"),
      reportText: document.querySelector("#labReportText"),
      fileInput: document.querySelector("#labReportFile"),
      dropZone: document.querySelector("#labDropZone"),
      fileStatus: document.querySelector("#labFileStatus"),
      controls,
      contextControls: Object.values(controls).filter(Boolean),
      savedSearch: document.querySelector("#labSavedSearch"),
      analyzeButtons: [
        document.querySelector("#labAnalyzeButton"),
        document.querySelector("#labAnalyzeTop")
      ].filter(Boolean),
      clearButton: document.querySelector("#labClearButton"),
      saveReportButton: document.querySelector("#labSaveReportButton"),
      addValueButton: document.querySelector("#labAddValue"),
      manualMarker: document.querySelector("#labManualMarker"),
      manualValue: document.querySelector("#labManualValue"),
      manualUnit: document.querySelector("#labManualUnit"),
      copyPacketButton: document.querySelector("#labCopyPacketButton"),
      downloadPacketButton: document.querySelector("#labDownloadPacketButton"),
      savedReports: document.querySelector("#labSavedReports"),
      scoreValue: document.querySelector("#labScoreValue"),
      scoreRing: document.querySelector("#labScoreRing"),
      scoreText: document.querySelector("#labScoreText"),
      markerCount: document.querySelector("#labMarkerCount"),
      abnormalCount: document.querySelector("#labAbnormalCount"),
      criticalCount: document.querySelector("#labCriticalCount"),
      confidenceValue: document.querySelector("#labConfidenceValue"),
      summaryList: document.querySelector("#labSummaryList"),
      feedback: document.querySelector("#labFeedback"),
      markerFilter: document.querySelector("#labMarkerFilter"),
      markerTable: document.querySelector("#labMarkerTable"),
      questions: document.querySelector("#labQuestions"),
      missingDetails: document.querySelector("#labMissingDetails"),
      trendList: document.querySelector("#labTrendList"),
      doctorPacket: document.querySelector("#labDoctorPacket"),
      exampleButtons: Array.from(document.querySelectorAll("[data-lab-example]"))
    };
  }

  return labDomCache;
}

function initializeLabReportAgent() {
  const dom = getLabDomCache();
  const labs = dom.root;

  if (!labs || labs.dataset.labReady === "true") {
    return;
  }

  const { reportText, fileInput, dropZone } = dom;
  const savedDraft = loadLocalTextValue(storageKeys.labReportDraft);
  const savedContext = readLabReportContext();
  const saveLabReportDraft = createDeferredTask(() => {
    saveLocalStorageValue(storageKeys.labReportDraft, reportText?.value || "");
  }, 120);
  const refreshLabReportText = createDeferredTask(() => {
    latestLabAgentResult = null;
    renderLabReportAnalysis();
  }, 240);
  const refreshLabReportContext = () => {
    latestLabAgentResult = null;
    invalidateLabAnalysisMemo();
    saveLabReportContext(collectLabContext());
    renderLabReportAnalysis();
  };
  const scheduleLabReportContext = createDeferredTask(refreshLabReportContext, 180);
  const scheduleSavedReportsRender = createDeferredTask(() => renderSavedLabReports(), 120);
  const scheduleMarkerFilterRender = createDeferredTask(() => renderLabReportAnalysis(), 80);

  if (reportText) {
    reportText.value = savedDraft;
    reportText.addEventListener("input", () => {
      latestLabAgentResult = null;
      saveLabReportDraft();
      refreshLabReportText();
    });
  }

  applyLabReportContext(savedContext);

  for (const control of dom.contextControls) {
    control.addEventListener("input", scheduleLabReportContext);
    control.addEventListener("change", () => scheduleLabReportContext.flush());
  }

  dom.savedSearch?.addEventListener("input", scheduleSavedReportsRender);
  dom.savedSearch?.addEventListener("search", () => renderSavedLabReports());
  dom.markerFilter?.addEventListener("input", scheduleMarkerFilterRender);
  dom.markerFilter?.addEventListener("search", () => renderLabReportAnalysis());

  for (const button of dom.analyzeButtons) {
    button.addEventListener("click", () => runLabIntelligenceReview(button));
  }

  dom.clearButton?.addEventListener("click", () => {
    if (reportText) {
      reportText.value = "";
    }

    if (dom.markerFilter) {
      dom.markerFilter.value = "";
    }

    latestLabAgentResult = null;
    invalidateLabAnalysisMemo();
    removeLocalStorageValue(storageKeys.labReportDraft);
    removeLocalStorageValue(storageKeys.labReportContext);
    applyLabReportContext({});
    renderLabReportAnalysis("");
    renderSavedLabReports(undefined, { force: true });
    setLabFileStatus("Text and CSV are read locally. Paste copied PDF or image text for offline review.", "none");
  });

  syncManualLabUnitHint();
  dom.manualMarker?.addEventListener("change", syncManualLabUnitHint);
  dom.manualValue?.addEventListener("keydown", handleManualLabEntryKeydown);
  dom.manualUnit?.addEventListener("keydown", handleManualLabEntryKeydown);
  dom.addValueButton?.addEventListener("click", addManualLabValue);
  dom.saveReportButton?.addEventListener("click", saveCurrentLabReport);
  dom.copyPacketButton?.addEventListener("click", copyCurrentLabDoctorPacket);
  dom.downloadPacketButton?.addEventListener("click", downloadCurrentLabDoctorPacket);
  dom.savedReports?.addEventListener("click", (event) => {
    const openButton = event.target.closest("[data-open-lab-report]");
    const deleteButton = event.target.closest("[data-delete-lab-report]");
    const downloadButton = event.target.closest("[data-download-lab-report]");

    if (openButton) {
      openSavedLabReport(openButton.dataset.openLabReport);
    } else if (deleteButton) {
      deleteSavedLabReport(deleteButton.dataset.deleteLabReport);
    } else if (downloadButton) {
      downloadSavedLabReport(downloadButton.dataset.downloadLabReport);
    }
  });

  for (const button of dom.exampleButtons) {
    button.addEventListener("click", () => {
      const exampleType = button.dataset.labExample || "diabetes";

      if (exampleType === "qa-pack") {
        seedLabQaPack();
        return;
      }

      const sample = labReportExamples[exampleType] || labReportExamples.diabetes;

      if (reportText) {
        reportText.value = sample;
        saveLocalStorageValue(storageKeys.labReportDraft, sample);
      }

      latestLabAgentResult = null;
      invalidateLabAnalysisMemo();
      applyLabExampleContext(exampleType);
      setLabFileStatus("Sample report loaded.", "low");
      renderLabReportAnalysis(sample);
    });
  }

  if (fileInput) {
    fileInput.addEventListener("change", () => {
      const [file] = fileInput.files || [];
      handleLabReportFile(file);
    });
  }

  if (dropZone) {
    for (const eventName of ["dragenter", "dragover"]) {
      dropZone.addEventListener(eventName, (event) => {
        event.preventDefault();
        dropZone.classList.add("is-dragging");
      });
    }

    for (const eventName of ["dragleave", "drop"]) {
      dropZone.addEventListener(eventName, () => {
        dropZone.classList.remove("is-dragging");
      });
    }

    dropZone.addEventListener("drop", (event) => {
      event.preventDefault();
      const [file] = event.dataTransfer?.files || [];
      handleLabReportFile(file);
    });
  }

  labs.dataset.labReady = "true";
  renderLabReportAnalysis(savedDraft);
  renderSavedLabReports();
}

function readLabReportContext() {
  try {
    return JSON.parse(localStorage.getItem(storageKeys.labReportContext) || "{}") || {};
  } catch {
    return {};
  }
}

function applyLabReportContext(context = {}) {
  const { controls = {} } = getLabDomCache();
  const values = {
    panelType: context.panelType || "general",
    reportDate: context.reportDate || "",
    fastingStatus: context.fastingStatus || "unknown",
    trendStatus: context.trendStatus || "unknown",
    clinicalContext: context.clinicalContext || "",
    symptoms: context.symptoms || "",
    medicines: context.medicines || ""
  };

  for (const [key, value] of Object.entries(values)) {
    const control = controls[key];

    if (control) {
      control.value = value;
    }
  }
}

function collectLabContext() {
  const { controls = {} } = getLabDomCache();

  return {
    panelType: controls.panelType?.value || "general",
    reportDate: controls.reportDate?.value || "",
    fastingStatus: controls.fastingStatus?.value || "unknown",
    trendStatus: controls.trendStatus?.value || "unknown",
    clinicalContext: controls.clinicalContext?.value || "",
    symptoms: controls.symptoms?.value.trim() || "",
    medicines: controls.medicines?.value.trim() || ""
  };
}

function saveLabReportContext(context) {
  saveJson(storageKeys.labReportContext, context || collectLabContext());
}

function applyLabExampleContext(exampleType) {
  const exampleContexts = {
    diabetes: { panelType: "diabetes", reportDate: "2026-06-20", fastingStatus: "fasting", trendStatus: "worsening", clinicalContext: "diabetes", symptoms: "Diabetes follow-up", medicines: "Metformin" },
    lipids: { panelType: "lipids", reportDate: "2026-06-20", fastingStatus: "fasting", trendStatus: "unknown", clinicalContext: "heart-risk", symptoms: "Heart-risk review", medicines: "No statin listed" },
    cbc: { panelType: "cbc", reportDate: "2026-06-20", fastingStatus: "unknown", trendStatus: "first", clinicalContext: "anemia", symptoms: "Tiredness", medicines: "" },
    kidney: { panelType: "kidney", reportDate: "2026-06-20", fastingStatus: "unknown", trendStatus: "worsening", clinicalContext: "kidney", symptoms: "BP and diabetes follow-up", medicines: "BP medicine" }
  };
  const context = exampleContexts[exampleType] || {};

  applyLabReportContext(context);
  saveLabReportContext(collectLabContext());
}

function createLabQaSeedEntry(sample, priorReports = []) {
  const profile = collectProfile();
  const reportDate = String(sample.reportDate || sample.context?.reportDate || formatDateForInput(new Date())).trim();
  const panel = String(sample.panel || sample.context?.panelType || "general").trim() || "general";
  const context = {
    panelType: panel,
    reportDate,
    fastingStatus: sample.context?.fastingStatus || "unknown",
    trendStatus: sample.context?.trendStatus || "unknown",
    clinicalContext: sample.context?.clinicalContext || "",
    symptoms: sample.context?.symptoms || "",
    medicines: sample.context?.medicines || ""
  };
  const createdAt = new Date(`${reportDate}T${sample.createdTime || "09:00:00"}Z`);
  const timestamp = Number.isNaN(createdAt.getTime()) ? new Date().toISOString() : createdAt.toISOString();
  const analysis = analyzeLabReportText(sample.text, context, priorReports);

  return normalizeLabVaultEntry({
    id: sample.id || `qa-lab-${Date.now()}`,
    createdAt: timestamp,
    updatedAt: timestamp,
    patientName: profile.name || defaultProfile.name,
    reportDate,
    panel,
    title: sample.title || `QA sample - ${getLabPanelLabel(panel)} - ${reportDate}`,
    text: sample.text,
    context,
    markers: analysis.markers,
    readiness: analysis.readiness,
    confidence: analysis.confidence,
    abnormalCount: analysis.abnormalCount,
    urgentCount: analysis.urgentCount,
    doctorPacket: analysis.doctorPacket
  });
}

function seedLabQaPack() {
  const dom = getLabDomCache();
  const existingReports = loadLabReportsVault().filter((report) => !labQaSeedSampleIds.has(report.id));
  const analysisBaseline = existingReports
    .slice()
    .sort((first, second) => new Date(first.createdAt).getTime() - new Date(second.createdAt).getTime());
  const seededEntries = [];

  for (const sample of labQaSeedSamples) {
    const entry = createLabQaSeedEntry(sample, [...analysisBaseline, ...seededEntries]);
    seededEntries.push(entry);
  }

  const nextReports = [...seededEntries.slice().reverse(), ...existingReports].slice(0, 80);
  const latestEntry = seededEntries[seededEntries.length - 1];

  saveLabReportsVault(nextReports);
  appendLabReportsToPatientRecords(seededEntries);

  if (dom.savedSearch) {
    dom.savedSearch.value = "";
  }

  if (dom.markerFilter) {
    dom.markerFilter.value = "";
  }

  if (dom.reportText && latestEntry) {
    dom.reportText.value = latestEntry.text;
    saveLocalStorageValue(storageKeys.labReportDraft, latestEntry.text);
  }

  latestLabAgentResult = null;
  invalidateLabAnalysisMemo();
  applyLabReportContext(latestEntry?.context || {});
  saveLabReportContext(latestEntry?.context || collectLabContext());
  setLabFileStatus(`QA sample pack seeded for ${collectProfile().name || "this patient"}. ${seededEntries.length} saved reports are ready below.`, "low");
  renderSavedLabReports(nextReports, { force: true });
  renderLabReportAnalysis(latestEntry?.text || "");
}

function handleLabReportFile(file) {
  const { reportText } = getLabDomCache();

  if (!file) {
    return;
  }

  const fileName = file.name || "report";
  const extension = fileName.split(".").pop()?.toLowerCase() || "";
  const canReadText = file.type.startsWith("text/") || ["txt", "csv", "json"].includes(extension);

  if (file.size > 1_000_000) {
    setLabFileStatus("File is large. Paste the key report text for a faster offline review.", "medium");
    return;
  }

  if (!canReadText) {
    setLabFileStatus(`${fileName} selected. For PDF or image reports, paste copied text into the box.`, "medium");
    return;
  }

  const reader = new FileReader();

  reader.addEventListener("load", () => {
    const text = String(reader.result || "").trim();

    if (reportText) {
      reportText.value = text;
      latestLabAgentResult = null;
      invalidateLabAnalysisMemo();
      saveLocalStorageValue(storageKeys.labReportDraft, text);
    }

    setLabFileStatus(`${fileName} loaded locally.`, "low");
    renderLabReportAnalysis(text);
  });

  reader.addEventListener("error", () => {
    setLabFileStatus("Could not read this file. Paste the report text instead.", "medium");
  });

  reader.readAsText(file);
}

function setLabFileStatus(message, level = "none") {
  const status = getLabDomCache().fileStatus;

  if (!status) {
    return;
  }

  status.textContent = message;
  status.dataset.level = level;
}

function getManualLabCatalogItem(marker = getLabDomCache().manualMarker?.value || "") {
  return labMarkerCatalog.find((item) => item.label.toLowerCase() === String(marker).toLowerCase()) || null;
}

function syncManualLabUnitHint() {
  const dom = getLabDomCache();
  const catalogItem = getManualLabCatalogItem(dom.manualMarker?.value);

  if (!dom.manualUnit) {
    return;
  }

  dom.manualUnit.placeholder = catalogItem?.unit ? `Default: ${catalogItem.unit}` : "mg/dL, %, g/dL";
  dom.manualUnit.setAttribute("aria-label", catalogItem?.unit ? `Unit. Default ${catalogItem.unit}` : "Unit");
}

function handleManualLabEntryKeydown(event) {
  if (event.key !== "Enter" || event.shiftKey || event.altKey || event.ctrlKey || event.metaKey) {
    return;
  }

  event.preventDefault();
  addManualLabValue();
}

function addManualLabValue() {
  const dom = getLabDomCache();
  const marker = dom.manualMarker?.value || "HbA1c";
  const value = dom.manualValue?.value.trim() || "";
  const unitInput = dom.manualUnit;
  const reportText = dom.reportText;

  if (!value || !reportText) {
    setLabFileStatus("Add a marker value first.", "medium");
    return;
  }

  const catalogItem = getManualLabCatalogItem(marker);
  const unit = unitInput?.value.trim() || catalogItem?.unit || "";
  const line = `${marker} ${value}${unit ? ` ${unit}` : ""}`;
  const nextText = `${reportText.value.trim() ? `${reportText.value.trim()}\n` : ""}${line}`;

  reportText.value = nextText;
  latestLabAgentResult = null;
  invalidateLabAnalysisMemo();
  saveLocalStorageValue(storageKeys.labReportDraft, nextText);

  if (unitInput) {
    unitInput.value = "";
  }

  const valueInput = dom.manualValue;

  if (valueInput) {
    valueInput.value = "";
  }

  setLabFileStatus(`${marker} added.`, "low");
  renderLabReportAnalysis(nextText);
}

function getLabVaultSignature(reports = []) {
  return (Array.isArray(reports) ? reports : [])
    .map((report) => [
      report.id || "",
      report.updatedAt || report.createdAt || "",
      report.reportDate || "",
      report.panel || "",
      String(report.text || "").length
    ].join(":"))
    .join("|");
}

function invalidateLabAnalysisMemo() {
  labAnalysisMemo.signature = "";
  labAnalysisMemo.analysis = null;
}

function getMemoizedLabAnalysis(text, context = collectLabContext(), reports = loadLabReportsVault()) {
  const signature = JSON.stringify({
    text: String(text || ""),
    context: context || {},
    reports: getLabVaultSignature(reports)
  });

  if (labAnalysisMemo.signature !== signature) {
    labAnalysisMemo.signature = signature;
    labAnalysisMemo.analysis = analyzeLabReportText(text, context, reports);
  }

  return labAnalysisMemo.analysis;
}

function getComparableLabReportsForAnalysis(text = "", reports = loadLabReportsVault()) {
  const normalizedText = normalizeLabSearchText(text);

  if (!normalizedText) {
    return Array.isArray(reports) ? reports : [];
  }

  let removedCurrentMatch = false;

  return (Array.isArray(reports) ? reports : []).filter((report) => {
    if (!removedCurrentMatch && normalizeLabSearchText(report.text) === normalizedText) {
      removedCurrentMatch = true;
      return false;
    }

    return true;
  });
}

function renderLabReportAnalysis(forcedText) {
  const reportText = getLabDomCache().reportText;
  const text = typeof forcedText === "string" ? forcedText : reportText?.value || "";
  const context = collectLabContext();
  const reports = getComparableLabReportsForAnalysis(text, loadLabReportsVault());
  const analysis = getMemoizedLabAnalysis(text, context, reports);

  renderLabScore(analysis);
  renderLabFeedback(analysis);
  renderLabMarkerTable(analysis.markers);
  renderLabQuestions(mergeLabQuestionsWithAgent(analysis.questions));
  renderLabMissingDetails(analysis.missing);
  renderLabSummaryList(analysis.summary);
  renderLabTrendList(analysis.trends);
  renderLabDoctorPacket(analysis.doctorPacket);

  return analysis;
}

function mergeLabQuestionsWithAgent(localQuestions = []) {
  const latest = getLatestLabAgentOutput();
  const questions = [];

  for (const question of [...(latest?.output?.doctorQuestions || []), ...localQuestions]) {
    const clean = compactText(question, 190);
    if (clean && !questions.includes(clean)) {
      questions.push(clean);
    }
  }

  return questions;
}

async function runLabIntelligenceReview(button) {
  if (labRunInFlight) {
    setLabFileStatus("Lab Intelligence Agent is already analyzing this report.", "medium");
    return;
  }

  const reportText = getLabDomCache().reportText;
  const text = reportText?.value.trim() || "";
  const context = collectLabContext();
  const analysis = renderLabReportAnalysis(text);

  if (!text || !analysis.markers.length) {
    setLabFileStatus("Add report text with marker names and values before running the Labs Agent.", "medium");
    reportText?.focus();
    return;
  }

  activateWorkspaceSubtab("labs", "findings", true);
  setLabRunState(true, button);
  setLabFileStatus("Lab Intelligence Agent is checking values, trends, priority, and clinician questions.", "medium");

  try {
    const result = await runAnalysis(buildLabAgentMessage(text, context, analysis), {
      interfaceName: "labs",
      singleAgentMode: true,
      preferredAgent: "LABS_AGENT",
      answerMode: getActiveAnswerMode("labs"),
      context: {
        ...workspaceSearchConfig.labs.context,
        careGoal: "lab-review",
        labReportContext: context,
        severity: analysis.priority?.level === "critical" ? "8" : analysis.priority?.level === "high" ? "6" : "4",
        redFlags: analysis.priority?.level === "critical" || context.clinicalContext === "urgent-symptoms" ? ["lab-critical"] : []
      }
    });

    if (result) {
      latestLabAgentResult = result;
      setLabFileStatus("Lab Intelligence Agent completed. Review priority, markers, packet, and questions below.", "low");
      renderLabReportAnalysis(text);
    } else {
      setLabFileStatus("Local lab review completed. Server agent output is unavailable, so review the local priority, markers, packet, and questions below.", "low");
      renderLabReportAnalysis(text);
    }
  } catch (error) {
    setLabFileStatus("Local lab review completed. Server agent output could not be reached; use the local findings below.", "medium");
    renderLabReportAnalysis(text);
  } finally {
    setLabRunState(false, button);
  }
}

function buildLabAgentMessage(text, context = {}, analysis = {}) {
  const markers = analysis.markers || [];
  const abnormal = markers.filter((marker) => marker.level !== "low");
  const urgent = markers.filter((marker) => marker.level === "critical");

  return [
    `Lab report review request: ${getLabPanelLabel(analysis.panel || context.panelType || "general")}.`,
    `Report context: date ${context.reportDate || "not provided"}; fasting ${context.fastingStatus || "unknown"}; trend ${context.trendStatus || "unknown"}; clinical context ${formatLabContextLabel(context.clinicalContext) || "none"}.`,
    `Symptoms or reason: ${context.symptoms || "not provided"}.`,
    `Medicines or supplements: ${context.medicines || "not provided"}.`,
    `Extracted markers: ${markers.length ? markers.map((marker) => `${marker.label} ${marker.value}${marker.unit ? ` ${marker.unit}` : ""} (${marker.status}; range ${marker.guideRange})`).join("; ") : "none"}.`,
    `Needs review: ${abnormal.length ? abnormal.map((marker) => marker.label).join(", ") : "none from local broad guide"}.`,
    `Same-day care markers: ${urgent.length ? urgent.map((marker) => marker.label).join(", ") : "none detected"}.`,
    `Priority: ${analysis.priority?.label || "clinician-review preparation"}.`,
    "",
    text
  ].join("\n");
}

function setLabRunState(isLoading, activeButton) {
  const dom = getLabDomCache();
  labRunInFlight = Boolean(isLoading);

  dom.root?.classList.toggle("is-running", Boolean(isLoading));
  dom.root?.setAttribute("aria-busy", String(Boolean(isLoading)));

  for (const button of dom.analyzeButtons || []) {
    const isActiveButton = activeButton ? button === activeButton : false;
    button.disabled = Boolean(isLoading);
    button.dataset.runTrigger = isActiveButton && isLoading ? "true" : "false";
    setLabRunButtonContent(button, Boolean(isLoading));
  }
}

function setLabRunButtonContent(button, isLoading) {
  if (!button) {
    return;
  }

  clearNode(button);
  button.append(createIcon(isLoading ? "icon-gauge" : "icon-send", "button-icon"), document.createTextNode(isLoading ? "Analyzing" : button.id === "labAnalyzeTop" ? "Analyze Report" : "Analyze Safely"));
}

function analyzeLabReportText(text, context = {}, savedReports = loadLabReportsVault()) {
  const sourceText = String(text || "").trim();
  const markers = sortLabMarkersByPriority(extractLabMarkers(sourceText));
  const urgentCount = markers.filter((marker) => marker.level === "critical").length;
  const abnormalCount = markers.filter((marker) => marker.level === "high" || marker.level === "medium" || marker.level === "critical").length;
  const panel = inferLabPanelType(markers, sourceText, context.panelType);
  const confidence = calculateLabConfidence(sourceText, markers, context);
  const trends = buildLabTrendInsights(markers, savedReports);
  const priority = buildLabReviewPriority(markers, sourceText, context, panel);
  const patternInsights = buildLabPatternInsights(markers, context, panel);

  return {
    text: sourceText,
    context,
    panel,
    markers,
    urgentCount,
    abnormalCount,
    confidence,
    readiness: calculateLabReadiness(sourceText, markers, context),
    priority,
    patternInsights,
    summary: buildLabSummary(markers, sourceText, context, panel, confidence, priority),
    feedback: buildLabFeedback(markers, sourceText, context, panel, priority, patternInsights),
    questions: buildLabQuestions(markers, context, panel, priority, patternInsights),
    missing: buildLabMissingDetails(sourceText, markers, context),
    trends,
    doctorPacket: buildLabDoctorPacket({
      text: sourceText,
      context,
      panel,
      markers,
      urgentCount,
      abnormalCount,
      confidence,
      priority,
      patternInsights,
      trends,
      questions: buildLabQuestions(markers, context, panel, priority, patternInsights)
    })
  };
}

function sortLabMarkersByPriority(markers = []) {
  const levelRank = { critical: 4, high: 3, medium: 2, low: 1, none: 0 };
  return [...markers].sort((first, second) => (
    (levelRank[second.level] || 0) - (levelRank[first.level] || 0)
    || String(first.label).localeCompare(String(second.label))
  ));
}

const labPanelLabels = {
  general: "General lab review",
  diabetes: "Diabetes and sugar review",
  lipids: "Lipid and heart-risk review",
  cbc: "CBC and anemia review",
  kidney: "Kidney and urine review",
  thyroid: "Thyroid review",
  liver: "Liver enzyme review",
  electrolytes: "Electrolyte review",
  vitamins: "Vitamin and nutrition review"
};

const labClinicalContextLabels = {
  diabetes: "Diabetes / sugar follow-up",
  kidney: "Kidney or urine concern",
  "heart-risk": "Heart-risk prevention",
  infection: "Fever or infection concern",
  anemia: "Tiredness / anemia concern",
  pregnancy: "Pregnancy / fertility context",
  procedure: "Before surgery, scan, or procedure",
  "urgent-symptoms": "Urgent symptoms present"
};

function inferLabPanelType(markers, text, selectedPanel = "general") {
  if (selectedPanel && selectedPanel !== "general") {
    return selectedPanel;
  }

  const ids = new Set(markers.map((marker) => marker.id));
  const source = normalizeLabSearchText(text);

  if (ids.has("hba1c") || ids.has("fasting-glucose") || ids.has("random-glucose") || source.includes("diabetes")) return "diabetes";
  if (ids.has("ldl") || ids.has("hdl") || ids.has("triglycerides") || ids.has("non-hdl")) return "lipids";
  if (ids.has("hemoglobin") || ids.has("hematocrit") || ids.has("rbc") || ids.has("wbc") || ids.has("neutrophils") || ids.has("lymphocytes") || ids.has("platelets") || ids.has("mcv") || ids.has("ferritin")) return "cbc";
  if (ids.has("creatinine") || ids.has("bun") || ids.has("egfr") || ids.has("uacr")) return "kidney";
  if (ids.has("tsh") || ids.has("free-t4")) return "thyroid";
  if (ids.has("alt") || ids.has("ast") || ids.has("ggt") || ids.has("bilirubin") || ids.has("alkaline-phosphatase") || ids.has("albumin")) return "liver";
  if (ids.has("sodium") || ids.has("potassium") || ids.has("chloride") || ids.has("calcium") || ids.has("magnesium")) return "electrolytes";
  if (ids.has("vitamin-d") || ids.has("vitamin-b12")) return "vitamins";

  return "general";
}

function normalizeLabSearchText(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/[^a-z0-9+%./\s-]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function getLabPanelLabel(panel) {
  return labPanelLabels[panel] || labPanelLabels.general;
}

function formatLabContextLabel(value) {
  return labClinicalContextLabels[value] || "";
}

function buildLabReviewPriority(markers = [], text = "", context = {}, panel = "general") {
  const urgent = markers.filter((marker) => marker.level === "critical");
  const high = markers.filter((marker) => marker.level === "high");
  const medium = markers.filter((marker) => marker.level === "medium");
  const source = normalizeLabSearchText(`${text} ${context.symptoms || ""} ${context.clinicalContext || ""}`);
  const urgentSymptom = /(chest pain|shortness of breath|trouble breathing|faint|confusion|seizure|black stool|vomit blood|yellow eyes|severe weakness|one-sided|one sided)/.test(source)
    || context.clinicalContext === "urgent-symptoms";

  if (urgent.length || urgentSymptom) {
    return {
      label: "Prompt clinical review",
      level: "critical",
      reason: urgent.length
        ? `${urgent.slice(0, 3).map((marker) => marker.label).join(", ")} reached an urgent review band.`
        : "Urgent symptom context was entered with lab review.",
      next: "Use real medical care promptly for urgent symptoms, critical flags, or rapidly worsening results."
    };
  }

  if (high.length >= 2 || (high.length && ["kidney", "cbc", "liver", "electrolytes"].includes(panel))) {
    return {
      label: "Focused clinician review",
      level: "high",
      reason: `${high.slice(0, 4).map((marker) => marker.label).join(", ")} need focused review with symptoms, medicines, and trend.`,
      next: "Share the doctor packet and ask what changed, what to repeat, and whether medicine review is needed."
    };
  }

  if (high.length || medium.length) {
    return {
      label: "Routine follow-up review",
      level: "medium",
      reason: `${[...high, ...medium].slice(0, 4).map((marker) => marker.label).join(", ")} should be reviewed in context.`,
      next: "Add prior results and ask your clinician what target or repeat timing applies to you."
    };
  }

  if (markers.length) {
    return {
      label: "Track and compare",
      level: "low",
      reason: "No extracted marker crossed the broad local review bands.",
      next: "Save this report to compare future trends and follow the lab or clinician reference range."
    };
  }

  return {
    label: "Needs report values",
    level: "none",
    reason: "No recognizable marker values were found yet.",
    next: "Add lab names, values, units, and reference ranges."
  };
}

function buildLabPatternInsights(markers = [], context = {}, panel = "general") {
  const ids = new Set(markers.map((marker) => marker.id));
  const abnormalIds = new Set(markers.filter((marker) => marker.level !== "low").map((marker) => marker.id));
  const insights = [];

  if (ids.has("hba1c") || ids.has("fasting-glucose") || ids.has("random-glucose")) {
    insights.push({
      title: "Sugar pattern",
      detail: abnormalIds.has("hba1c") || abnormalIds.has("fasting-glucose") || abnormalIds.has("random-glucose")
        ? "Review meal timing, home glucose readings, medicines, kidney function, and follow-up target."
        : "Sugar markers look trackable from the entered values; trend and personal target still matter.",
      level: abnormalIds.has("hba1c") || abnormalIds.has("fasting-glucose") || abnormalIds.has("random-glucose") ? "medium" : "low"
    });
  }

  if (ids.has("ldl") || ids.has("hdl") || ids.has("triglycerides") || ids.has("non-hdl")) {
    insights.push({
      title: "Heart-risk pattern",
      detail: "Lipid meaning depends on age, BP, diabetes, smoking, family history, medicines, and personal LDL/non-HDL target.",
      level: ["ldl", "triglycerides", "non-hdl", "hdl"].some((id) => abnormalIds.has(id)) ? "medium" : "low"
    });
  }

  if (ids.has("hemoglobin") || ids.has("mcv") || ids.has("ferritin") || ids.has("vitamin-b12")) {
    insights.push({
      title: "Blood-count pattern",
      detail: "Review anemia, iron, B12, bleeding, periods, diet, kidney disease, inflammation, and fatigue or breathlessness symptoms.",
      level: ["hemoglobin", "mcv", "ferritin", "vitamin-b12"].some((id) => abnormalIds.has(id)) ? "medium" : "low"
    });
  }

  if (ids.has("creatinine") || ids.has("egfr") || ids.has("uacr") || ids.has("potassium")) {
    insights.push({
      title: "Kidney pattern",
      detail: "Review eGFR trend, urine albumin, potassium, hydration, BP, diabetes, NSAID pain relievers, and kidney-affecting medicines.",
      level: ["creatinine", "egfr", "uacr", "potassium"].some((id) => abnormalIds.has(id)) ? "high" : "low"
    });
  }

  if (ids.has("alt") || ids.has("ast") || ids.has("bilirubin") || ids.has("alkaline-phosphatase") || ids.has("ggt")) {
    insights.push({
      title: "Liver pattern",
      detail: "Review alcohol, medicines, supplements, fatty liver risk, infection symptoms, jaundice, abdominal pain, and repeat testing.",
      level: ["alt", "ast", "bilirubin", "alkaline-phosphatase", "ggt"].some((id) => abnormalIds.has(id)) ? "medium" : "low"
    });
  }

  if (ids.has("tsh") || ids.has("free-t4")) {
    insights.push({
      title: "Thyroid pattern",
      detail: "Interpret TSH with free T4, symptoms, pregnancy context, timing of thyroid medicine, supplements, and repeat plan.",
      level: ["tsh", "free-t4"].some((id) => abnormalIds.has(id)) ? "medium" : "low"
    });
  }

  if (ids.has("crp") || ids.has("esr") || ids.has("wbc") || context.clinicalContext === "infection") {
    insights.push({
      title: "Inflammation pattern",
      detail: "Inflammation markers are nonspecific. Fever, duration, infection signs, autoimmune symptoms, medicines, and trend guide next questions.",
      level: ["crp", "esr", "wbc", "neutrophils"].some((id) => abnormalIds.has(id)) ? "medium" : "low"
    });
  }

  if (!insights.length) {
    insights.push({
      title: getLabPanelLabel(panel),
      detail: "Add more markers, symptoms, medicines, and previous results to build a pattern-level review.",
      level: "none"
    });
  }

  return insights.slice(0, 5);
}

function calculateLabConfidence(text, markers, context = {}) {
  if (!text || !markers.length) {
    return 0;
  }

  let score = 36 + Math.min(markers.length * 7, 32);

  if (context.panelType && context.panelType !== "general") score += 7;
  if (context.reportDate || hasLabDate(text)) score += 7;
  if (hasLabReferenceContext(text, markers)) score += 7;
  if (context.trendStatus && context.trendStatus !== "unknown") score += 5;
  if (/previous|prior|last result|trend|repeat/i.test(text)) score += 5;
  if (context.fastingStatus && context.fastingStatus !== "unknown") score += 4;
  if (context.symptoms) score += 4;
  if (context.medicines) score += 4;

  const likelyUnits = markers.filter((marker) => marker.unit).length;
  if (likelyUnits >= Math.max(1, Math.floor(markers.length * 0.8))) score += 4;

  return Math.max(0, Math.min(98, score));
}

function buildLabSummary(markers, text, context = {}, panel = "general", confidence = 0, priority = null) {
  if (!text) {
    return [
      "Ready for report text, file upload, or manual values.",
      "Choose the report type to focus the review.",
      "Add date, fasting status, symptoms, and previous trend for better precision."
    ];
  }

  const abnormal = markers.filter((marker) => marker.level !== "low");
  const panelLabel = getLabPanelLabel(panel);
  const summary = [
    `${panelLabel}: ${markers.length} marker${markers.length === 1 ? "" : "s"} detected.`,
    priority ? `${priority.label}: ${priority.reason}` : "",
    confidence >= 80 ? "High context confidence for a doctor-ready note." : "Context can be improved before sharing with a clinician."
  ].filter(Boolean);

  if (abnormal.length) {
    summary.push(`Needs review: ${abnormal.slice(0, 4).map((marker) => marker.label).join(", ")}.`);
  } else if (markers.length) {
    summary.push("No extracted marker crossed the built-in broad review bands.");
  }

  if (context.trendStatus && !["unknown", "first"].includes(context.trendStatus)) {
    summary.push(`Trend provided: ${context.trendStatus}.`);
  }

  if (context.symptoms) {
    summary.push(`Reason noted: ${compactText(context.symptoms, 70)}.`);
  }

  if (context.clinicalContext) {
    summary.push(`Clinical context: ${formatLabContextLabel(context.clinicalContext)}.`);
  }

  return summary.slice(0, 5);
}

function extractLabMarkers(text) {
  if (!text) {
    return [];
  }

  const markers = [];
  const used = new Set();

  for (const item of labMarkerCatalog) {
    const match = findLabMarkerMatch(text, item);

    if (!match || used.has(item.id)) {
      continue;
    }

    used.add(item.id);
    markers.push(evaluateLabMarker(item, match.value, match.unit, match.referenceRange));
  }

  return markers;
}

function findLabMarkerMatch(text, item) {
  const lines = String(text || "")
    .split(/\r?\n+/)
    .map((line) => line.trim())
    .filter(Boolean);

  for (const alias of item.aliases) {
    const aliasPattern = escapeLabRegex(alias).replace(/\\s+/g, "\\s+");
    const pattern = new RegExp(`(?:^|[^a-z0-9])${aliasPattern}(?:\\b|(?=[^a-z0-9]))[^\\d<>]{0,45}([<>]?\\s*\\d+(?:\\.\\d+)?)\\s*([%a-zA-Z\\u00b5\\u03bc/\\.\\^0-9+-]+)?`, "i");

    for (const line of lines) {
      if (shouldSkipLabAliasLine(item, line)) {
        continue;
      }

      const match = pattern.exec(line);

      if (!match) {
        continue;
      }

      const value = Number.parseFloat(String(match[1] || "").replace(/[<>\s]/g, ""));

      if (!Number.isFinite(value)) {
        continue;
      }

      return {
        value,
        unit: normalizeLabUnit(match[2]) || item.unit,
        referenceRange: extractLabReferenceRange(line, item)
      };
    }

    const match = pattern.exec(text);
    const matchWindow = match ? text.slice(Math.max(0, match.index - 30), match.index + 140) : "";

    if (!match) {
      continue;
    }

    if (shouldSkipLabAliasLine(item, matchWindow)) {
      continue;
    }

    const value = Number.parseFloat(String(match[1] || "").replace(/[<>\s]/g, ""));

    if (!Number.isFinite(value)) {
      continue;
    }

    return {
      value,
      unit: normalizeLabUnit(match[2]) || item.unit,
      referenceRange: extractLabReferenceRange(matchWindow, item)
    };
  }

  return null;
}

function shouldSkipLabAliasLine(item, line) {
  const source = normalizeLabSearchText(line);

  return item.id === "albumin" && /(urine|uacr|acr|albumin creatinine ratio|albumin\/creatinine|creatinine ratio)/i.test(source);
}

function escapeLabRegex(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function normalizeLabUnit(unit) {
  return String(unit || "")
    .replace(/\u03bc/g, "u")
    .replace(/\u00b5/g, "u")
    .replace(/\.$/, "")
    .trim();
}

function extractLabReferenceRange(line, item = {}) {
  const source = String(line || "").replace(/\u2013|\u2014/g, "-");
  const unitPattern = item.unit
    ? `(?:\\s*${escapeLabRegex(item.unit).replace(/\\s+/g, "\\s+")})?`
    : "(?:\\s*[%a-zA-Z/u0-9.^+-]+)?";
  const boundedPatterns = [
    new RegExp(`(?:reference\\s*range|ref\\.?\\s*range|normal\\s*range|normal|range)\\s*[:=]?\\s*([<>]?\\s*\\d+(?:\\.\\d+)?)\\s*(?:-|to)\\s*([<>]?\\s*\\d+(?:\\.\\d+)?)${unitPattern}`, "i"),
    new RegExp(`\\(\\s*([<>]?\\s*\\d+(?:\\.\\d+)?)\\s*(?:-|to)\\s*([<>]?\\s*\\d+(?:\\.\\d+)?)${unitPattern}\\s*\\)`, "i")
  ];

  for (const pattern of boundedPatterns) {
    const match = pattern.exec(source);

    if (!match) {
      continue;
    }

    const min = Number.parseFloat(String(match[1] || "").replace(/[<>\s]/g, ""));
    const max = Number.parseFloat(String(match[2] || "").replace(/[<>\s]/g, ""));

    if (Number.isFinite(min) && Number.isFinite(max)) {
      return {
        min: Math.min(min, max),
        max: Math.max(min, max),
        label: `${Math.min(min, max)}-${Math.max(min, max)}${item.unit ? ` ${item.unit}` : ""}`,
        source: "report"
      };
    }
  }

  const lessThan = /(?:reference\s*range|ref\.?\s*range|normal\s*range|normal|range|\()\s*[:=]?\s*<\s*(\d+(?:\.\d+)?)/i.exec(source)
    || /\(<\s*(\d+(?:\.\d+)?)/i.exec(source);

  if (lessThan) {
    const max = Number.parseFloat(lessThan[1]);

    if (Number.isFinite(max)) {
      return {
        max,
        label: `< ${max}${item.unit ? ` ${item.unit}` : ""}`,
        source: "report"
      };
    }
  }

  const greaterThan = /(?:reference\s*range|ref\.?\s*range|normal\s*range|normal|range|\()\s*[:=]?\s*>\s*(\d+(?:\.\d+)?)/i.exec(source)
    || /\(>\s*(\d+(?:\.\d+)?)/i.exec(source);

  if (greaterThan) {
    const min = Number.parseFloat(greaterThan[1]);

    if (Number.isFinite(min)) {
      return {
        min,
        label: `> ${min}${item.unit ? ` ${item.unit}` : ""}`,
        source: "report"
      };
    }
  }

  return null;
}

function evaluateLabMarker(item, value, unit, referenceRange = null) {
  const range = referenceRange || null;
  const status = {
    label: range ? "In report range" : "In guide",
    level: "low",
    detail: item.normalMeaning || item.meaning
  };

  const lowLimit = Number.isFinite(range?.min) ? range.min : item.min;
  const highLimit = Number.isFinite(range?.max) ? range.max : item.max;

  if (Number.isFinite(item.criticalLow) && value <= item.criticalLow) {
    status.label = "Urgent low";
    status.level = "critical";
    status.detail = item.lowMeaning || item.meaning;
  } else if (Number.isFinite(item.criticalHigh) && value >= item.criticalHigh) {
    status.label = "Urgent high";
    status.level = "critical";
    status.detail = item.highMeaning || item.meaning;
  } else if (Number.isFinite(lowLimit) && value < lowLimit) {
    status.label = "Low";
    status.level = "high";
    status.detail = item.lowMeaning || item.meaning;
  } else if (Number.isFinite(highLimit) && value > highLimit) {
    status.label = Number.isFinite(item.high) && value >= item.high ? "High" : "Above guide";
    status.level = Number.isFinite(item.high) && value >= item.high ? "high" : "medium";
    status.detail = item.highMeaning || item.meaning;
  }

  return {
    id: item.id,
    label: item.label,
    value,
    unit: unit || item.unit || "",
    guideRange: range?.label || formatLabGuideRange(item),
    rangeSource: range?.source || "guide",
    meaning: item.meaning,
    status: status.label,
    level: status.level,
    detail: status.detail
  };
}

function formatLabGuideRange(item) {
  const unit = item.unit ? ` ${item.unit}` : "";

  if (Number.isFinite(item.min) && Number.isFinite(item.max)) {
    return `${item.min}-${item.max}${unit}`;
  }

  if (Number.isFinite(item.min)) {
    return `${item.min}+${unit}`;
  }

  if (Number.isFinite(item.max)) {
    return `< ${item.max}${unit}`;
  }

  return "Context-based";
}

function calculateLabReadiness(text, markers, context = {}) {
  if (!text) {
    return 0;
  }

  let score = 22 + Math.min(markers.length * 8, 42);

  if (context.panelType && context.panelType !== "general") score += 7;
  if (context.reportDate || hasLabDate(text)) score += 8;
  if (hasLabReferenceContext(text, markers)) score += 8;
  if (context.trendStatus && context.trendStatus !== "unknown") score += 6;
  if (/previous|prior|last result|trend|repeat/i.test(text)) score += 5;
  if ((context.fastingStatus && context.fastingStatus !== "unknown") || /fasting|non[-\s]?fasting|random/i.test(text)) score += 5;
  if (context.symptoms) score += 5;
  if (context.medicines) score += 4;
  if (/medicine|medication|metformin|statin|thyroid|supplement/i.test(text)) score += 4;

  return Math.max(0, Math.min(96, score));
}

function hasLabDate(text) {
  return /report date|collection date|sample date|date[:\s]|\b\d{1,2}[/-]\d{1,2}[/-]\d{2,4}\b|\b\d{4}-\d{1,2}-\d{1,2}\b/i.test(text);
}

function hasLabReferenceContext(text, markers = []) {
  return markers.some((marker) => marker.rangeSource === "report")
    || /reference|range|normal|flag|\(\s*[<>]?\s*\d+(?:\.\d+)?\s*(?:-|to)\s*\d+(?:\.\d+)?\s*\)|\(\s*[<>]\s*\d+(?:\.\d+)?/i.test(text);
}

function buildLabFeedback(markers, text, context = {}, panel = "general", priority = null, patternInsights = []) {
  if (!text) {
    return [
      {
        title: "Add your report",
        detail: "Upload a text or CSV report, paste copied PDF text, or add values manually. PDF and image files stay local, but copied report text gives the best offline review.",
        level: "none",
        icon: "icon-install"
      }
    ];
  }

  if (!markers.length) {
    return [
      {
        title: "No common markers detected",
        detail: "Paste marker names and values like HbA1c 8.2 %, LDL 160 mg/dL, Hemoglobin 10.8 g/dL, Creatinine 1.6 mg/dL, or eGFR 48.",
        level: "medium",
        icon: "icon-message"
      }
    ];
  }

  const urgent = markers.filter((marker) => marker.level === "critical");
  const abnormal = markers.filter((marker) => marker.level === "high" || marker.level === "medium");
  const normal = markers.filter((marker) => marker.level === "low");
  const cards = [
    ...(priority ? [{
      title: priority.label,
      detail: `${priority.reason} ${priority.next}`,
      level: priority.level || "low",
      icon: priority.level === "critical" ? "icon-alert" : "icon-gauge"
    }] : []),
    {
      title: getLabPanelLabel(panel),
      detail: `Review context: ${context.reportDate || hasLabDate(text) ? "date available" : "date missing"}, ${context.fastingStatus && context.fastingStatus !== "unknown" ? context.fastingStatus : "fasting unknown"}, ${context.trendStatus && context.trendStatus !== "unknown" ? `${context.trendStatus} trend` : "trend not provided"}${context.clinicalContext ? `, ${formatLabContextLabel(context.clinicalContext).toLowerCase()}` : ""}.`,
      level: "low",
      icon: "icon-layers"
    },
    {
      title: "Report understood",
      detail: `I found ${markers.length} marker${markers.length === 1 ? "" : "s"}. ${abnormal.length + urgent.length} need focused review and ${normal.length} look within the available range guide.`,
      level: urgent.length ? "critical" : abnormal.length ? "medium" : "low",
      icon: "icon-brain"
    }
  ];

  if (urgent.length) {
    cards.push({
      title: "Prompt clinical review",
      detail: `${urgent.map((marker) => `${marker.label} ${marker.value}${marker.unit ? ` ${marker.unit}` : ""}`).join(", ")} reached an urgent review band in this demo guide. Use real clinical care for symptoms or very abnormal values.`,
      level: "critical",
      icon: "icon-alert"
    });
  }

  if (abnormal.length) {
    cards.push({
      title: "Focus areas",
      detail: abnormal.slice(0, 4).map((marker) => `${marker.label}: ${marker.status.toLowerCase()}`).join("; ") + ". Review trends, reference ranges, symptoms, and medicines with a clinician.",
      level: "medium",
      icon: "icon-route"
    });
  }

  if (context.symptoms) {
    cards.push({
      title: "Symptoms linked",
      detail: `Reason for review: ${compactText(context.symptoms, 120)}. Share this with the clinician because symptoms can change how lab values are interpreted.`,
      level: "medium",
      icon: "icon-message"
    });
  }

  for (const insight of patternInsights.slice(0, 3)) {
    cards.push({
      title: insight.title,
      detail: insight.detail,
      level: insight.level,
      icon: insight.level === "high" ? "icon-alert" : "icon-route"
    });
  }

  cards.push({
    title: "Plain-language meaning",
    detail: markers.slice(0, 3).map((marker) => `${marker.label} usually relates to ${marker.meaning.toLowerCase()}`).join(" "),
    level: "low",
    icon: "icon-message"
  });

  cards.push({
    title: "Safety boundary",
    detail: "This explains common report patterns only. It does not diagnose disease, prescribe treatment, or replace your doctor or lab reference ranges.",
    level: "low",
    icon: "icon-shield"
  });

  return cards;
}

function buildLabQuestions(markers, context = {}, panel = "general", priority = null, patternInsights = []) {
  if (!markers.length) {
    return ["Which exact lab names, values, units, and reference ranges should be reviewed?"];
  }

  const questions = [];
  const urgent = markers.filter((marker) => marker.level === "critical");
  const abnormal = markers.filter((marker) => marker.level !== "low");

  if (priority?.level === "critical") {
    questions.push("Do any of these results or symptoms need same-day medical care for my situation?");
  }

  questions.push(`For this ${getLabPanelLabel(panel).toLowerCase()}, which result is most important for my age, conditions, and medicines?`);

  if (urgent.length) {
    questions.push("Do any of these values need urgent same-day medical review for my situation?");
  }

  for (const marker of abnormal.slice(0, 4)) {
    questions.push(`What could explain my ${marker.label} being ${marker.status.toLowerCase()}, and when should it be repeated?`);
  }

  if (markers.some((marker) => ["hba1c", "fasting-glucose", "random-glucose"].includes(marker.id))) {
    questions.push("How do these sugar results fit with my diabetes plan, meals, activity, and medicines?");
  }

  if (markers.some((marker) => ["ldl", "hdl", "triglycerides", "total-cholesterol"].includes(marker.id))) {
    questions.push("What heart-risk target should I use for my lipid results based on my age, BP, diabetes, and family history?");
  }

  if (markers.some((marker) => ["creatinine", "egfr", "potassium", "sodium"].includes(marker.id))) {
    questions.push("Do my kidney or electrolyte results require medicine review, hydration advice, urine testing, or follow-up?");
  }

  if (markers.some((marker) => ["alt", "ast", "bilirubin", "alkaline-phosphatase", "albumin"].includes(marker.id))) {
    questions.push("Do the liver-related markers form a pattern that needs repeat testing, medicine review, alcohol review, imaging, or hepatitis testing?");
  }

  if (markers.some((marker) => ["tsh", "free-t4"].includes(marker.id))) {
    questions.push("Should thyroid symptoms, medicine timing, pregnancy status, or free hormone values change how this result is interpreted?");
  }

  if (markers.some((marker) => ["hemoglobin", "mcv", "ferritin", "vitamin-b12"].includes(marker.id))) {
    questions.push("Could anemia, iron, B12, bleeding, diet, kidney disease, or inflammation explain these blood-count results?");
  }

  for (const insight of patternInsights.slice(0, 2)) {
    questions.push(`For the ${insight.title.toLowerCase()}, what is the likely next follow-up: repeat lab, medicine review, lifestyle target, or additional test?`);
  }

  if (context.clinicalContext) {
    questions.push(`Does my ${formatLabContextLabel(context.clinicalContext).toLowerCase()} change how these lab results should be interpreted?`);
  }

  questions.push(context.trendStatus && context.trendStatus !== "unknown"
    ? `Given that my trend is marked ${context.trendStatus}, what changed most compared with my previous report?`
    : "Which result changed most compared with my previous report?");
  questions.push("What one lifestyle or follow-up action matters most before the next visit?");

  return [...new Set(questions)].slice(0, 7);
}

function buildLabMissingDetails(text, markers, context = {}) {
  const missing = [];

  if (!text) {
    return [
      "Upload or paste report text.",
      "Include value, unit, reference range, and report date.",
      "Add symptoms, medicines, fasting status, and previous results when available."
    ];
  }

  if (!context.panelType || context.panelType === "general") {
    missing.push("Choose the closest report type so the agent can focus the review.");
  }

  if (!context.reportDate && !hasLabDate(text)) {
    missing.push("Add the report date or sample collection date.");
  }

  if (!hasLabReferenceContext(text, markers)) {
    missing.push("Add the report reference ranges because ranges can vary by lab, age, sex, and method.");
  }

  if ((!context.trendStatus || context.trendStatus === "unknown") && !/previous|prior|last result|trend|repeat/i.test(text)) {
    missing.push("Add previous results to understand whether values are improving, stable, or worsening.");
  }

  if (markers.some((marker) => ["hba1c", "fasting-glucose", "random-glucose", "ldl", "triglycerides"].includes(marker.id)) && (!context.fastingStatus || context.fastingStatus === "unknown") && !/fasting|non[-\s]?fasting|random/i.test(text)) {
    missing.push("Add fasting or meal timing for sugar and lipid interpretation.");
  }

  if (!context.symptoms) {
    missing.push("Add symptoms or the reason for the test so abnormal values can be framed safely.");
  }

  if (!context.clinicalContext && markers.some((marker) => marker.level !== "low")) {
    missing.push("Choose a clinical context such as diabetes, kidney, infection, anemia, heart risk, pregnancy, procedure, or urgent symptoms.");
  }

  if (!context.medicines && !/medicine|medication|metformin|amlodipine|statin|thyroid|supplement/i.test(text)) {
    missing.push("Add current medicines and supplements if a clinician is reviewing abnormal values.");
  }

  if (!missing.length) {
    missing.push("Good detail. Add symptoms and previous trends if you want a stronger doctor-ready note.");
  }

  return missing.slice(0, 6);
}

function renderLabScore(analysis) {
  const {
    scoreValue,
    scoreRing,
    scoreText,
    markerCount,
    abnormalCount,
    criticalCount,
    confidenceValue
  } = getLabDomCache();
  const score = analysis.readiness || 0;

  if (scoreValue) {
    scoreValue.textContent = `${score}%`;
  }

  if (scoreRing) {
    scoreRing.style.setProperty("--lab-fill", `${score}%`);
    scoreRing.dataset.level = analysis.urgentCount ? "critical" : score >= 76 ? "low" : score >= 48 ? "medium" : "none";
  }

  if (scoreText) {
    scoreText.textContent = !analysis.text
      ? "Upload or paste a report to begin."
      : analysis.markers.length
        ? score >= 76
          ? `${getLabPanelLabel(analysis.panel)} is ready for review. Check the focus areas below.`
          : "Good start. Add reference ranges, date, fasting status, symptoms, and previous results for better review."
        : "Text added, but common lab markers were not detected yet.";
  }

  if (markerCount) markerCount.textContent = String(analysis.markers.length);
  if (abnormalCount) abnormalCount.textContent = String(analysis.abnormalCount);
  if (criticalCount) criticalCount.textContent = String(analysis.urgentCount);
  if (confidenceValue) confidenceValue.textContent = analysis.confidence ? `${analysis.confidence}%` : "--";
}

function renderLabFeedback(analysis) {
  const node = getLabDomCache().feedback;

  if (!node) {
    return;
  }

  const fragment = document.createDocumentFragment();

  for (const card of [...buildLabAgentFeedbackCards(), ...analysis.feedback]) {
    const article = document.createElement("article");
    const title = document.createElement("strong");
    const detail = document.createElement("span");

    article.dataset.level = card.level || "low";
    article.append(createIcon(card.icon || "icon-message", "section-icon"));
    title.textContent = card.title;
    detail.textContent = card.detail;
    article.append(title, detail);
    fragment.append(article);
  }

  node.replaceChildren(fragment);
}

function getLatestLabAgentOutput() {
  const result = latestLabAgentResult;
  const agent = result?.agentResults?.find((item) => item.id === "LABS_AGENT");

  if (!result || !agent) {
    return null;
  }

  return {
    result,
    agent,
    output: agent.output || {}
  };
}

function buildLabAgentFeedbackCards() {
  const latest = getLatestLabAgentOutput();

  if (!latest) {
    return [];
  }

  const { result, output } = latest;
  const priority = output.priority || result.risk?.label || "lab review";
  const action = output.labActions?.[0] || output.checklist?.[0] || result.finalResponse?.whatToDoNow?.[0] || "Review exact values, units, ranges, and symptoms with a clinician.";
  const gaps = Array.isArray(output.accuracyGaps) && output.accuracyGaps.length
    ? `Missing for higher precision: ${output.accuracyGaps.slice(0, 4).join(", ")}.`
    : "Core context is enough for a focused clinician packet.";

  return [
    {
      title: `Agent priority: ${formatContextValue(priority)}`,
      detail: output.summary || result.finalResponse?.summary || "Labs Agent completed the focused report review.",
      level: /prompt|urgent|critical|high/i.test(priority) || result.risk?.level === "HIGH" || result.risk?.level === "CRITICAL" ? "critical" : "low",
      icon: "icon-brain"
    },
    {
      title: "Next best step",
      detail: action,
      level: result.risk?.level?.toLowerCase?.() || "low",
      icon: "icon-route"
    },
    {
      title: "Precision check",
      detail: gaps,
      level: output.accuracyGaps?.length ? "medium" : "low",
      icon: "icon-shield"
    }
  ];
}

function getLabMarkerFilterValue() {
  return getLabDomCache().markerFilter?.value.trim().toLowerCase() || "";
}

function doesLabMarkerMatchFilter(marker, filterValue) {
  if (!filterValue) {
    return true;
  }

  return [
    marker.label,
    marker.value,
    marker.unit,
    marker.guideRange,
    marker.status,
    marker.detail,
    marker.level
  ].some((value) => String(value || "").toLowerCase().includes(filterValue));
}

function renderLabMarkerTable(markers = []) {
  const table = getLabDomCache().markerTable;

  if (!table) {
    return;
  }

  const fragment = document.createDocumentFragment();
  const filterValue = getLabMarkerFilterValue();
  const visibleMarkers = (markers || []).filter((marker) => doesLabMarkerMatchFilter(marker, filterValue));

  if (!markers.length) {
    const row = document.createElement("tr");
    const cell = document.createElement("td");

    cell.colSpan = 5;
    cell.textContent = "No report analyzed yet.";
    row.append(cell);
    fragment.append(row);
    table.replaceChildren(fragment);
    return;
  }

  if (!visibleMarkers.length) {
    const row = document.createElement("tr");
    const cell = document.createElement("td");

    cell.colSpan = 5;
    cell.textContent = "No extracted markers match this filter.";
    row.append(cell);
    fragment.append(row);
    table.replaceChildren(fragment);
    return;
  }

  for (const marker of visibleMarkers) {
    const row = document.createElement("tr");
    const status = document.createElement("span");

    row.dataset.level = marker.level;
    status.className = "lab-status-pill";
    status.dataset.level = marker.level;
    status.textContent = marker.status;

    for (const value of [
      marker.label,
      `${marker.value}${marker.unit ? ` ${marker.unit}` : ""}`,
      `${marker.guideRange}${marker.rangeSource === "report" ? " (report)" : " (guide)"}`
    ]) {
      const cell = document.createElement("td");
      cell.textContent = value;
      row.append(cell);
    }

    const statusCell = document.createElement("td");
    const meaningCell = document.createElement("td");

    statusCell.append(status);
    meaningCell.textContent = marker.detail;
    row.append(statusCell, meaningCell);
    fragment.append(row);
  }

  table.replaceChildren(fragment);
}

function renderLabQuestions(questions) {
  const list = getLabDomCache().questions;

  if (!list) {
    return;
  }

  renderDashboardList(list, (questions.length ? questions : ["Add a report to generate focused questions."]).map((question, index) => ({
    title: index === 0 ? "Start here" : `Question ${index + 1}`,
    detail: question,
    level: /urgent|same-day|critical|prompt/i.test(question) ? "critical" : index < 2 ? "low" : "medium"
  })));
}

function renderLabMissingDetails(items) {
  const list = getLabDomCache().missingDetails;

  if (!list) {
    return;
  }

  renderDashboardList(list, (items.length ? items : ["Good detail."]).map((detail, index) => ({
    title: index === 0 ? "Improve precision" : `Check ${index + 1}`,
    detail,
    level: index === 0 ? "medium" : "low"
  })));
}

function renderLabSummaryList(items = []) {
  const list = getLabDomCache().summaryList;

  if (!list) {
    return;
  }

  const fragment = document.createDocumentFragment();

  for (const detail of items.length ? items : ["Select a report type and add values to build a review plan."]) {
    const item = document.createElement("li");
    item.textContent = detail;
    fragment.append(item);
  }

  list.replaceChildren(fragment);
}

function buildLabTrendInsights(markers = [], savedReports = []) {
  if (!markers.length) {
    return ["Analyze a report to compare saved marker trends."];
  }

  const trends = [];

  for (const marker of markers) {
    const prior = savedReports
      .flatMap((report) => (report.markers || []).map((savedMarker) => ({
        report,
        marker: savedMarker
      })))
      .find((entry) => entry.marker.id === marker.id);

    if (!prior) {
      trends.push(`${marker.label}: no saved prior value yet. Save this report to start the trend.`);
      continue;
    }

    const delta = Number(marker.value) - Number(prior.marker.value);
    const absDelta = Math.abs(delta);
    const direction = absDelta < 0.01 ? "same as" : delta > 0 ? "higher than" : "lower than";
    const date = prior.report.reportDate || prior.report.createdAt?.slice(0, 10) || "previous report";

    trends.push(`${marker.label}: ${marker.value}${marker.unit ? ` ${marker.unit}` : ""} is ${direction} ${date} (${prior.marker.value}${prior.marker.unit ? ` ${prior.marker.unit}` : ""}).`);
  }

  return trends.slice(0, 6);
}

function renderLabTrendList(items = []) {
  const list = getLabDomCache().trendList;

  if (!list) {
    return;
  }

  renderDashboardList(list, (items.length ? items : ["Save at least one report to compare future marker trends."]).map((detail, index) => ({
    title: index === 0 ? "Trend signal" : `Trend ${index + 1}`,
    detail,
    level: /higher|lower|worsening|urgent|critical/i.test(detail) ? "medium" : "low"
  })));
}

function buildLabDoctorPacket(analysis = {}) {
  const markers = analysis.markers || [];
  const context = analysis.context || {};
  const profile = typeof collectProfile === "function" ? collectProfile() : defaultProfile;
  const abnormal = markers.filter((marker) => marker.level !== "low");
  const urgent = markers.filter((marker) => marker.level === "critical");
  const questions = analysis.questions || buildLabQuestions(markers, context, analysis.panel || "general");

  if (!analysis.text && !markers.length) {
    return "No lab report analyzed yet.";
  }

  return [
    "Care Nova AI - Lab Review Packet",
    `Patient: ${profile.name || defaultProfile.name}${profile.age ? `, ${profile.age}` : ""}`,
    `Report: ${getLabPanelLabel(analysis.panel || "general")}`,
    `Date: ${context.reportDate || "not provided"}`,
    `Readiness: ${analysis.confidence || 0}% context confidence`,
    `Priority: ${analysis.priority?.label || "not calculated"}${analysis.priority?.reason ? ` - ${analysis.priority.reason}` : ""}`,
    `Markers detected: ${markers.length}`,
    `Needs review: ${abnormal.length ? abnormal.map((marker) => `${marker.label} ${marker.value}${marker.unit ? ` ${marker.unit}` : ""} - ${marker.status}`).join("; ") : "none flagged by this local review"}`,
    urgent.length ? `Urgent flags: ${urgent.map((marker) => marker.label).join(", ")}` : "Urgent flags: none detected by this local review",
    `Fasting/meal context: ${context.fastingStatus || "unknown"}`,
    `Clinical context: ${formatLabContextLabel(context.clinicalContext) || "not provided"}`,
    `Symptoms or reason: ${context.symptoms || "not provided"}`,
    `Medicines or supplements: ${context.medicines || "not provided"}`,
    "",
    "Pattern notes:",
    ...((analysis.patternInsights || []).slice(0, 4).map((insight) => `- ${insight.title}: ${insight.detail}`)),
    "",
    "Key questions:",
    ...questions.slice(0, 5).map((question) => `- ${question}`),
    "",
    "Safety boundary: This packet explains extracted patterns and questions only. It does not diagnose, prescribe, or replace the lab's reference range or clinician review."
  ].join("\n");
}

function renderLabDoctorPacket(packet = "") {
  const node = getLabDomCache().doctorPacket;

  if (node) {
    node.textContent = packet || "Analyze a report to build a concise doctor-ready packet.";
  }
}

function getLabReportsVaultStorageKey(targetPatientId = patientId) {
  return `${storageKeys.labReportsVault}.${normalizePatientStorageId(targetPatientId)}`;
}

function loadLabReportsVault(targetPatientId = patientId) {
  return loadJson(getLabReportsVaultStorageKey(targetPatientId), [])
    .map(normalizeLabVaultEntry)
    .filter((entry) => entry.id)
    .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
}

function saveLabReportsVault(reports = [], targetPatientId = patientId, options = {}) {
  saveJson(getLabReportsVaultStorageKey(targetPatientId), reports.map(normalizeLabVaultEntry).slice(0, 80), {
    targetPatientId,
    reason: "lab-report-update",
    ...options
  });
}

function normalizeLabVaultEntry(entry = {}) {
  const now = new Date().toISOString();
  const context = entry.context || {};
  const reportDate = String(entry.reportDate || context.reportDate || formatDateForInput(new Date())).trim();

  return {
    id: String(entry.id || `lab-${Date.now()}`).trim(),
    createdAt: parseIsoDate(entry.createdAt) || now,
    updatedAt: parseIsoDate(entry.updatedAt) || now,
    patientName: String(entry.patientName || collectProfile().name || defaultProfile.name).trim(),
    reportDate,
    panel: String(entry.panel || context.panelType || "general").trim(),
    title: String(entry.title || `${getLabPanelLabel(entry.panel || context.panelType || "general")} - ${reportDate}`).trim(),
    text: String(entry.text || "").trim(),
    context,
    markers: Array.isArray(entry.markers) ? entry.markers : [],
    readiness: Number(entry.readiness || 0),
    confidence: Number(entry.confidence || 0),
    abnormalCount: Number(entry.abnormalCount || 0),
    urgentCount: Number(entry.urgentCount || 0),
    doctorPacket: String(entry.doctorPacket || "").trim()
  };
}

function saveCurrentLabReport() {
  const text = getLabDomCache().reportText?.value.trim() || "";
  const context = collectLabContext();
  const analysis = getMemoizedLabAnalysis(text, context, getComparableLabReportsForAnalysis(text, loadLabReportsVault()));

  if (!text || !analysis.markers.length) {
    setLabFileStatus("Add a report with recognizable marker names and values before saving.", "medium");
    return;
  }

  const profile = collectProfile();
  const now = new Date().toISOString();
  const reportDate = context.reportDate || extractLabReportDate(text) || formatDateForInput(new Date());
  const entry = normalizeLabVaultEntry({
    id: `lab-${Date.now()}`,
    createdAt: now,
    updatedAt: now,
    patientName: profile.name || defaultProfile.name,
    reportDate,
    panel: analysis.panel,
    title: `${getLabPanelLabel(analysis.panel)} - ${reportDate}`,
    text,
    context: {
      ...context,
      reportDate
    },
    markers: analysis.markers,
    readiness: analysis.readiness,
    confidence: analysis.confidence,
    abnormalCount: analysis.abnormalCount,
    urgentCount: analysis.urgentCount,
    doctorPacket: analysis.doctorPacket
  });
  const reports = [entry, ...loadLabReportsVault().filter((report) => report.id !== entry.id)].slice(0, 80);

  saveLabReportsVault(reports);
  appendLabReportsToPatientRecords([entry]);
  setLabFileStatus("Lab report saved locally and added to patient Records.", "low");
  invalidateLabAnalysisMemo();
  renderSavedLabReports(reports, { force: true });
  renderLabReportAnalysis(text);
  activateWorkspaceSubtab("labs", "vault", true);
}

function extractLabReportDate(text) {
  const match = /(?:report|collection|sample)?\s*date[:\s]+(\d{4}-\d{1,2}-\d{1,2}|\d{1,2}[/-]\d{1,2}[/-]\d{2,4})/i.exec(text);

  if (!match) {
    return "";
  }

  const date = parseInputDate(match[1]);
  return date ? formatDateForInput(date) : match[1];
}

function appendLabReportToPatientRecords(entry) {
  appendLabReportsToPatientRecords(entry ? [entry] : []);
}

function appendLabReportsToPatientRecords(entries = []) {
  try {
    const profile = collectProfile();
    const safeEntries = (Array.isArray(entries) ? entries : [])
      .map(normalizeLabVaultEntry)
      .filter((entry) => entry.id);

    if (!safeEntries.length) {
      return;
    }

    let records = loadPatientDataRecords();
    let selectedRecordId = "";

    for (const entry of safeEntries) {
      const markerSummary = buildLabMarkerSummaryText(entry.markers);
      const record = normalizePatientDataRecordForClient({
        id: `record-${entry.id}`,
        createdAt: entry.createdAt,
        updatedAt: entry.updatedAt,
        patientName: profile.name || defaultProfile.name,
        age: profile.age || "",
        type: "labs",
        date: entry.reportDate || formatDateForInput(new Date()),
        episode: "Lab review",
        tags: ["labs", entry.panel, "doctor-packet", entry.urgentCount ? "urgent-review" : ""].filter(Boolean).join(", "),
        source: "Labs tab",
        documentCategory: "lab-report",
        documentName: entry.title,
        conditions: profile.conditions || "",
        allergies: profile.allergies || "",
        medicines: entry.context?.medicines || profile.medications || "",
        vitals: summarizeVitalsForRecord(collectVitals()),
        labs: markerSummary,
        notes: entry.doctorPacket,
        followUp: entry.urgentCount
          ? "Share urgent flags with real medical care promptly."
          : "Review abnormal markers, trends, and questions with a clinician.",
        versionNote: "Saved from Labs Intelligence Agent."
      });

      record.correctionHistory = buildRecordCorrectionHistory(null, record);
      records = [record, ...records.filter((item) => item.id !== record.id)].slice(0, 300);
      selectedRecordId = record.id;
    }

    savePatientDataRecordsLocal(records);

    if (selectedRecordId) {
      setSelectedPatientDataRecordId(selectedRecordId);
    }

    renderPatientDataRecords();

    if (selectedRecordId) {
      persistPatientDataRecords(records, selectedRecordId);
    }
  } catch {
    // The lab report remains in the local lab vault if Records sync is unavailable.
  }
}

function buildLabMarkerSummaryText(markers = []) {
  if (!markers.length) {
    return "No extracted markers.";
  }

  return markers
    .slice(0, 24)
    .map((marker) => `${marker.label}: ${marker.value}${marker.unit ? ` ${marker.unit}` : ""}; ${marker.status}; range ${marker.guideRange}${marker.rangeSource === "report" ? " from report" : " guide"}`)
    .join("\n");
}

async function copyCurrentLabDoctorPacket() {
  const packet = getLabDomCache().doctorPacket?.textContent || "";
  const copied = await copyText(packet);
  setLabFileStatus(copied ? "Doctor packet copied." : "Copy was blocked; packet remains visible.", copied ? "low" : "medium");
}

function downloadCurrentLabDoctorPacket() {
  const packet = getLabDomCache().doctorPacket?.textContent || "";

  if (!packet || /No lab report analyzed/i.test(packet)) {
    setLabFileStatus("Analyze a report before downloading a packet.", "medium");
    return;
  }

  downloadLocalFile(packet, getPatientReportFilename("lab-doctor-packet", "txt"), "text/plain");
  setLabFileStatus("Doctor packet downloaded.", "low");
}

function openSavedLabReport(reportId) {
  const report = loadLabReportsVault().find((entry) => entry.id === reportId);

  if (!report) {
    return;
  }

  const reportText = getLabDomCache().reportText;

  if (reportText) {
    reportText.value = report.text;
    saveLocalStorageValue(storageKeys.labReportDraft, report.text);
  }

  applyLabReportContext(report.context || {});
  saveLabReportContext(report.context || collectLabContext());
  invalidateLabAnalysisMemo();
  setLabFileStatus("Saved lab report opened.", "low");
  renderLabReportAnalysis(report.text);
  activateWorkspaceSubtab("labs", "findings", true);
}

function deleteSavedLabReport(reportId) {
  const reports = loadLabReportsVault().filter((entry) => entry.id !== reportId);
  saveLabReportsVault(reports);
  invalidateLabAnalysisMemo();
  setLabFileStatus("Saved lab report removed from the lab vault.", "medium");
  renderSavedLabReports(reports, { force: true });
  renderLabReportAnalysis();
}

function downloadSavedLabReport(reportId) {
  const report = loadLabReportsVault().find((entry) => entry.id === reportId);

  if (!report) {
    return;
  }

  downloadLocalFile(report.doctorPacket || buildLabDoctorPacket(report), getPatientReportFilename("saved-lab-report", "txt"), "text/plain");
  setLabFileStatus("Saved report packet downloaded.", "low");
}

function renderSavedLabReports(reports = loadLabReportsVault(), options = {}) {
  const dom = getLabDomCache();
  const list = dom.savedReports;

  if (!list) {
    return;
  }

  const query = normalizeLabSearchText(dom.savedSearch?.value || "");
  const renderSignature = `${query}:${getLabVaultSignature(reports)}`;

  if (!options.force && labSavedReportsRenderSignature === renderSignature) {
    return;
  }

  labSavedReportsRenderSignature = renderSignature;

  const filtered = query
    ? reports.filter((report) => normalizeLabSearchText([
      report.title,
      report.reportDate,
      getLabPanelLabel(report.panel),
      report.text,
      buildLabMarkerSummaryText(report.markers)
    ].join(" ")).includes(query))
    : reports;
  const fragment = document.createDocumentFragment();

  if (!filtered.length) {
    const item = document.createElement("li");
    item.textContent = reports.length ? "No saved lab report matches this search." : "No saved lab reports yet.";
    fragment.append(item);
    list.replaceChildren(fragment);
    return;
  }

  for (const report of filtered.slice(0, 16)) {
    const item = document.createElement("li");
    const title = document.createElement("strong");
    const detail = document.createElement("span");
    const actions = document.createElement("div");
    const open = document.createElement("button");
    const download = document.createElement("button");
    const remove = document.createElement("button");

    item.className = "lab-vault-item";
    title.textContent = report.title;
    detail.textContent = `${report.markers.length} markers - ${report.abnormalCount} need review - ${report.confidence || report.readiness}% ready`;
    actions.className = "lab-vault-actions";

    open.type = "button";
    open.dataset.openLabReport = report.id;
    open.append(createIcon("icon-route", "button-icon"), document.createTextNode("Open"));
    download.type = "button";
    download.dataset.downloadLabReport = report.id;
    download.append(createIcon("icon-install", "button-icon"), document.createTextNode("Download"));
    remove.type = "button";
    remove.dataset.deleteLabReport = report.id;
    remove.append(createIcon("icon-eraser", "button-icon"), document.createTextNode("Delete"));

    actions.append(open, download, remove);
    item.append(title, detail, actions);
    fragment.append(item);
  }

  list.replaceChildren(fragment);
}

function initializeRecordsVault() {
  const records = document.querySelector("#recordsInterface");

  if (!records || records.dataset.recordsReady === "true") {
    return;
  }

  records.querySelector("#recordSaveButton")?.addEventListener("click", savePatientDataRecord);
  records.querySelector("#recordClearButton")?.addEventListener("click", () => {
    clearPatientRecordForm();
    setSelectedPatientDataRecordId("");
    setRecordFormStatus("Ready for a new local record. Valid changes autosave locally.");
    renderPatientDataRecords({ force: true });
  });
  records.querySelector("#recordNewButton")?.addEventListener("click", () => {
    clearPatientRecordForm();
    setSelectedPatientDataRecordId("");
    renderPatientDataRecords({ force: true });
    activateWorkspaceSubtab("records", "builder", true);
  });
  records.querySelector("#recordDeleteButton")?.addEventListener("click", deleteSelectedPatientRecord);
  records.querySelector("#recordUseProfile")?.addEventListener("click", fillRecordFromProfile);
  records.querySelector("#recordUseVitals")?.addEventListener("click", fillRecordFromVitals);
  records.querySelector("#recordUseVisit")?.addEventListener("click", fillRecordFromVisitDraft);
  records.querySelector("#recordUseLab")?.addEventListener("click", fillRecordFromLabText);
  records.querySelector("#recordFileTrigger")?.addEventListener("click", () => {
    records.querySelector("#recordFileInput")?.click();
  });
  records.querySelector("#recordFileInput")?.addEventListener("change", updateRecordFileReference);
  records.querySelector("#recordSearchInput")?.addEventListener("input", schedulePatientDataRecordsRender);
  records.querySelector("#recordSortSelect")?.addEventListener("change", (event) => {
    records.dataset.recordSort = event.target.value || "newest";
    renderPatientDataRecords({ force: true });
  });
  records.querySelector("#recordClearFiltersButton")?.addEventListener("click", () => {
    const searchInput = records.querySelector("#recordSearchInput");
    const sortSelect = records.querySelector("#recordSortSelect");

    if (searchInput) {
      searchInput.value = "";
    }

    if (sortSelect) {
      sortSelect.value = "newest";
    }

    records.dataset.recordFilter = "all";
    records.dataset.recordSort = "newest";
    renderPatientDataRecords({ force: true });
  });
  records.querySelector(".record-editor-card")?.addEventListener("input", (event) => {
    if (event.target.closest("#recordFileInput")) {
      return;
    }

    records.dataset.formDirty = "true";
    clearPatientRecordValidation();
    patientRecordAutosaveRequested = true;
    setRecordFormStatus("Editing record. Valid changes autosave locally after a short pause.");
    schedulePatientRecordDraftPreview();
    schedulePatientRecordAutosave();
  });
  records.querySelector(".record-editor-card")?.addEventListener("change", (event) => {
    if (event.target.closest("#recordFileInput")) {
      return;
    }

    records.dataset.formDirty = "true";
    clearPatientRecordValidation();
    schedulePatientRecordDraftPreview.flush();
    patientRecordAutosaveRequested = true;
    schedulePatientRecordAutosave();
  });
  records.querySelector("#recordCopySummaryButton")?.addEventListener("click", copyRecordPacket);
  records.querySelector("#recordExportButton")?.addEventListener("click", exportPatientDataRecords);
  records.querySelector("#recordDownloadJson")?.addEventListener("click", downloadPatientReportJson);
  records.querySelector("#recordDownloadText")?.addEventListener("click", downloadPatientReportText);
  records.querySelector("#recordDownloadCsv")?.addEventListener("click", downloadPatientRecordsCsv);
  records.querySelector("#recordTypeFilters")?.addEventListener("click", (event) => {
    const button = event.target.closest("[data-record-filter]");

    if (!button) {
      return;
    }

    const nextFilter = button.dataset.recordFilter || "all";

    if ((records.dataset.recordFilter || "all") === nextFilter) {
      return;
    }

    records.dataset.recordFilter = nextFilter;
    renderPatientDataRecords();
  });

  records.querySelector("#recordVaultList")?.addEventListener("click", (event) => {
    const openButton = event.target.closest("[data-open-record]");
    const deleteButton = event.target.closest("[data-delete-record]");

    if (openButton) {
      openPatientDataRecord(openButton.dataset.openRecord);
    }

    if (deleteButton) {
      deletePatientDataRecord(deleteButton.dataset.deleteRecord);
    }
  });

  setDefaultRecordDate();
  hydrateSelectedPatientRecordForm();
  updateRecordFileSelectionSummary();
  records.dataset.recordsReady = "true";
  renderPatientDataRecords();
  syncPatientDataRecordsFromServer();
}

function setDefaultRecordDate() {
  const date = document.querySelector("#recordDate");

  if (date && !date.value) {
    date.value = formatDateForInput(new Date());
  }
}

function hydrateSelectedPatientRecordForm(selectedRecordId = getSelectedPatientDataRecordId()) {
  const records = document.querySelector("#recordsInterface");

  if (records?.dataset.formDirty === "true") {
    return;
  }

  const patientRecords = loadPatientDataRecords();
  const record = patientRecords.find((item) => item.id === selectedRecordId) || patientRecords[0] || null;

  if (record) {
    applyPatientDataRecord(record);
    return;
  }

  clearPatientRecordForm({ render: false });
  fillRecordFromProfile(false);

  if (records) {
    records.dataset.formDirty = "false";
    records.dataset.formHydrated = "true";
  }

  markPatientDataRecordFormSaved();
}

function updateRecordFileReference() {
  const input = document.querySelector("#recordFileInput");
  const reference = document.querySelector("#recordFileReference");

  updateRecordFileSelectionSummary(input?.files || []);

  if (!input || !reference || !input.files?.length) {
    return;
  }

  const files = Array.from(input.files)
    .slice(0, 8)
    .map((file) => `${file.name} (${formatRecordFileSize(file.size)})`);
  const existing = reference.value.trim();

  reference.value = [existing, ...files]
    .filter(Boolean)
    .join(existing ? "\n" : "");
  document.querySelector("#recordsInterface")?.setAttribute("data-form-dirty", "true");
  patientRecordAutosaveRequested = true;
  setRecordFormStatus("Attachment reference added. Valid changes autosave locally.");
  renderPatientRecordPreview(collectPatientDataRecord());
  schedulePatientRecordAutosave();
}

function updateRecordFileSelectionSummary(files = []) {
  const summary = document.querySelector("#recordFileSummary");
  const selections = Array.from(files || []);

  if (!summary) {
    return;
  }

  if (!selections.length) {
    summary.textContent = "No files selected";
    summary.removeAttribute("title");
    return;
  }

  const previewNames = selections.slice(0, 2).map((file) => file.name);
  const remaining = selections.length - previewNames.length;
  summary.textContent = remaining > 0 ? `${previewNames.join(", ")} + ${remaining} more` : previewNames.join(", ");
  summary.title = selections.map((file) => file.name).join(", ");
}

function formatRecordFileSize(bytes) {
  const size = Number(bytes || 0);

  if (!Number.isFinite(size) || size <= 0) {
    return "size unknown";
  }

  if (size < 1024 * 1024) {
    return `${Math.max(1, Math.round(size / 1024))} KB`;
  }

  return `${(size / (1024 * 1024)).toFixed(1)} MB`;
}

function collectPatientDataRecord() {
  return {
    id: document.querySelector("#recordsInterface")?.dataset.selectedRecord || `record-${Date.now()}`,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    patientName: document.querySelector("#recordPatientName")?.value.trim() || "Patient",
    age: document.querySelector("#recordPatientAge")?.value.trim() || "",
    type: document.querySelector("#recordType")?.value || "profile",
    date: document.querySelector("#recordDate")?.value || formatDateForInput(new Date()),
    episode: document.querySelector("#recordEpisode")?.value.trim() || "",
    tags: parseRecordTags(document.querySelector("#recordTags")?.value || ""),
    source: document.querySelector("#recordSource")?.value.trim() || "",
    documentCategory: document.querySelector("#recordDocumentCategory")?.value || "",
    documentName: document.querySelector("#recordDocumentName")?.value.trim() || "",
    fileReferences: document.querySelector("#recordFileReference")?.value.trim() || "",
    conditions: document.querySelector("#recordConditions")?.value.trim() || "",
    allergies: document.querySelector("#recordAllergies")?.value.trim() || "",
    medicines: document.querySelector("#recordMedicines")?.value.trim() || "",
    vitals: document.querySelector("#recordVitals")?.value.trim() || "",
    labs: document.querySelector("#recordLabs")?.value.trim() || "",
    notes: document.querySelector("#recordNotes")?.value.trim() || "",
    followUp: document.querySelector("#recordFollowUp")?.value.trim() || "",
    versionNote: document.querySelector("#recordVersionNote")?.value.trim() || "",
    correctionHistory: []
  };
}

function getPatientDataRecordFormSignature() {
  return JSON.stringify({
    patientId,
    selectedRecordId: document.querySelector("#recordsInterface")?.dataset.selectedRecord || "",
    patientName: document.querySelector("#recordPatientName")?.value.trim() || "",
    age: document.querySelector("#recordPatientAge")?.value.trim() || "",
    type: document.querySelector("#recordType")?.value || "profile",
    date: document.querySelector("#recordDate")?.value || "",
    episode: document.querySelector("#recordEpisode")?.value.trim() || "",
    tags: document.querySelector("#recordTags")?.value.trim() || "",
    source: document.querySelector("#recordSource")?.value.trim() || "",
    documentCategory: document.querySelector("#recordDocumentCategory")?.value || "",
    documentName: document.querySelector("#recordDocumentName")?.value.trim() || "",
    fileReferences: document.querySelector("#recordFileReference")?.value.trim() || "",
    conditions: document.querySelector("#recordConditions")?.value.trim() || "",
    allergies: document.querySelector("#recordAllergies")?.value.trim() || "",
    medicines: document.querySelector("#recordMedicines")?.value.trim() || "",
    vitals: document.querySelector("#recordVitals")?.value.trim() || "",
    labs: document.querySelector("#recordLabs")?.value.trim() || "",
    notes: document.querySelector("#recordNotes")?.value.trim() || "",
    followUp: document.querySelector("#recordFollowUp")?.value.trim() || "",
    versionNote: document.querySelector("#recordVersionNote")?.value.trim() || ""
  });
}

function markPatientDataRecordFormSaved() {
  patientRecordLastSavedFormSignature = getPatientDataRecordFormSignature();
  patientRecordAutosaveRequested = false;
}

function validatePatientRecordForm({ markInvalid = true } = {}) {
  clearPatientRecordValidation();

  const name = document.querySelector("#recordPatientName");
  const date = document.querySelector("#recordDate");
  const detailControls = [
    "#recordConditions",
    "#recordAllergies",
    "#recordMedicines",
    "#recordVitals",
    "#recordLabs",
    "#recordNotes",
    "#recordFollowUp",
    "#recordDocumentName",
    "#recordFileReference"
  ]
    .map((selector) => document.querySelector(selector))
    .filter(Boolean);

  if (!name?.value.trim()) {
    if (markInvalid) {
      markPatientRecordFieldInvalid(name);
    }
    return {
      valid: false,
      target: name,
      message: "Add a patient name before saving this record."
    };
  }

  if (!date?.value || Number.isNaN(new Date(date.value).getTime())) {
    if (markInvalid) {
      markPatientRecordFieldInvalid(date);
    }
    return {
      valid: false,
      target: date,
      message: "Add a valid record date before saving."
    };
  }

  if (!detailControls.some((control) => control.value.trim())) {
    const target = document.querySelector("#recordNotes") || detailControls[0] || null;
    if (markInvalid) {
      markPatientRecordFieldInvalid(target);
    }
    return {
      valid: false,
      target,
      message: "Add at least one clinical note, document reference, medicine, lab, vital, condition, allergy, or follow-up detail."
    };
  }

  return { valid: true, target: null, message: "" };
}

function markPatientRecordFieldInvalid(control) {
  if (!control) {
    return;
  }

  control.setAttribute("aria-invalid", "true");
  control.classList.add("record-field-invalid");
}

function clearPatientRecordValidation() {
  document.querySelectorAll("#recordsInterface .record-field-invalid").forEach((control) => {
    control.classList.remove("record-field-invalid");
    control.removeAttribute("aria-invalid");
  });
}

function applyPatientDataRecord(record) {
  const values = {
    recordPatientName: record.patientName,
    recordPatientAge: record.age,
    recordType: record.type,
    recordDate: record.date,
    recordEpisode: record.episode,
    recordTags: formatRecordTags(record.tags),
    recordSource: record.source,
    recordDocumentCategory: record.documentCategory,
    recordDocumentName: record.documentName,
    recordFileReference: record.fileReferences,
    recordConditions: record.conditions,
    recordAllergies: record.allergies,
    recordMedicines: record.medicines,
    recordVitals: record.vitals,
    recordLabs: record.labs,
    recordNotes: record.notes,
    recordFollowUp: record.followUp,
    recordVersionNote: ""
  };

  for (const [id, value] of Object.entries(values)) {
    const control = document.querySelector(`#${id}`);

    if (control) {
      control.value = value || "";
    }
  }

  const records = document.querySelector("#recordsInterface");

  if (records) {
    records.dataset.selectedRecord = record.id || "";
    records.dataset.formDirty = "false";
    records.dataset.formHydrated = "true";
    records.dataset.blankDraft = "false";
  }

  const deleteButton = document.querySelector("#recordDeleteButton");

  if (deleteButton) {
    deleteButton.disabled = !record.id;
  }

  markPatientDataRecordFormSaved();
}

function syncPatientDataRecordEditorState(record) {
  const records = document.querySelector("#recordsInterface");
  const deleteButton = document.querySelector("#recordDeleteButton");
  const versionNote = document.querySelector("#recordVersionNote");

  if (records) {
    records.dataset.selectedRecord = record.id || "";
    records.dataset.formDirty = "false";
    records.dataset.formHydrated = "true";
    records.dataset.blankDraft = "false";
  }

  if (versionNote) {
    versionNote.value = "";
  }

  if (deleteButton) {
    deleteButton.disabled = !record.id;
  }

  markPatientDataRecordFormSaved();
}

async function savePatientDataRecord({ auto = false } = {}) {
  const validation = validatePatientRecordForm({ markInvalid: !auto });

  if (!validation.valid) {
    if (!auto) {
      setRecordFormStatus(validation.message);
      validation.target?.focus?.({ preventScroll: false });
    }
    return false;
  }

  const record = collectPatientDataRecord();
  const records = loadPatientDataRecords();
  const existingIndex = records.findIndex((item) => item.id === record.id);
  const saveButton = document.querySelector("#recordSaveButton");

  if (saveButton) {
    saveButton.disabled = true;
    saveButton.setAttribute("aria-busy", "true");
  }

  setRecordFormStatus(auto ? "Autosaving record locally." : "Saving record locally.");

  try {
    if (existingIndex >= 0) {
      const previousRecord = records[existingIndex];
      record.createdAt = previousRecord.createdAt || record.createdAt;
      record.correctionHistory = buildRecordCorrectionHistory(previousRecord, record, { mode: auto ? "auto" : "manual" });
      records[existingIndex] = record;
    } else {
      record.correctionHistory = buildRecordCorrectionHistory(null, record, { mode: auto ? "auto" : "manual" });
      records.unshift(record);
    }

    savePatientDataRecordsLocal(records);
    setSelectedPatientDataRecordId(record.id);
    if (auto) {
      syncPatientDataRecordEditorState(record);
    } else {
      applyPatientDataRecord(record);
    }
    resetRecordRenderState();
    renderPatientDataRecords({ force: true });
    await persistPatientDataRecords(records, record.id);
    setRecordFormStatus(recordServerSyncStatus.state === "synced"
      ? auto
        ? "Record autosaved locally and synced to the localhost records store."
        : "Record saved locally and synced to the localhost records store."
      : auto
        ? "Record autosaved on this device. Server sync will retry when available."
        : "Record saved on this device. Server sync will retry when available.");
    markPatientDataRecordFormSaved();
    return true;
  } finally {
    if (saveButton) {
      saveButton.disabled = false;
      saveButton.removeAttribute("aria-busy");
    }
  }
}

async function runPatientRecordAutosave() {
  const records = document.querySelector("#recordsInterface");

  if (!records?.isConnected || records.dataset.formDirty !== "true") {
    patientRecordAutosaveRequested = false;
    return false;
  }

  if (patientRecordAutosaveInFlight) {
    if (patientRecordAutosaveRequested) {
      schedulePatientRecordAutosave();
    }
    return false;
  }

  const validation = validatePatientRecordForm({ markInvalid: false });

  if (!validation.valid) {
    clearPatientRecordValidation();
    setRecordFormStatus("Editing record. Autosave will save when patient name, date, and one record detail are complete.");
    return false;
  }

  if (getPatientDataRecordFormSignature() === patientRecordLastSavedFormSignature) {
    records.dataset.formDirty = "false";
    patientRecordAutosaveRequested = false;
    return false;
  }

  patientRecordAutosaveRequested = false;
  patientRecordAutosaveInFlight = true;

  try {
    return await savePatientDataRecord({ auto: true });
  } finally {
    patientRecordAutosaveInFlight = false;

    if (patientRecordAutosaveRequested && document.querySelector("#recordsInterface")?.isConnected) {
      schedulePatientRecordAutosave();
    }
  }
}

function getPatientDataRecordsStorageKey(targetPatientId = patientId) {
  return `${storageKeys.patientDataRecords}.${normalizePatientStorageId(targetPatientId)}`;
}

function getSelectedDataRecordStorageKey(targetPatientId = patientId) {
  return `${storageKeys.selectedDataRecord}.${normalizePatientStorageId(targetPatientId)}`;
}

function normalizePatientStorageId(value = patientId) {
  return String(value || defaultProfile.id)
    .toLowerCase()
    .replace(/[^a-z0-9_-]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 80) || defaultProfile.id;
}

function loadPatientDataRecords(targetPatientId = patientId) {
  const scopedRecords = loadJson(getPatientDataRecordsStorageKey(targetPatientId), null);

  if (Array.isArray(scopedRecords)) {
    return sortPatientDataRecords(scopedRecords);
  }

  const legacyRecords = normalizePatientStorageId(targetPatientId) === normalizePatientStorageId(defaultProfile.id)
    ? loadJson(storageKeys.patientDataRecords, [])
    : [];

  if (legacyRecords.length) {
    savePatientDataRecordsLocal(legacyRecords, targetPatientId, { skipOfflineSync: true });
  }

  return sortPatientDataRecords(legacyRecords);
}

function savePatientDataRecordsLocal(records = [], targetPatientId = patientId, options = {}) {
  saveJson(getPatientDataRecordsStorageKey(targetPatientId), sortPatientDataRecords(records), {
    targetPatientId,
    reason: "records-update",
    ...options
  });
}

function getSelectedPatientDataRecordId(targetPatientId = patientId) {
  return localStorage.getItem(getSelectedDataRecordStorageKey(targetPatientId))
    || (normalizePatientStorageId(targetPatientId) === normalizePatientStorageId(defaultProfile.id)
      ? localStorage.getItem(storageKeys.selectedDataRecord)
      : "")
    || "";
}

function setSelectedPatientDataRecordId(recordId = "", targetPatientId = patientId, options = {}) {
  const key = getSelectedDataRecordStorageKey(targetPatientId);

  if (recordId) {
    localStorage.setItem(key, recordId);
  } else {
    localStorage.removeItem(key);
  }

  if (normalizePatientStorageId(targetPatientId) === normalizePatientStorageId(defaultProfile.id)) {
    if (recordId) {
      localStorage.setItem(storageKeys.selectedDataRecord, recordId);
    } else {
      localStorage.removeItem(storageKeys.selectedDataRecord);
    }
  }

  if (!options.skipOfflineSync) {
    queueBrowserStateSync("record-selection-update", { targetPatientId });
  }
}

function refreshActivePatientRecordVault() {
  const records = document.querySelector("#recordsInterface");

  if (records) {
    records.dataset.selectedRecord = getSelectedPatientDataRecordId();
    records.dataset.formDirty = "false";
  }

  resetRecordRenderState();
  hydrateSelectedPatientRecordForm();
  renderPatientDataRecords({ force: true });
  syncPatientDataRecordsFromServer();
}

async function syncPatientDataRecordsFromServer() {
  const syncRequestId = ++recordServerSyncRequestId;
  const syncPatientId = patientId;

  if (isStaticRuntime()) {
    recordServerSyncStatus = {
      ...recordServerSyncStatus,
      state: "browser-only",
      message: "Saved privately on this device for GitHub/static mode.",
      file: "On-device local storage",
      updatedAt: new Date().toISOString()
    };
    renderPatientDataRecords();
    return;
  }

  recordServerSyncStatus = {
    ...recordServerSyncStatus,
    state: "syncing",
    message: "Checking localhost records store."
  };
  renderRecordStorageStats(loadPatientDataRecords());

  try {
    const response = await fetch(`/api/records?patientId=${encodeURIComponent(syncPatientId)}`);
    const payload = await response.json();

    if (syncRequestId !== recordServerSyncRequestId || syncPatientId !== patientId) {
      return;
    }

    if (!response.ok || !payload.ok) {
      throw new Error(payload.message || "Unable to load localhost records.");
    }

    const localRecords = loadPatientDataRecords();
    const serverRecords = Array.isArray(payload.records?.records) ? payload.records.records : [];
    const mergedRecords = mergePatientDataRecordSets(localRecords, serverRecords);
    const preferredSelectedRecordId = getSelectedPatientDataRecordId() || payload.records?.selectedRecordId || "";
    const selectedRecordId = mergedRecords.some((record) => record.id === preferredSelectedRecordId)
      ? preferredSelectedRecordId
      : mergedRecords[0]?.id || "";
    const needsServerUpdate = JSON.stringify(sortPatientDataRecords(serverRecords)) !== JSON.stringify(mergedRecords)
      || (selectedRecordId && selectedRecordId !== payload.records?.selectedRecordId);

    savePatientDataRecordsLocal(mergedRecords, syncPatientId, { skipOfflineSync: true });
    setSelectedPatientDataRecordId(selectedRecordId, syncPatientId, { skipOfflineSync: true });
    hydrateSelectedPatientRecordForm(selectedRecordId);

    recordServerSyncStatus = {
      state: "synced",
      message: mergedRecords.length
        ? "Stored on localhost server and mirrored on this device."
        : "Localhost records store is ready.",
      file: payload.records?.file || "data/records/patient-records.json",
      updatedAt: payload.records?.updatedAt || new Date().toISOString()
    };
    resetRecordRenderState();
    renderPatientDataRecords({ force: true });

    if (needsServerUpdate) {
      persistPatientDataRecords(mergedRecords, selectedRecordId);
    }
  } catch {
    if (syncRequestId !== recordServerSyncRequestId || syncPatientId !== patientId) {
      return;
    }

    recordServerSyncStatus = {
      ...recordServerSyncStatus,
      state: "browser-only",
      message: "Server sync unavailable; records are currently mirrored on this device.",
      updatedAt: new Date().toISOString()
    };
    renderPatientDataRecords();
  }
}

async function persistPatientDataRecords(records = loadPatientDataRecords(), selectedRecordId = getSelectedPatientDataRecordId() || "") {
  const syncRequestId = ++recordServerSyncRequestId;
  const syncPatientId = patientId;

  if (isStaticRuntime()) {
    savePatientDataRecordsLocal(records);
    setSelectedPatientDataRecordId(selectedRecordId);
    recordServerSyncStatus = {
      state: "browser-only",
      message: "Saved privately on this device for GitHub/static mode.",
      file: "On-device local storage",
      updatedAt: new Date().toISOString()
    };
    renderRecordStorageStats(records);
    renderPatientDataRecords();
    return;
  }

  recordServerSyncStatus = {
    ...recordServerSyncStatus,
    state: "saving",
    message: "Saving records to localhost server.",
    updatedAt: new Date().toISOString()
  };
  renderRecordStorageStats(records);

  try {
    const response = await fetch("/api/records", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        patientId: syncPatientId,
        records,
        selectedRecordId
      })
    });
    const payload = await response.json();

    if (syncRequestId !== recordServerSyncRequestId || syncPatientId !== patientId) {
      return;
    }

    if (!response.ok || !payload.ok) {
      throw new Error(payload.message || "Unable to save localhost records.");
    }

    const savedRecords = Array.isArray(payload.records?.records) ? payload.records.records : records;
    const savedSelectedId = savedRecords.some((record) => record.id === payload.records?.selectedRecordId)
      ? payload.records.selectedRecordId
      : savedRecords.some((record) => record.id === selectedRecordId)
        ? selectedRecordId
        : savedRecords[0]?.id || "";
    savePatientDataRecordsLocal(savedRecords, syncPatientId, { skipOfflineSync: true });
    setSelectedPatientDataRecordId(savedSelectedId, syncPatientId, { skipOfflineSync: true });
    hydrateSelectedPatientRecordForm(savedSelectedId);

    recordServerSyncStatus = {
      state: "synced",
      message: "Saved on localhost server and mirrored on this device.",
      file: payload.records?.file || "data/records/patient-records.json",
      updatedAt: payload.records?.updatedAt || new Date().toISOString()
    };
    resetRecordRenderState();
    renderPatientDataRecords({ force: true });
  } catch {
    if (syncRequestId !== recordServerSyncRequestId || syncPatientId !== patientId) {
      return;
    }

    recordServerSyncStatus = {
      ...recordServerSyncStatus,
      state: "browser-only",
      message: "Could not reach localhost records store; browser mirror is still available.",
      updatedAt: new Date().toISOString()
    };
    renderRecordStorageStats(records);
  }
}

function mergePatientDataRecordSets(localRecords = [], serverRecords = []) {
  const merged = new Map();

  for (const record of [...serverRecords, ...localRecords].map(normalizePatientDataRecordForClient)) {
    if (!record.id) {
      continue;
    }

    const existing = merged.get(record.id);
    if (!existing || new Date(record.updatedAt).getTime() >= new Date(existing.updatedAt).getTime()) {
      merged.set(record.id, record);
    }
  }

  return sortPatientDataRecords(Array.from(merged.values()));
}

function normalizePatientDataRecordForClient(record = {}) {
  const now = new Date().toISOString();

  return {
    id: String(record.id || `record-${Date.now()}`).trim(),
    createdAt: parseIsoDate(record.createdAt) || now,
    updatedAt: parseIsoDate(record.updatedAt) || now,
    patientName: String(record.patientName || "Patient").trim() || "Patient",
    age: String(record.age || "").trim(),
    type: String(record.type || "profile").trim() || "profile",
    date: String(record.date || formatDateForInput(new Date())).trim(),
    episode: String(record.episode || "").trim(),
    tags: parseRecordTags(record.tags),
    source: String(record.source || "").trim(),
    documentCategory: String(record.documentCategory || "").trim(),
    documentName: String(record.documentName || "").trim(),
    fileReferences: String(record.fileReferences || record.fileReference || "").trim(),
    conditions: String(record.conditions || "").trim(),
    allergies: String(record.allergies || "").trim(),
    medicines: String(record.medicines || "").trim(),
    vitals: String(record.vitals || "").trim(),
    labs: String(record.labs || "").trim(),
    notes: String(record.notes || "").trim(),
    followUp: String(record.followUp || "").trim(),
    versionNote: String(record.versionNote || "").trim(),
    correctionHistory: normalizeRecordCorrectionHistory(record.correctionHistory)
  };
}

function parseRecordTags(value) {
  if (Array.isArray(value)) {
    return value
      .flatMap((item) => parseRecordTags(item))
      .slice(0, 12);
  }

  return String(value || "")
    .split(/[,;\n]+/)
    .map((tag) => tag.trim().replace(/^#/, ""))
    .filter(Boolean)
    .map((tag) => tag.slice(0, 40))
    .filter((tag, index, list) => list.findIndex((item) => item.toLowerCase() === tag.toLowerCase()) === index)
    .slice(0, 12);
}

function formatRecordTags(tags) {
  return parseRecordTags(tags).join(", ");
}

function normalizeRecordCorrectionHistory(history) {
  if (!Array.isArray(history)) {
    return [];
  }

  return history
    .map((entry) => ({
      at: parseIsoDate(entry?.at) || new Date().toISOString(),
      note: String(entry?.note || "").trim().slice(0, 220),
      changes: Array.isArray(entry?.changes)
        ? entry.changes.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 8)
        : []
    }))
    .filter((entry) => entry.note || entry.changes.length)
    .slice(0, 10);
}

function buildRecordCorrectionHistory(previousRecord, nextRecord, { mode = "manual" } = {}) {
  const priorHistory = normalizeRecordCorrectionHistory(previousRecord?.correctionHistory);
  const changes = previousRecord ? getRecordChangedFields(previousRecord, nextRecord) : ["Record created"];
  const note = String(nextRecord.versionNote || "").trim();

  if (!previousRecord || note || changes.length) {
    const entry = {
      at: new Date().toISOString(),
      note: previousRecord
        ? mode === "auto"
          ? note
            ? `Autosaved: ${note}`
            : "Autosaved update"
          : note || "Record updated"
        : note || "Record created",
      changes: changes.slice(0, 8)
    };

    if (previousRecord && mode === "auto" && priorHistory[0]?.note === entry.note && entry.note.startsWith("Autosaved")) {
      return [entry, ...priorHistory.slice(1)].slice(0, 10);
    }

    return [entry, ...priorHistory].slice(0, 10);
  }

  return priorHistory;
}

function getRecordChangedFields(previousRecord = {}, nextRecord = {}) {
  const labels = {
    patientName: "patient name",
    age: "age",
    type: "record type",
    date: "record date",
    episode: "care episode",
    tags: "tags",
    source: "source",
    documentCategory: "document category",
    documentName: "document name",
    fileReferences: "file references",
    conditions: "conditions",
    allergies: "allergies",
    medicines: "medicines",
    vitals: "vitals",
    labs: "labs",
    notes: "notes",
    followUp: "follow-up"
  };

  return Object.entries(labels)
    .filter(([key]) => normalizeRecordComparableValue(previousRecord[key]) !== normalizeRecordComparableValue(nextRecord[key]))
    .map(([, label]) => label);
}

function normalizeRecordComparableValue(value) {
  return Array.isArray(value)
    ? value.map((item) => String(item || "").trim().toLowerCase()).sort().join("|")
    : String(value || "").trim().toLowerCase();
}

function sortPatientDataRecords(records = []) {
  return records
    .map(normalizePatientDataRecordForClient)
    .sort((a, b) => {
      const updatedDelta = new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime();
      if (updatedDelta) {
        return updatedDelta;
      }

      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
}

function parseIsoDate(value) {
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? "" : date.toISOString();
}

function normalizeRecordSearchQuery(value) {
  return String(value || "").trim().toLowerCase();
}

function buildRecordSearchText(record = {}) {
  return normalizeRecordSearchQuery([
    record.patientName,
    record.age,
    record.type,
    record.date,
    record.episode,
    formatRecordTags(record.tags),
    record.source,
    record.documentCategory,
    record.documentName,
    record.fileReferences,
    record.conditions,
    record.allergies,
    record.medicines,
    record.vitals,
    record.labs,
    record.notes,
    record.followUp,
    record.versionNote
  ].join(" "));
}

function getPatientDataRecordsSignature(records = []) {
  return records.map(getPatientDataRecordSignature).join("||");
}

function getPatientDataRecordSignature(record = {}) {
  return [
    record.id,
    record.updatedAt,
    record.createdAt,
    record.patientName,
    record.age,
    record.type,
    record.date,
    record.episode,
    formatRecordTags(record.tags),
    record.source,
    record.documentCategory,
    record.documentName,
    record.fileReferences,
    record.conditions,
    record.allergies,
    record.medicines,
    record.vitals,
    record.labs,
    record.notes,
    record.followUp,
    normalizeRecordCorrectionHistory(record.correctionHistory).length
  ].map((value) => String(value || "")).join("\u001f");
}

function getPatientDataRecordPreviewSignature(record = {}) {
  return [
    record.patientName,
    record.age,
    record.type,
    record.date,
    record.episode,
    formatRecordTags(record.tags),
    record.source,
    record.documentCategory,
    record.documentName,
    record.fileReferences,
    record.conditions,
    record.allergies,
    record.medicines,
    record.vitals,
    record.labs,
    record.notes,
    record.followUp
  ].map((value) => String(value || "")).join("\u001f");
}

function getRecordProfileSignature() {
  return [
    elements.profileName?.value,
    elements.profileAge?.value,
    elements.profileMeds?.value,
    elements.profileAllergies?.value
  ].map((value) => String(value || "")).join("\u001f");
}

function getRecordSyncStatusSignature() {
  return [
    recordServerSyncStatus.state,
    recordServerSyncStatus.message,
    recordServerSyncStatus.file,
    recordServerSyncStatus.updatedAt
  ].map((value) => String(value || "")).join("\u001f");
}

function shouldRenderRecordSection(key, signature, force = false) {
  if (force || recordRenderState[key] !== signature) {
    recordRenderState[key] = signature;
    return true;
  }

  return false;
}

function renderPatientDataRecords({ force = false } = {}) {
  const list = document.querySelector("#recordVaultList");
  const preview = document.querySelector("#recordPreview");
  const recordsRoot = document.querySelector("#recordsInterface");
  const records = loadPatientDataRecords();
  const localDataSnapshot = buildLocalDataSnapshot({
    patientId,
    profile: collectProfile(),
    records,
    history: loadHistory()
  });
  const search = normalizeRecordSearchQuery(document.querySelector("#recordSearchInput")?.value || "");
  let typeFilter = recordsRoot?.dataset.recordFilter || "all";
  const sortSelect = document.querySelector("#recordSortSelect");
  const sortMode = recordsRoot?.dataset.recordSort || sortSelect?.value || "newest";

  if (typeFilter !== "all" && !records.some((record) => record.type === typeFilter)) {
    typeFilter = "all";

    if (recordsRoot) {
      recordsRoot.dataset.recordFilter = "all";
    }
  }

  const selectedId = recordsRoot?.dataset.selectedRecord || getSelectedPatientDataRecordId();
  const blankDraft = recordsRoot?.dataset.blankDraft === "true";
  const selectedMatch = records.find((record) => record.id === selectedId) || null;
  const selected = selectedMatch || (blankDraft ? null : records[0] || null);
  const formDirty = recordsRoot?.dataset.formDirty === "true";
  const recordRows = records.map((record) => ({
    record,
    quality: computeRecordCompleteness(record),
    searchText: buildRecordSearchText(record)
  }));
  const filtered = sortPatientDataRecordRows(recordRows.filter(({ record, searchText }) => {
    if (typeFilter !== "all" && record.type !== typeFilter) {
      return false;
    }

    if (!search) {
      return true;
    }

    return searchText.includes(search);
  }), sortMode);
  const recordsSignature = getPatientDataRecordsSignature(records);
  const selectedSignature = selected ? getPatientDataRecordSignature(selected) : "none";
  const profileSignature = getRecordProfileSignature();
  const activeSelectedId = selected?.id || "";

  if (selectedId && selected?.id !== selectedId) {
    if (recordsRoot) {
      recordsRoot.dataset.selectedRecord = selected?.id || "";
    }

    setSelectedPatientDataRecordId(selected?.id || "");
  }

  if (list) {
    const listSignature = [
      recordsSignature,
      activeSelectedId,
      typeFilter,
      sortMode,
      search,
      filtered.map(({ record }) => record.id).join(",")
    ].join("||");

    if (force || recordRenderState.listSignature !== listSignature || !list.childElementCount) {
      const fragment = document.createDocumentFragment();

      if (!filtered.length) {
        const empty = document.createElement("li");
        empty.className = "record-empty-state";
        empty.textContent = records.length ? "No matching records found." : "No patient records saved yet.";
        fragment.append(empty);
      }

      for (const { record, quality } of filtered) {
        fragment.append(createPatientDataRecordRow(record, activeSelectedId, quality));
      }

      list.replaceChildren(fragment);
      recordRenderState.listSignature = listSignature;
    }
  }

  if (selected && !formDirty && !blankDraft && recordsRoot?.dataset.selectedRecord !== selected.id) {
    applyPatientDataRecord(selected);
    setSelectedPatientDataRecordId(selected.id);
  }

  if (shouldRenderRecordSection("filtersSignature", `${recordsSignature}||${typeFilter}`, force)) {
    renderRecordTypeFilters(records, typeFilter);
  }

  renderRecordBrowserControls(records.length, filtered.length, search, typeFilter, sortMode);

  renderPatientRecordPreview(formDirty ? collectPatientDataRecord() : selected, preview);

  if (shouldRenderRecordSection("packetSignature", `${recordsSignature}||${selectedSignature}`, force)) {
    renderRecordPacket(records, selected);
  }

  if (shouldRenderRecordSection("checklistSignature", `${recordsSignature}||${selectedSignature}||${profileSignature}`, force)) {
    renderRecordChecklist(selected, records);
  }

  if (shouldRenderRecordSection("storageSignature", `${recordsSignature}||${getRecordSyncStatusSignature()}||${localDataSnapshot.signature}`, force)) {
    renderRecordStorageStats(records, recordRows, localDataSnapshot);
  }

  if (shouldRenderRecordSection("downloadSignature", `${recordsSignature}||${selectedSignature}||${profileSignature}`, force)) {
    renderRecordDownloadPanel(records, selected);
  }

  if (shouldRenderRecordSection("intelligenceSignature", `${recordsSignature}||${selectedSignature}||${profileSignature}`, force)) {
    renderRecordIntelligence(records, selected);
  }

  if (shouldRenderRecordSection("episodesSignature", recordsSignature, force)) {
    renderRecordEpisodes(records);
  }

  if (shouldRenderRecordSection("documentsSignature", recordsSignature, force)) {
    renderRecordDocumentVault(records);
  }

  if (shouldRenderRecordSection("versionsSignature", selectedSignature, force)) {
    renderRecordVersionHistory(selected);
  }
}

function createPatientDataRecordRow(record, selectedRecordId = "", quality = computeRecordCompleteness(record)) {
  const row = document.createElement("li");
  const main = document.createElement("div");
  const title = document.createElement("strong");
  const detail = document.createElement("span");
  const meta = document.createElement("div");
  const actions = document.createElement("div");
  const open = document.createElement("button");
  const remove = document.createElement("button");

  row.dataset.recordType = record.type || "profile";
  row.classList.toggle("is-selected", record.id === selectedRecordId);
  title.textContent = `${record.patientName || "Patient"} - ${formatRecordType(record.type)}`;
  detail.textContent = `${formatStoredRecordDate(record.date)} - ${compactText(record.conditions || record.notes || record.medicines || record.labs || "Stored patient detail", 96)}`;
  meta.className = "record-row-meta";
  meta.append(
    createRecordMetaChip(`${quality.score}% complete`),
    createRecordMetaChip(record.episode || record.source || "Local entry"),
    createRecordMetaChip(record.documentCategory ? formatRecordDocumentCategory(record.documentCategory) : formatRecordTags(record.tags) || record.documentName || "No tag")
  );
  main.append(title, detail, meta);

  open.type = "button";
  open.dataset.openRecord = record.id;
  open.textContent = "Open";
  remove.type = "button";
  remove.dataset.deleteRecord = record.id;
  remove.textContent = "Delete";
  actions.append(open, remove);
  row.append(main, actions);
  return row;
}

function sortPatientDataRecordRows(rows, sortMode = "newest") {
  const getTime = (record) => {
    const date = new Date(record.date || record.updatedAt || record.createdAt || "");
    return Number.isNaN(date.getTime()) ? 0 : date.getTime();
  };
  const sorted = [...rows];

  sorted.sort((left, right) => {
    switch (sortMode) {
      case "oldest":
        return getTime(left.record) - getTime(right.record);
      case "needs-info":
        return left.quality.score - right.quality.score
          || getTime(right.record) - getTime(left.record);
      case "complete":
        return right.quality.score - left.quality.score
          || getTime(right.record) - getTime(left.record);
      case "type":
        return formatRecordType(left.record.type).localeCompare(formatRecordType(right.record.type))
          || getTime(right.record) - getTime(left.record);
      case "newest":
      default:
        return getTime(right.record) - getTime(left.record);
    }
  });

  return sorted;
}

function renderRecordBrowserControls(totalCount, visibleCount, search, typeFilter, sortMode) {
  const summary = document.querySelector("#recordResultSummary");
  const sortSelect = document.querySelector("#recordSortSelect");
  const clearButton = document.querySelector("#recordClearFiltersButton");
  const filterActive = typeFilter !== "all";
  const sortActive = sortMode !== "newest";
  const searchActive = Boolean(search);

  if (sortSelect && sortSelect.value !== sortMode) {
    sortSelect.value = sortMode;
  }

  if (clearButton) {
    clearButton.disabled = !filterActive && !sortActive && !searchActive;
  }

  if (summary) {
    const activeParts = [
      searchActive ? "search" : "",
      filterActive ? formatRecordType(typeFilter) : "",
      sortActive ? formatRecordSortLabel(sortMode) : ""
    ].filter(Boolean);
    const filterDetail = activeParts.length ? ` with ${activeParts.join(", ")}` : "";

    summary.textContent = totalCount
      ? `Showing ${visibleCount} of ${totalCount} records${filterDetail}.`
      : "No saved records yet. Add a record to start the patient vault.";
  }
}

function formatRecordSortLabel(value) {
  const labels = {
    newest: "newest first",
    oldest: "oldest first",
    "needs-info": "needs info first",
    complete: "most complete first",
    type: "type A-Z"
  };

  return labels[value] || labels.newest;
}

function renderPatientRecordPreview(record, preview = document.querySelector("#recordPreview")) {
  if (!preview) {
    return;
  }

  if (!record) {
    if (recordRenderState.previewSignature === "empty" && preview.childElementCount) {
      return;
    }

    clearNode(preview);
    const title = document.createElement("strong");
    const detail = document.createElement("span");

    title.textContent = "No record selected";
    detail.textContent = "Save or open a record to view stored patient details.";
    preview.append(title, detail);
    recordRenderState.previewSignature = "empty";
    return;
  }

  const previewSignature = getPatientDataRecordPreviewSignature(record);

  if (recordRenderState.previewSignature === previewSignature && preview.childElementCount) {
    return;
  }

  clearNode(preview);
  recordRenderState.previewSignature = previewSignature;

  const fields = [
    ["Patient", `${record.patientName || "Patient"}${record.age ? `, ${record.age}` : ""}`],
    ["Type", formatRecordType(record.type)],
    ["Date", formatStoredRecordDate(record.date)],
    ["Care episode", record.episode],
    ["Tags", formatRecordTags(record.tags)],
    ["Source", record.source],
    ["Document category", formatRecordDocumentCategory(record.documentCategory)],
    ["Document", record.documentName],
    ["File references", record.fileReferences],
    ["Conditions", record.conditions],
    ["Allergies / alerts", record.allergies],
    ["Medicines", record.medicines],
    ["Vitals", record.vitals],
    ["Labs / documents", record.labs],
    ["Notes", record.notes],
    ["Follow-up", record.followUp]
  ].filter(([, value]) => value);

  for (const [label, value] of fields) {
    const item = document.createElement("article");
    const title = document.createElement("strong");
    const detail = document.createElement("span");

    title.textContent = label;
    detail.textContent = value;
    item.append(title, detail);
    preview.append(item);
  }
}

function hasMeaningfulLocalDraft(value) {
  if (Array.isArray(value)) {
    return value.some((item) => hasMeaningfulLocalDraft(item));
  }

  if (value && typeof value === "object") {
    return Object.values(value).some((item) => hasMeaningfulLocalDraft(item));
  }

  if (typeof value === "boolean") {
    return value;
  }

  if (typeof value === "number") {
    return Number.isFinite(value) && value !== 0;
  }

  return Boolean(String(value || "").trim());
}

function loadLocalTextValue(key) {
  try {
    return localStorage.getItem(key) || "";
  } catch {
    return "";
  }
}

function formatLocalDraftLabel(key = "") {
  const labels = {
    advisor: "General",
    specialist: "Specialist",
    labs: "Labs",
    insurance: "Insurance",
    summary: "Summary",
    visits: "Visits",
    visit: "Visits",
    medicine: "Medicine",
    medications: "Medicine",
    vitals: "Vitals",
    wellness: "Wellness",
    records: "Records",
    profile: "Profile",
    atlas: "Atlas",
    safety: "Safety"
  };
  const normalized = String(key || "").trim().toLowerCase();

  if (labels[normalized]) {
    return labels[normalized];
  }

  return String(key || "Draft")
    .replace(/([a-z])([A-Z])/g, "$1 $2")
    .replace(/[-_]+/g, " ")
    .trim()
    .split(/\s+/)
    .filter(Boolean)
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(" ") || "Draft";
}

function buildLocalDraftLabels(targetPatientId = patientId) {
  const labels = new Set();
  const workspaceDrafts = loadJson(storageKeys.workspaceDrafts, {});

  if (workspaceDrafts && typeof workspaceDrafts === "object") {
    for (const [key, value] of Object.entries(workspaceDrafts)) {
      if (hasMeaningfulLocalDraft(value)) {
        labels.add(formatLocalDraftLabel(key));
      }
    }
  }

  const extraDrafts = [
    ["Lab report", loadLocalTextValue(storageKeys.labReportDraft)],
    ["Visit plan", loadJson(storageKeys.visitDraft, null)],
    ["Medicine review", loadJson(storageKeys.medicineDraft, {})],
    ["Vitals session", loadJson(getVitalsDraftStorageKey(targetPatientId), {})],
    ["Vitals baseline", loadJson(getVitalsBaselineStorageKey(targetPatientId), {})],
    ["Wellness check-in", loadJson(storageKeys.wellnessDraft, {})]
  ];

  for (const [label, value] of extraDrafts) {
    if (hasMeaningfulLocalDraft(value)) {
      labels.add(label);
    }
  }

  return [...labels].sort((left, right) => left.localeCompare(right));
}

function buildLocalDataSnapshot({
  patientId: targetPatientId = patientId,
  profile = collectProfile(),
  records = loadPatientDataRecords(targetPatientId),
  history = loadHistory(targetPatientId)
} = {}) {
  const recordItems = Array.isArray(records) ? records : [];
  const historyItems = Array.isArray(history) ? history : [];
  const labReports = typeof loadLabReportsVault === "function" ? loadLabReportsVault(targetPatientId) : [];
  const vitalsTrend = typeof loadVitalsTrendLog === "function" ? loadVitalsTrendLog(targetPatientId) : [];
  const medicineEntries = typeof loadMedicineVault === "function" ? loadMedicineVault(targetPatientId) : [];
  const profileKey = normalizePatientStorageId(profile?.name || targetPatientId);
  const insuranceCases = typeof loadInsuranceCases === "function"
    ? loadInsuranceCases().filter((item) => {
      const memberKey = normalizePatientStorageId(item?.memberName || "");
      return !memberKey || memberKey === profileKey || memberKey === normalizePatientStorageId(targetPatientId);
    })
    : [];
  const documents = typeof getDocumentRecords === "function" ? getDocumentRecords(recordItems) : [];
  const draftLabels = buildLocalDraftLabels(targetPatientId);
  const typeCounts = recordItems.reduce((map, record) => {
    const type = record?.type || "profile";
    map[type] = (map[type] || 0) + 1;
    return map;
  }, {});
  const typeHighlights = Object.entries(typeCounts)
    .sort((left, right) => right[1] - left[1] || left[0].localeCompare(right[0]))
    .slice(0, 3)
    .map(([type, count]) => `${count} ${formatRecordType(type)}`);
  const activities = [
    ...recordItems.map((record) => ({
      label: `${formatRecordType(record.type)} record`,
      at: record.updatedAt || record.createdAt || record.date
    })),
    ...historyItems.map((entry) => ({
      label: "Care check",
      at: entry.at
    })),
    ...labReports.map((report) => ({
      label: `${getLabPanelLabel(report.panel)} lab`,
      at: report.updatedAt || report.createdAt || report.reportDate
    })),
    ...vitalsTrend.map((entry) => ({
      label: "Vitals trend",
      at: entry.updatedAt || entry.createdAt || entry.date
    })),
    ...medicineEntries.map((entry) => ({
      label: "Medicine entry",
      at: entry.updatedAt || entry.createdAt || entry.date
    })),
    ...insuranceCases.map((entry) => ({
      label: `${formatInsuranceClaimType(entry.claimType)} claim`,
      at: entry.updatedAt || entry.createdAt || entry.serviceDate
    }))
  ]
    .map((entry) => {
      const at = String(entry?.at || "").trim();
      const time = at ? new Date(at).getTime() : Number.NaN;
      return Number.isFinite(time) ? { ...entry, at, time } : null;
    })
    .filter(Boolean)
    .sort((left, right) => right.time - left.time);
  const latestActivity = activities[0] || null;
  const earliestActivity = activities.at(-1) || null;
  const signature = [
    buildPatientLabel(profile),
    recordItems.length,
    historyItems.length,
    labReports.length,
    vitalsTrend.length,
    medicineEntries.length,
    insuranceCases.length,
    documents.length,
    draftLabels.join(","),
    typeHighlights.join(","),
    latestActivity?.at || "",
    earliestActivity?.at || ""
  ].join("||");

  return {
    profile,
    records: recordItems,
    history: historyItems,
    labReports,
    vitalsTrend,
    medicineEntries,
    insuranceCases,
    documents,
    draftLabels,
    typeHighlights,
    latestActivity,
    earliestActivity,
    signature
  };
}

function loadVisitQueueForPatient(targetPatientId = patientId, profile = null) {
  const activeProfile = profile || collectProfile();
  const patientKey = normalizePatientStorageId(activeProfile?.name || targetPatientId);
  const fallbackKey = normalizePatientStorageId(targetPatientId);

  return loadVisitQueue().filter((item) => {
    const visitPatient = String(item?.patient || "").trim();
    const visitKey = visitPatient ? normalizePatientStorageId(visitPatient) : "";
    return !visitKey || visitKey === patientKey || visitKey === fallbackKey;
  });
}

function readStoredSelectionValue(key) {
  try {
    return localStorage.getItem(key) || "";
  } catch {
    return "";
  }
}

function loadOfflineSyncQueue() {
  const queue = loadJson(storageKeys.offlineSyncQueue, []);

  return Array.isArray(queue)
    ? queue
      .filter((entry) => entry && entry.patientId)
      .map((entry) => ({
        patientId: normalizePatientStorageId(entry.patientId),
        reason: String(entry.reason || "local-data-update").slice(0, 80),
        queuedAt: entry.queuedAt || new Date().toISOString(),
        updatedAt: entry.updatedAt || entry.queuedAt || new Date().toISOString()
      }))
      .slice(0, 12)
    : [];
}

function saveOfflineSyncQueue(entries = []) {
  saveJson(storageKeys.offlineSyncQueue, entries.slice(0, 12), { skipOfflineSync: true });
}

function loadCachedRuntimeSnapshot(key) {
  const cached = loadJson(key, null);
  const payload = cached?.payload;

  if (!payload || typeof payload !== "object") {
    return null;
  }

  return {
    ...payload,
    cached: true,
    cachedAt: cached.savedAt || ""
  };
}

function saveCachedRuntimeSnapshot(key, payload) {
  if (!payload || typeof payload !== "object") {
    return;
  }

  saveJson(key, {
    savedAt: new Date().toISOString(),
    payload
  }, { skipOfflineSync: true });
}

function buildBrowserStateSyncPayload(targetPatientId = patientId, reason = "local-data-update") {
  const normalizedTarget = normalizePatientStorageId(targetPatientId);
  const patientProfiles = loadPatientRecords();
  const activeProfile = normalizedTarget === normalizePatientStorageId(patientId)
    ? collectProfile()
    : patientProfiles.find((record) => normalizePatientStorageId(record.id) === normalizedTarget)
      || patientProfiles[0]
      || { ...defaultProfile, id: targetPatientId };
  const history = loadHistory(targetPatientId);
  const records = loadPatientDataRecords(targetPatientId);
  const snapshot = buildLocalDataSnapshot({
    patientId: targetPatientId,
    profile: activeProfile,
    records,
    history
  });
  const medicineSideEffects = loadMedicineSideEffects(targetPatientId);
  const visitQueue = loadVisitQueueForPatient(targetPatientId, activeProfile);
  const wellnessProgress = loadWellnessProgress(targetPatientId);
  const safetyEvents = loadSafetyEvents(targetPatientId);

  return {
    patientId: targetPatientId,
    profile: activeProfile,
    history: history.slice(0, 24),
    snapshot: {
      activePatientId: loadJson(storageKeys.activePatientId, defaultProfile.id),
      selectedRecordId: getSelectedPatientDataRecordId(targetPatientId),
      selectedInsuranceCaseId: readStoredSelectionValue(storageKeys.selectedInsuranceCase),
      privacyMode: loadJson(storageKeys.localPrivacyMode, null),
      patientProfiles,
      summary: {
        signature: snapshot.signature,
        recordCount: records.length,
        historyCount: history.length,
        labReportCount: snapshot.labReports.length,
        vitalsTrendCount: snapshot.vitalsTrend.length,
        medicineEntryCount: snapshot.medicineEntries.length,
        medicineSideEffectCount: medicineSideEffects.length,
        insuranceCaseCount: snapshot.insuranceCases.length,
        visitQueueCount: visitQueue.length,
        wellnessEntryCount: wellnessProgress.length,
        safetyEventCount: safetyEvents.length,
        patientProfileCount: patientProfiles.length,
        documentCount: snapshot.documents.length,
        draftLabels: snapshot.draftLabels,
        typeHighlights: snapshot.typeHighlights,
        latestActivity: snapshot.latestActivity,
        earliestActivity: snapshot.earliestActivity
      },
      labReports: snapshot.labReports,
      vitalsTrend: snapshot.vitalsTrend,
      medicineEntries: snapshot.medicineEntries,
      medicineSideEffects,
      insuranceCases: snapshot.insuranceCases,
      visitQueue,
      wellnessProgress,
      safetyEvents,
      drafts: {
        workspaceDrafts: loadJson(storageKeys.workspaceDrafts, {}),
        labReportText: loadLocalTextValue(storageKeys.labReportDraft),
        labReportContext: loadJson(storageKeys.labReportContext, {}),
        visitDraft: loadJson(storageKeys.visitDraft, null),
        medicineDraft: loadJson(storageKeys.medicineDraft, {}),
        vitalsDraft: loadJson(getVitalsDraftStorageKey(targetPatientId), {}),
        vitalsBaseline: loadJson(getVitalsBaselineStorageKey(targetPatientId), {}),
        wellnessDraft: loadJson(storageKeys.wellnessDraft, {})
      }
    },
    metadata: {
      reason,
      queuedAt: new Date().toISOString(),
      connectivityMode: connectivityState.mode,
      browserOnline: getBrowserOnline(),
      serviceWorkerReady: hasServiceWorkerAppShell(),
      installed: isStandaloneApp()
    }
  };
}

function queueBrowserStateSync(reason = "local-data-update", options = {}) {
  if (isStaticRuntime()) {
    return [];
  }

  const targetPatientId = normalizePatientStorageId(
    options.targetPatientId
      || loadJson(storageKeys.activePatientId, patientId)
      || patientId
      || defaultProfile.id
  );
  const now = new Date().toISOString();
  const queue = loadOfflineSyncQueue();
  const existing = queue.find((entry) => normalizePatientStorageId(entry.patientId) === targetPatientId);
  const nextQueue = [
    {
      patientId: targetPatientId,
      reason: String(reason || existing?.reason || "local-data-update").slice(0, 80),
      queuedAt: existing?.queuedAt || now,
      updatedAt: now
    },
    ...queue.filter((entry) => normalizePatientStorageId(entry.patientId) !== targetPatientId)
  ].slice(0, 12);

  saveOfflineSyncQueue(nextQueue);

  if (connectivityState.serverOnline && getBrowserOnline()) {
    scheduleBrowserStateSyncFlush({
      reason,
      delayMs: offlineSyncFlushDebounceMs
    });
  }

  return nextQueue;
}

function scheduleBrowserStateSyncFlush(options = {}) {
  const { delayMs = offlineSyncFlushDebounceMs } = options;

  if (isStaticRuntime() || !connectivityState.serverOnline || !getBrowserOnline()) {
    return;
  }

  window.clearTimeout(offlineSyncFlushTimer);
  offlineSyncFlushTimer = window.setTimeout(() => {
    offlineSyncFlushTimer = null;
    void flushBrowserStateSyncQueue(options);
  }, delayMs);
}

async function flushBrowserStateSyncQueue(options = {}) {
  if (offlineSyncFlushPromise) {
    return offlineSyncFlushPromise;
  }

  if (isStaticRuntime() || !connectivityState.serverOnline || !getBrowserOnline()) {
    return null;
  }

  const queue = loadOfflineSyncQueue();

  if (!queue.length) {
    return {
      ok: true,
      syncedCount: 0,
      remainingCount: 0
    };
  }

  offlineSyncFlushPromise = (async () => {
    let remaining = queue.slice();
    let syncedCount = 0;

    for (const entry of queue) {
      try {
        const response = await fetch("/api/browser-state-sync", {
          method: "POST",
          headers: {
            "Content-Type": "application/json"
          },
          body: JSON.stringify(
            buildBrowserStateSyncPayload(
              entry.patientId,
              entry.reason || options.reason || "queued-browser-state"
            )
          )
        });
        const payload = await response.json();

        if (!response.ok || !payload.ok) {
          throw new Error(payload.message || "Browser recovery sync unavailable.");
        }

        syncedCount += 1;
        remaining = remaining.filter(
          (item) => normalizePatientStorageId(item.patientId) !== normalizePatientStorageId(entry.patientId)
        );
        saveOfflineSyncQueue(remaining);
      } catch {
        break;
      }
    }

    return {
      ok: remaining.length === 0,
      syncedCount,
      remainingCount: remaining.length
    };
  })().finally(() => {
    offlineSyncFlushPromise = null;
  });

  return offlineSyncFlushPromise;
}

function renderRecordLocalDataSummary(snapshot = buildLocalDataSnapshot()) {
  const summary = document.querySelector("#recordLocalDataSummary");

  if (!summary) {
    return;
  }

  clearNode(summary);

  const cards = [
    {
      title: "Active patient",
      value: buildPatientLabel(snapshot.profile)
    },
    {
      title: "Local memory",
      value: [
        `${snapshot.records.length} record${snapshot.records.length === 1 ? "" : "s"}`,
        `${snapshot.history.length} check${snapshot.history.length === 1 ? "" : "s"}`,
        `${snapshot.documents.length} document${snapshot.documents.length === 1 ? "" : "s"}`
      ].join(", ")
    },
    {
      title: "Saved vaults",
      value: [
        snapshot.labReports.length ? `${snapshot.labReports.length} lab${snapshot.labReports.length === 1 ? "" : "s"}` : "",
        snapshot.vitalsTrend.length ? `${snapshot.vitalsTrend.length} vitals trend${snapshot.vitalsTrend.length === 1 ? "" : "s"}` : "",
        snapshot.medicineEntries.length ? `${snapshot.medicineEntries.length} medicine entr${snapshot.medicineEntries.length === 1 ? "y" : "ies"}` : "",
        snapshot.insuranceCases.length ? `${snapshot.insuranceCases.length} claim${snapshot.insuranceCases.length === 1 ? "" : "s"}` : ""
      ].filter(Boolean).join(", ") || "No lab, medicine, vitals, or claim vault data yet."
    },
    {
      title: "Open drafts",
      value: snapshot.draftLabels.length
        ? compactText(snapshot.draftLabels.join(", "), 86)
        : "No active drafts."
    },
    {
      title: "Latest item",
      value: snapshot.latestActivity
        ? `${snapshot.latestActivity.label} on ${formatRecordUpdatedAt(snapshot.latestActivity.at)}`
        : "No recent local activity."
    },
    {
      title: "Coverage window",
      value: snapshot.earliestActivity && snapshot.latestActivity
        ? snapshot.earliestActivity.at === snapshot.latestActivity.at
          ? formatRecordUpdatedAt(snapshot.latestActivity.at)
          : `${formatRecordUpdatedAt(snapshot.earliestActivity.at)} to ${formatRecordUpdatedAt(snapshot.latestActivity.at)}`
        : "No dated local activity yet."
    }
  ];

  for (const card of cards) {
    const article = document.createElement("article");
    const title = document.createElement("strong");
    const value = document.createElement("span");

    title.textContent = card.title;
    value.textContent = card.value;
    article.append(title, value);
    summary.append(article);
  }
}

function renderRecordStorageStats(records, recordRows = null, snapshot = buildLocalDataSnapshot({ records })) {
  const patientNames = new Set(records.map((record) => (record.patientName || "").toLowerCase()).filter(Boolean));
  const types = new Set(records.map((record) => record.type).filter(Boolean));
  const raw = JSON.stringify(records);
  const quality = records.length
    ? Math.round((recordRows || records.map((record) => ({ quality: computeRecordCompleteness(record) }))).reduce((sum, row) => sum + row.quality.score, 0) / records.length)
    : 0;
  const latest = records
    .map((record) => record.updatedAt || record.createdAt || record.date)
    .filter(Boolean)
    .sort()
    .at(-1);

  const total = document.querySelector("#recordTotalCount");
  const patientCount = document.querySelector("#recordPatientCount");
  const typeCount = document.querySelector("#recordTypeCount");
  const qualityScore = document.querySelector("#recordQualityScore");
  const size = document.querySelector("#recordStorageSize");
  const meter = document.querySelector("#recordStorageMeter");
  const lastUpdated = document.querySelector("#recordLastUpdated");

  if (total) total.textContent = String(records.length);
  if (patientCount) patientCount.textContent = String(patientNames.size);
  if (typeCount) typeCount.textContent = String(types.size);
  if (qualityScore) qualityScore.textContent = `${quality}%`;
  if (size) size.textContent = `${Math.max(1, Math.ceil(raw.length / 1024))} KB`;
  if (lastUpdated) {
    const syncDetail = recordServerSyncStatus.state === "synced"
      ? `Stored on localhost server at ${recordServerSyncStatus.file}.`
      : recordServerSyncStatus.message;
    const latestDetail = snapshot.latestActivity
      ? `Latest local item: ${snapshot.latestActivity.label} on ${formatRecordUpdatedAt(snapshot.latestActivity.at)}.`
      : latest
        ? `Last updated ${formatRecordUpdatedAt(latest)}.`
        : "No local patient data saved yet.";
    const coverageDetail = snapshot.earliestActivity && snapshot.latestActivity && snapshot.earliestActivity.at !== snapshot.latestActivity.at
      ? ` Coverage window: ${formatRecordUpdatedAt(snapshot.earliestActivity.at)} to ${formatRecordUpdatedAt(snapshot.latestActivity.at)}.`
      : "";
    lastUpdated.textContent = `${latestDetail}${coverageDetail} ${syncDetail || "No cloud upload or external sharing is performed."}`.trim();
  }

  if (meter) {
    meter.style.setProperty("--record-fill", `${quality}%`);
  }

  renderRecordLocalDataSummary(snapshot);
}

function renderRecordDownloadPanel(records, selected) {
  const summary = document.querySelector("#recordDownloadSummary");
  const status = document.querySelector("#recordDownloadStatus");
  const csvButton = document.querySelector("#recordDownloadCsv");
  const profile = collectProfile();
  const latest = records
    .map((record) => record.updatedAt || record.createdAt || record.date)
    .filter(Boolean)
    .sort()
    .at(-1);

  if (summary) {
    clearNode(summary);

    const facts = [
      ["Current patient", `${profile.name || "Patient"}${profile.age ? `, ${profile.age}` : ""}`],
      ["Saved records", `${records.length}`],
      ["Selected record", selected ? formatRecordType(selected.type) : "None"],
      ["Latest update", latest ? formatRecordUpdatedAt(latest) : "No records yet"]
    ];

    for (const [label, value] of facts) {
      const item = document.createElement("article");
      const title = document.createElement("strong");
      const detail = document.createElement("span");

      title.textContent = label;
      detail.textContent = value;
      item.append(title, detail);
      summary.append(item);
    }
  }

  if (csvButton) {
    csvButton.disabled = !records.length;
  }

  if (status) {
    status.textContent = records.length
      ? "Downloads include this patient's profile, local vault records, recent checks, and selected record only."
      : "Full report can still download the patient profile; save records to enable CSV export.";
  }
}

function openPatientDataRecord(id) {
  const record = loadPatientDataRecords().find((item) => item.id === id);

  if (!record) {
    return;
  }

  setSelectedPatientDataRecordId(record.id);
  applyPatientDataRecord(record);
  renderPatientDataRecords({ force: true });
}

function deleteSelectedPatientRecord() {
  const id = document.querySelector("#recordsInterface")?.dataset.selectedRecord || "";

  if (id) {
    deletePatientDataRecord(id);
  }
}

function deletePatientDataRecord(id) {
  const nextRecords = loadPatientDataRecords().filter((record) => record.id !== id);
  const nextSelectedId = nextRecords[0]?.id || "";

  savePatientDataRecordsLocal(nextRecords);
  setSelectedPatientDataRecordId(nextSelectedId);

  if (nextSelectedId) {
    applyPatientDataRecord(nextRecords[0]);
  } else {
    clearPatientRecordForm({ render: false });
    hydrateSelectedPatientRecordForm("");
  }

  resetRecordRenderState();
  renderPatientDataRecords({ force: true });
  persistPatientDataRecords(nextRecords, nextSelectedId);
}

function clearPatientRecordForm({ render = true, preserveSelected = false } = {}) {
  const records = document.querySelector("#recordsInterface");

  clearPatientRecordValidation();

  for (const selector of ["#recordPatientName", "#recordPatientAge", "#recordEpisode", "#recordTags", "#recordSource", "#recordDocumentName", "#recordFileReference", "#recordConditions", "#recordAllergies", "#recordMedicines", "#recordVitals", "#recordLabs", "#recordNotes", "#recordFollowUp", "#recordVersionNote"]) {
    const control = document.querySelector(selector);

    if (control) {
      control.value = "";
    }
  }

  const type = document.querySelector("#recordType");
  const documentCategory = document.querySelector("#recordDocumentCategory");
  const fileInput = document.querySelector("#recordFileInput");
  const deleteButton = document.querySelector("#recordDeleteButton");

  if (type) type.selectedIndex = 0;
  if (documentCategory) documentCategory.selectedIndex = 0;
  if (fileInput) fileInput.value = "";
  updateRecordFileSelectionSummary();
  if (records) {
    if (!preserveSelected) {
      records.dataset.selectedRecord = "";
      records.dataset.blankDraft = "true";
    }
    records.dataset.formDirty = "false";
    records.dataset.formHydrated = "false";
  }
  if (deleteButton) deleteButton.disabled = true;

  setDefaultRecordDate();
  resetRecordRenderState();
  markPatientDataRecordFormSaved();

  if (render) {
    renderPatientRecordPreview(null);
  }
}

