  const notes = document.querySelector("#recordNotes");

  if (name) name.value = elements.profileName?.value || defaultProfile.name;
  if (age) age.value = elements.profileAge?.value || defaultProfile.age;
  if (conditions) conditions.value = elements.profileConditions?.value || defaultProfile.conditions;
  if (medicines) medicines.value = elements.profileMeds?.value || defaultProfile.medications;
  if (allergies) allergies.value = elements.profileAllergies?.value || defaultProfile.allergies || "";
