function formatRecordType(value) {
  const labels = {
    profile: "Profile details",
    visit: "Visit note",
    vitals: "Vitals reading",
    labs: "Lab report note",
    medicine: "Medicine record",
    allergy: "Allergy / alert",
    imaging: "Imaging note",
    procedure: "Procedure / surgery",
    immunization: "Vaccination record",
    "care-plan": "Care plan",
    insurance: "Insurance record",
    discharge: "Discharge note",
    document: "Document note"
  };

  return labels[value] || "Profile details";
}

function formatStoredRecordDate(value) {
  const date = parseInputDate(value);

  return date ? date.toLocaleDateString([], { month: "short", day: "numeric", year: "numeric" }) : "No date";
}

function createRecordMetaChip(text) {
  const chip = document.createElement("em");
  chip.textContent = compactText(text || "Local entry", 28);
  return chip;
}

function computeRecordCompleteness(record = {}) {
  const hasAny = (...keys) => keys.some((key) => String(record[key] || "").trim());
  const hasTags = parseRecordTags(record.tags).length > 0;
  const checks = [
    ["patientName", "patient name", hasAny("patientName")],
    ["age", "age", hasAny("age")],
    ["type", "record type", hasAny("type")],
    ["date", "record date", hasAny("date")],
    ["source", "care source", hasAny("source")],
    ["episode", "care episode or tags", hasAny("episode") || hasTags],
    ["safety", "medicine, allergy, or condition context", hasAny("conditions", "allergies", "medicines")],
    ["clinical", "clinical details or notes", hasAny("vitals", "labs", "notes", "followUp")]
  ];
  const documentTypes = new Set(["labs", "imaging", "discharge", "document", "insurance", "procedure", "immunization"]);

  if (documentTypes.has(record.type) || record.documentCategory || record.documentName || record.fileReferences) {
    checks.push(
      ["documentCategory", "document category", hasAny("documentCategory") || hasAny("type")],
      ["documentName", "document name", hasAny("documentName")],
      ["fileReferences", "file reference or storage location", hasAny("fileReferences") || hasAny("labs")]
    );
  }

  if (record.type === "medicine") {
    checks.push(
      ["medicines", "medicine name", hasAny("medicines")],
      ["followUp", "pharmacist or clinician question", hasAny("followUp", "notes")]
    );
  }

  if (record.type === "vitals") {
    checks.push(
      ["vitals", "reading values", hasAny("vitals")],
      ["notes", "reading context", hasAny("notes", "followUp")]
    );
  }

  if (record.type === "allergy") {
    checks.push(["allergies", "reaction or alert detail", hasAny("allergies", "notes")]);
  }

  const filled = checks.filter(([, , ok]) => ok).length;
  const missing = checks.filter(([, , ok]) => !ok).map(([, label]) => label);

  return {
    score: Math.round((filled / checks.length) * 100),
    missing
  };
}

function formatRecordDocumentCategory(value) {
  const labels = {
    prescription: "Prescription",
    "lab-report": "Lab report",
    "discharge-summary": "Discharge summary",
    "imaging-report": "Imaging report",
    "insurance-paper": "Insurance paper",
    "doctor-note": "Doctor note",
    vaccination: "Vaccination record",
    "other-document": "Other document"
  };

  return labels[value] || "";
}

function renderRecordIntelligence(records, selected) {
  const grid = document.querySelector("#recordReadinessGrid");
  const alerts = document.querySelector("#recordAlertList");

  if (grid) {
    clearNode(grid);
    for (const item of buildRecordReadinessFactors(records, selected)) {
      grid.append(createRecordReadinessCard(item));
    }
  }

  if (alerts) {
    renderDashboardList(alerts, buildRecordAlertItems(records, selected));
  }
}

function buildRecordReadinessFactors(records, selected) {
  const profile = collectProfile();
  const latest = getLatestRecordDate(records);
  const documents = getDocumentRecords(records);
  const selectedQuality = selected ? computeRecordCompleteness(selected).score : 0;
  const safetyReady = Boolean(profile.allergies || records.some((record) => record.allergies));
  const medicineReady = Boolean(profile.medications || records.some((record) => record.medicines));
  const followUpReady = records.some((record) => record.followUp);
  const shareScore = Math.round([
    profile.name && profile.age ? 100 : 45,
    safetyReady ? 100 : 45,
    medicineReady ? 100 : 55,
    records.length ? 100 : 30,
    documents.length ? 100 : 55,
    followUpReady ? 100 : 65,
    selectedQuality || 55
  ].reduce((sum, score) => sum + score, 0) / 7);

  return [
    {
      label: "Share readiness",
      value: `${shareScore}%`,
      detail: shareScore >= 82 ? "Doctor packet is well prepared." : "Add missing context before sharing.",
      level: shareScore >= 82 ? "low" : shareScore >= 62 ? "medium" : "high"
    },
    {
      label: "Selected record",
      value: selected ? `${selectedQuality}%` : "None",
      detail: selected ? `${formatRecordType(selected.type)} quality` : "Open or save a record.",
      level: selectedQuality >= 82 ? "low" : selectedQuality >= 55 ? "medium" : "high"
    },
    {
      label: "Documents",
      value: String(documents.length),
      detail: documents.length ? "Reports and file references indexed." : "Add report or prescription details.",
      level: documents.length ? "low" : "medium"
    },
    {
      label: "Latest update",
      value: latest ? formatRecordUpdatedAt(latest) : "No record",
      detail: latest ? "Timeline available." : "Start a local patient timeline.",
      level: latest ? "low" : "medium"
    }
  ];
}

function createRecordReadinessCard(item) {
  const card = document.createElement("article");
  const label = document.createElement("span");
  const value = document.createElement("strong");
  const detail = document.createElement("small");

  card.dataset.level = item.level || "none";
  label.textContent = item.label;
  value.textContent = item.value;
  detail.textContent = item.detail;
  card.append(label, value, detail);
  return card;
}

function buildRecordAlertItems(records, selected) {
  const profile = collectProfile();
  const selectedQuality = selected ? computeRecordCompleteness(selected) : null;
  const hasAllergy = Boolean(profile.allergies || records.some((record) => record.allergies));
  const hasMedicine = Boolean(profile.medications || records.some((record) => record.medicines));
  const hasFollowUp = records.some((record) => record.followUp);
  const hasDocuments = getDocumentRecords(records).length > 0;
  const latest = getLatestRecordDate(records);
  const stale = latest ? (Date.now() - new Date(latest).getTime()) > 1000 * 60 * 60 * 24 * 90 : false;
  const alerts = [];

  if (!records.length) {
    alerts.push({ title: "Start the vault", detail: "Save the first profile, medicine, lab, visit, or vitals record.", level: "medium" });
  }

  if (selectedQuality?.missing?.length) {
    alerts.push({
      title: "Selected record gap",
      detail: `Add ${selectedQuality.missing.slice(0, 4).join(", ")}.`,
      level: selectedQuality.score >= 70 ? "medium" : "high"
    });
  }

  if (!hasAllergy) {
    alerts.push({ title: "Allergy status missing", detail: "Record allergies, intolerances, or clearly mark none known.", level: "high" });
  }

  if (!hasMedicine) {
    alerts.push({ title: "Medicine list missing", detail: "Add active medicines, supplements, or no-current-medicine status.", level: "medium" });
  }

  if (!hasDocuments) {
    alerts.push({ title: "No documents indexed", detail: "Add prescription, lab report, discharge summary, scan report, or file reference.", level: "medium" });
  }

  if (!hasFollowUp) {
    alerts.push({ title: "Follow-up not captured", detail: "Add next review date, doctor question, or pending action.", level: "medium" });
  }

  if (stale) {
    alerts.push({ title: "Timeline may be stale", detail: "Latest record is older than 90 days; refresh active medicines, allergies, and readings.", level: "medium" });
  }

  return alerts.length
    ? alerts.slice(0, 6)
    : [{
      title: "No major record gaps",
      detail: "Identity, safety context, documents, timeline, and follow-up are ready for the selected record.",
      level: "low"
    }];
}

function renderRecordEpisodes(records) {
  const list = document.querySelector("#recordEpisodeList");

  if (!list) {
    return;
  }

  const groups = buildRecordEpisodeGroups(records);

  if (!groups.length) {
    renderDashboardList(list, [
      {
        title: "No care episode yet",
        detail: "Add an episode such as BP follow-up, diabetes review, surgery recovery, or annual check.",
        level: "medium"
      }
    ]);
    return;
  }

  renderDashboardList(list, groups.slice(0, 7).map((group) => ({
    title: group.name,
    detail: `${group.count} record${group.count === 1 ? "" : "s"} - ${group.types.join(", ")} - latest ${formatStoredRecordDate(group.latestDate)}.`,
    level: group.hasFollowUp ? "low" : "medium"
  })));
}

function buildRecordEpisodeGroups(records) {
  const groups = new Map();

  for (const record of records) {
    const name = getRecordEpisodeLabel(record);
    const existing = groups.get(name) || {
      name,
      count: 0,
      types: new Set(),
      latestDate: record.date || record.updatedAt || "",
      hasFollowUp: false
    };

    existing.count += 1;
    existing.types.add(formatRecordType(record.type));
    existing.hasFollowUp = existing.hasFollowUp || Boolean(record.followUp);

    if (String(record.date || record.updatedAt || "") > String(existing.latestDate || "")) {
      existing.latestDate = record.date || record.updatedAt || existing.latestDate;
    }

    groups.set(name, existing);
  }

  return Array.from(groups.values())
    .map((group) => ({
      ...group,
      types: Array.from(group.types).slice(0, 3)
    }))
    .sort((a, b) => String(b.latestDate || "").localeCompare(String(a.latestDate || "")));
}

function getRecordEpisodeLabel(record = {}) {
  if (record.episode) {
    return compactText(record.episode, 42);
  }

  const firstTag = parseRecordTags(record.tags)[0];
  if (firstTag) {
    return compactText(firstTag, 42);
  }

  if (record.conditions) {
    return compactText(record.conditions.split(/[,;\n]+/)[0], 42);
  }

  return formatRecordType(record.type);
}

function renderRecordDocumentVault(records) {
  const list = document.querySelector("#recordDocumentVaultList");

  if (!list) {
    return;
  }

  const documents = getDocumentRecords(records);

  if (!documents.length) {
    renderDashboardList(list, [
      {
        title: "No document indexed",
        detail: "Add lab reports, prescriptions, discharge summaries, scan reports, vaccination records, or insurance papers.",
        level: "medium"
      },
      {
        title: "Safe local behavior",
        detail: "The app stores file names and references locally; keep original files in your secure folder or OneDrive mirror.",
        level: "low"
      }
    ]);
    return;
  }

  const items = documents.slice(0, 8).map((record) => {
    const category = formatRecordDocumentCategory(record.documentCategory) || formatRecordType(record.type);
    const title = record.documentName || record.fileReferences?.split(/\n/)[0] || category;
    const location = record.fileReferences ? `Reference: ${compactText(record.fileReferences.replace(/\s+/g, " "), 88)}` : "No file path entered.";

    return {
      title: `${category}: ${compactText(title, 54)}`,
      detail: `${formatStoredRecordDate(record.date)} - ${record.source || "Local entry"}. ${location}`,
      level: record.fileReferences || record.documentName ? "low" : "medium"
    };
  });

  renderDashboardList(list, items);
}

function getDocumentRecords(records = []) {
  const documentTypes = new Set(["labs", "imaging", "discharge", "document", "insurance", "procedure", "immunization"]);

  return records
    .filter((record) => documentTypes.has(record.type) || record.documentCategory || record.documentName || record.fileReferences)
    .sort((a, b) => String(b.date || b.updatedAt || "").localeCompare(String(a.date || a.updatedAt || "")));
}

function getLatestRecordDate(records = []) {
  return records
    .map((record) => record.updatedAt || record.date || record.createdAt)
    .filter(Boolean)
    .sort()
    .at(-1) || "";
}

function renderRecordVersionHistory(selected) {
  const list = document.querySelector("#recordVersionList");

  if (!list) {
    return;
  }

  if (!selected) {
    renderDashboardList(list, [
      {
        title: "No selected record",
        detail: "Open a record to see created, updated, and correction notes.",
        level: "medium"
      }
    ]);
    return;
  }

  const entries = normalizeRecordCorrectionHistory(selected.correctionHistory);
  const items = [
    {
      title: "Current version",
      detail: `Updated ${formatRecordUpdatedAt(selected.updatedAt)}. Created ${formatRecordUpdatedAt(selected.createdAt)}.`,
      level: "low"
    },
    ...entries.slice(0, 7).map((entry) => ({
      title: entry.note || "Record updated",
      detail: `${formatRecordUpdatedAt(entry.at)} - ${entry.changes.length ? entry.changes.join(", ") : "No field list saved."}`,
      level: "low"
    }))
  ];

  renderDashboardList(list, items);
}

function renderRecordTypeFilters(records, active = "all") {
  const container = document.querySelector("#recordTypeFilters");

  if (!container) {
    return;
  }

  const counts = records.reduce((map, record) => {
    const type = record.type || "profile";
    map[type] = (map[type] || 0) + 1;
    return map;
  }, {});
  const filters = [
    ["all", `All ${records.length}`],
    ...Object.entries(counts)
      .sort(([a], [b]) => formatRecordType(a).localeCompare(formatRecordType(b)))
      .map(([type, count]) => [type, `${formatRecordType(type)} ${count}`])
  ];

  clearNode(container);

  for (const [type, label] of filters) {
    const button = document.createElement("button");
    button.type = "button";
    button.dataset.recordFilter = type;
    button.className = type === active ? "is-active" : "";
    button.setAttribute("aria-pressed", type === active ? "true" : "false");
    button.textContent = label;
    container.append(button);
  }
}

function renderRecordPacket(records, selected) {
  const packet = document.querySelector("#recordPacket");

  if (!packet) {
    return;
  }

  clearNode(packet);

  if (!records.length) {
    const title = document.createElement("strong");
    const detail = document.createElement("span");
    title.textContent = "No packet yet";
    detail.textContent = "Save records to build a timeline, active medicines, alerts, and follow-up summary.";
    packet.append(title, detail);
    return;
  }

  const summary = buildRecordPacketSections(records, selected);

  for (const section of summary) {
    const item = document.createElement("article");
    const title = document.createElement("strong");
    const detail = document.createElement("span");
    title.textContent = section.title;
    detail.textContent = section.detail;
    item.append(title, detail);
    packet.append(item);
  }
}

function buildRecordPacketSections(records, selected) {
  const sorted = [...records].sort((a, b) => String(b.date || b.updatedAt || "").localeCompare(String(a.date || a.updatedAt || "")));
  const latest = sorted.slice(0, 4).map((record) => `${formatStoredRecordDate(record.date)}: ${formatRecordType(record.type)} - ${compactText(record.conditions || record.labs || record.notes || record.medicines || "Stored detail", 56)}`);
  const medicines = uniqueRecordSnippets(records, "medicines", 3);
  const alerts = uniqueRecordSnippets(records, "allergies", 3);
  const followUp = uniqueRecordSnippets(records, "followUp", 3);
  const episodes = buildRecordEpisodeGroups(records).slice(0, 3).map((group) => `${group.name} (${group.count})`);
  const documents = getDocumentRecords(records).slice(0, 4).map((record) => record.documentName || formatRecordDocumentCategory(record.documentCategory) || formatRecordType(record.type));
  const quality = selected ? computeRecordCompleteness(selected) : { score: 0, missing: [] };

  return [
    {
      title: "Selected record",
      detail: selected
        ? `${selected.patientName || "Patient"} - ${formatRecordType(selected.type)} - ${quality.score}% complete${quality.missing.length ? `; missing ${quality.missing.slice(0, 3).join(", ")}` : "; ready to share"}`
        : "No selected record"
    },
    {
      title: "Recent timeline",
      detail: latest.length ? latest.join(" | ") : "No timeline entries yet"
    },
    {
      title: "Care episodes",
      detail: episodes.length ? episodes.join("; ") : "No episodes grouped yet."
    },
    {
      title: "Document vault",
      detail: documents.length ? documents.join("; ") : "No document references saved yet."
    },
    {
      title: "Medicines and alerts",
      detail: `Medicines: ${medicines.length ? medicines.join("; ") : "not recorded"}. Alerts: ${alerts.length ? alerts.join("; ") : "not recorded"}.`
    },
    {
      title: "Follow-up",
      detail: followUp.length ? followUp.join("; ") : "No follow-up actions recorded yet."
    }
  ];
}

function renderRecordChecklist(selected, records) {
  const list = document.querySelector("#recordChecklist");

  if (!list) {
    return;
  }

  const quality = selected ? computeRecordCompleteness(selected) : null;
  const alerts = buildRecordAlertItems(records, selected);
  const items = [
    ...(quality ? [{
      title: `Selected quality ${quality.score}%`,
      detail: quality.missing.length ? `Add ${quality.missing.slice(0, 4).join(", ")}.` : "Core record fields are complete.",
      level: quality.score >= 82 ? "low" : quality.score >= 55 ? "medium" : "high"
    }] : []),
    ...alerts,
    {
      title: "Share packet",
      detail: "Copy or download the doctor-ready packet after checking identity, medicines, allergies, documents, and follow-up.",
      level: "low"
    }
  ].slice(0, 7);

  renderDashboardList(list, items);
}

function uniqueRecordSnippets(records, key, limit = 4) {
  const seen = new Set();
  const snippets = [];

  for (const record of records) {
    const value = String(record[key] || "").trim();
    const normalized = value.toLowerCase();

    if (!value || seen.has(normalized)) {
      continue;
    }

    seen.add(normalized);
    snippets.push(compactText(value.replace(/\s+/g, " "), 86));

    if (snippets.length >= limit) {
      break;
    }
  }

  return snippets;
}

function buildRecordPacketText(records = loadPatientDataRecords(), selected = null) {
  const active = selected || records.find((record) => record.id === (document.querySelector("#recordsInterface")?.dataset.selectedRecord || getSelectedPatientDataRecordId())) || records[0] || null;
  const sections = buildRecordPacketSections(records, active);

  return [
    "Care Nova AI - Patient Record Packet",
    `Generated: ${new Date().toLocaleString()}`,
    "",
    ...sections.flatMap((section) => [`${section.title}:`, section.detail, ""])
  ].join("\n");
}

function copyRecordPacket() {
  const text = buildRecordPacketText();
  const feedback = document.querySelector("#recordLastUpdated");

  if (!navigator.clipboard?.writeText) {
    if (feedback) feedback.textContent = "Copy is not available in this browser. The packet remains visible on screen.";
    return;
  }

  navigator.clipboard.writeText(text)
    .then(() => {
      if (feedback) feedback.textContent = "Doctor-ready packet copied locally.";
    })
    .catch(() => {
      if (feedback) feedback.textContent = "Copy failed. You can still read the packet on screen.";
    });
}

function exportPatientDataRecords() {
  downloadPatientReportJson();
}

function buildPatientReportPayload() {
  const records = loadPatientDataRecords();
  const activeId = document.querySelector("#recordsInterface")?.dataset.selectedRecord || getSelectedPatientDataRecordId() || "";
  const selected = records.find((record) => record.id === activeId) || records[0] || null;
  const history = loadHistory();
  const profile = collectProfile();
  const vitals = collectVitals();
  const context = latestSafetyContext || collectSafetyCommandContext();
  const packetSections = buildRecordPacketSections(records, selected);
  const quality = selected ? computeRecordCompleteness(selected) : { score: 0, missing: [] };
  const recordInsights = {
    readiness: buildRecordReadinessFactors(records, selected),
    alerts: buildRecordAlertItems(records, selected),
    episodes: buildRecordEpisodeGroups(records),
    documents: getDocumentRecords(records).map((record) => ({
      id: record.id,
      type: record.type,
      category: record.documentCategory,
      title: record.documentName,
      date: record.date,
      source: record.source,
      references: record.fileReferences
    }))
  };

  return {
    app: "Care Nova AI",
    type: "patient-specific-health-report",
    generatedAt: new Date().toISOString(),
    patientId,
    patient: profile,
    vitals,
    context,
    storage: {
      scope: "active-patient-only",
      browserKey: getPatientDataRecordsStorageKey(),
      serverFile: recordServerSyncStatus.file || "data/records/patient-records.json",
      syncState: recordServerSyncStatus.state || "local",
      syncMessage: recordServerSyncStatus.message || "Local records available"
    },
    summary: {
      recordCount: records.length,
      selectedRecordId: selected?.id || "",
      selectedRecordType: selected ? formatRecordType(selected.type) : "",
      selectedRecordQuality: quality.score,
      missingSelectedFields: quality.missing,
      documentCount: recordInsights.documents.length,
      episodeCount: recordInsights.episodes.length,
      recentChecks: history.length,
      latestRisk: latestResult?.risk?.label || formatDashboardRiskLabel(history[0]?.risk) || "Ready"
    },
    recordInsights,
    activeRecordId: activeId,
    selectedRecord: selected,
    packetSections,
    records,
    recentHistory: history.slice(0, 12),
    latestHealthCheck: latestResult ? {
      risk: latestResult.risk,
      intents: latestResult.intents,
      plan: latestResult.plan,
      finalResponse: latestResult.finalResponse,
      agentResults: latestResult.agentResults
    } : null
  };
}

function downloadPatientReportJson() {
  const payload = buildPatientReportPayload();

  downloadLocalFile(
    JSON.stringify(payload, null, 2),
    getPatientReportFilename("full-report", "json"),
    "application/json;charset=utf-8"
  );
  setRecordDownloadStatus("Full patient report downloaded.");
}

function downloadPatientReportText() {
  const payload = buildPatientReportPayload();

  downloadLocalFile(
    buildPatientReportText(payload),
    getPatientReportFilename("doctor-note", "txt"),
    "text/plain;charset=utf-8"
  );
  setRecordDownloadStatus("Doctor note downloaded.");
}

function downloadPatientRecordsCsv() {
  const records = loadPatientDataRecords();

  if (!records.length) {
    setRecordDownloadStatus("Save at least one record before downloading CSV.");
    return;
  }

  downloadLocalFile(
    buildPatientRecordsCsv(records),
    getPatientReportFilename("records", "csv"),
    "text/csv;charset=utf-8"
  );
  setRecordDownloadStatus("Patient records CSV downloaded.");
}

function buildPatientReportText(payload) {
  const patient = payload.patient || {};
  const vitals = payload.vitals || {};
  const sections = payload.packetSections || [];
  const selected = payload.selectedRecord;
  const history = payload.recentHistory || [];
  const lines = [
    "Care Nova AI - Patient Report",
    `Generated: ${new Date(payload.generatedAt).toLocaleString()}`,
    `Patient: ${patient.name || "Patient"}${patient.age ? `, ${patient.age}` : ""}`,
    `Patient ID: ${payload.patientId || "not available"}`,
    "",
    "Profile",
    `Conditions: ${patient.conditions || "not recorded"}`,
    `Medicines: ${patient.medications || "not recorded"}`,
    `Allergies: ${patient.allergies || "not recorded"}`,
    `Baseline BP: ${patient.baselineBp || "not recorded"}`,
    `Emergency contact: ${patient.emergencyContact || "not recorded"}`,
    "",
    "Current Readings",
    `BP: ${vitals.systolic || "--"}/${vitals.diastolic || "--"}`,
    `Blood sugar: ${vitals.bloodSugar || "not recorded"}`,
    `Heart rate: ${vitals.heartRate || "not recorded"}`,
    `Temperature C: ${vitals.temperatureC || "not recorded"}`,
    `Oxygen: ${vitals.oxygenSaturation || "not recorded"}`,
    "",
    "Record Summary",
    `Saved records: ${payload.summary?.recordCount || 0}`,
    `Care episodes: ${payload.summary?.episodeCount || 0}`,
    `Document references: ${payload.summary?.documentCount || 0}`,
    `Selected record: ${selected ? `${formatRecordType(selected.type)} on ${formatStoredRecordDate(selected.date)}` : "none"}`,
    `Selected quality: ${payload.summary?.selectedRecordQuality || 0}%`,
    ""
  ];

  for (const section of sections) {
    lines.push(section.title, section.detail || "No detail recorded.", "");
  }

  if (payload.recordInsights?.alerts?.length) {
    lines.push("Missing Data and Safety Gaps");
    for (const item of payload.recordInsights.alerts.slice(0, 6)) {
      lines.push(`- ${item.title}: ${item.detail}`);
    }
    lines.push("");
  }

  if (payload.recordInsights?.episodes?.length) {
    lines.push("Care Episodes");
    for (const item of payload.recordInsights.episodes.slice(0, 6)) {
      lines.push(`- ${item.name}: ${item.count} record${item.count === 1 ? "" : "s"}; ${item.types.join(", ")}`);
    }
    lines.push("");
  }

  if (payload.recordInsights?.documents?.length) {
    lines.push("Document Vault");
    for (const item of payload.recordInsights.documents.slice(0, 8)) {
      lines.push(`- ${item.title || formatRecordDocumentCategory(item.category) || formatRecordType(item.type)} (${item.date || "no date"}): ${item.references || "no file reference"}`);
    }
    lines.push("");
  }

  if (history.length) {
    lines.push("Recent Checks");
    for (const item of history.slice(0, 6)) {
      lines.push(`- ${formatRecordUpdatedAt(item.at || item.createdAt || new Date().toISOString())}: ${formatDashboardRiskLabel(item.risk) || item.risk || "Ready"} - ${compactText(item.message || "Saved check", 120)}`);
    }
    lines.push("");
  }

  if (payload.latestHealthCheck?.finalResponse) {
    lines.push("Latest Care Reply");
    lines.push(payload.latestHealthCheck.finalResponse.summary || payload.latestHealthCheck.finalResponse.title || "Latest response available.");
    const nextSteps = payload.latestHealthCheck.finalResponse.whatToDoNow || [];
    if (nextSteps.length) {
      lines.push("Next steps:");
      for (const step of nextSteps.slice(0, 5)) {
        lines.push(`- ${step}`);
      }
    }
    lines.push("");
  }

  lines.push("Storage");
  lines.push(`Scope: ${payload.storage?.scope || "active-patient-only"}`);
  lines.push(`Local status: ${payload.storage?.syncMessage || "Local records available"}`);
  lines.push("");
  lines.push("Note: This report organizes patient information for review and does not replace clinical care.");

  return lines.join("\n");
}

function buildPatientRecordsCsv(records) {
  const headers = [
    "Patient",
    "Age",
    "Type",
    "Date",
    "Episode",
    "Tags",
    "Source",
    "Document Category",
    "Document",
    "File References",
    "Conditions",
    "Allergies",
    "Medicines",
    "Vitals",
    "Labs",
    "Notes",
    "Follow-up",
    "Updated"
  ];
  const rows = records.map((record) => [
    record.patientName,
    record.age,
    formatRecordType(record.type),
    record.date,
    record.episode,
    formatRecordTags(record.tags),
    record.source,
    formatRecordDocumentCategory(record.documentCategory),
    record.documentName,
    record.fileReferences,
    record.conditions,
    record.allergies,
    record.medicines,
    record.vitals,
    record.labs,
    record.notes,
    record.followUp,
    record.updatedAt
  ]);

  return [headers, ...rows]
    .map((row) => row.map(escapeCsvValue).join(","))
    .join("\r\n");
}

function escapeCsvValue(value) {
  const text = String(value ?? "").replace(/\r?\n/g, " ").trim();
  return /[",]/.test(text) ? `"${text.replace(/"/g, '""')}"` : text;
}

function getPatientReportFilename(label, extension) {
  const profile = collectProfile();
  const name = sanitizeFilenamePart(profile.name || patientId || "patient");
  const stamp = new Date().toISOString().slice(0, 10);

  return `care-nova-${name}-${label}-${stamp}.${extension}`;
}

function sanitizeFilenamePart(value) {
  return String(value || "patient")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 40) || "patient";
}

function downloadLocalFile(content, filename, type) {
  const blob = new Blob([content], { type });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");

  link.href = url;
  link.download = filename;
  document.body.append(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
}

function setRecordDownloadStatus(message) {
  const status = document.querySelector("#recordDownloadStatus") || document.querySelector("#recordLastUpdated");

  if (status) {
    status.textContent = message;
  }
}

function setRecordFormStatus(message) {
  const status = document.querySelector("#recordFormStatus");

  if (status) {
    status.textContent = message;
  }
}

function formatRecordUpdatedAt(value) {
  const date = new Date(value);

  if (Number.isNaN(date.getTime())) {
    return formatStoredRecordDate(value);
  }

  return date.toLocaleString([], { month: "short", day: "numeric", hour: "2-digit", minute: "2-digit" });
}

function formatRecordVisitDepartment(value) {
  return visitDepartmentCatalog[value]?.label || value || "Not selected";
}

