function invalidateInsuranceAnalysisMemo() {
  insuranceAnalysisMemo.signature = "";
  insuranceAnalysisMemo.analysis = null;
}

function getInsuranceAnalysisSignature(input = {}) {
  const stableInput = { ...input };
  delete stableInput.id;
  delete stableInput.createdAt;
  delete stableInput.updatedAt;
  stableInput.documents = [...(stableInput.documents || [])].sort();
  return JSON.stringify(stableInput);
}

function getMemoizedInsuranceAnalysis(input = collectInsuranceInput()) {
  const signature = getInsuranceAnalysisSignature(input);

  if (insuranceAnalysisMemo.signature !== signature) {
    insuranceAnalysisMemo.signature = signature;
    insuranceAnalysisMemo.analysis = buildInsuranceAnalysis(input);
  }

  return insuranceAnalysisMemo.analysis;
}

function getInsuranceCasesSignature(cases = []) {
  return cases
    .map((item) => `${item.id || ""}:${item.updatedAt || ""}:${item.claimStatus || ""}`)
    .join("|");
}

function setInsuranceFieldValues(values = {}) {
  const { controls } = getInsuranceDomCache();

  for (const [idOrKey, value] of Object.entries(values)) {
    const key = insuranceControlSelectors[idOrKey] ? idOrKey : Object.entries(insuranceControlSelectors).find(([, selector]) => selector === `#${idOrKey}`)?.[0];
    const control = key ? controls[key] : document.querySelector(`#${idOrKey}`);

    if (control) {
      control.value = value || "";
    }
  }

  invalidateInsuranceAnalysisMemo();
}

function initializeInsuranceGuide() {
  const dom = getInsuranceDomCache();
  const insurance = dom.root;

  if (!insurance || insurance.dataset.insuranceReady === "true") {
    return;
  }

  const scheduleGuidanceRender = createDeferredTask(() => {
    invalidateInsuranceAnalysisMemo();
    renderInsuranceGuidance(false);
  }, 220);
  const flushGuidanceRender = () => {
    invalidateInsuranceAnalysisMemo();
    scheduleGuidanceRender.flush();
  };
  const scheduleCasesRender = createDeferredTask(() => renderInsuranceCases(), 120);

  dom.loadExampleButton?.addEventListener("click", fillInsuranceExample);
  dom.analyzeButton?.addEventListener("click", () => runInsuranceGuidanceReview(dom.analyzeButton));
  dom.saveButton?.addEventListener("click", saveInsuranceCase);
  dom.resetButton?.addEventListener("click", clearInsuranceForm);
  dom.eobExampleButton?.addEventListener("click", fillInsuranceEobExample);
  dom.samplePackButton?.addEventListener("click", seedInsuranceSampleCases);
  dom.markRequiredDocsButton?.addEventListener("click", markInsuranceRequiredDocuments);
  dom.clearDocsButton?.addEventListener("click", clearInsuranceDocuments);
  dom.planButton?.addEventListener("click", () => {
    renderInsurancePlanAdvice();
    activateWorkspaceSubtab("insurance", "coverage", true);
  });
  dom.planExampleButton?.addEventListener("click", fillInsurancePlanExample);
  dom.copyPacketButton?.addEventListener("click", copyInsurancePacket);
  dom.copyAppealButton?.addEventListener("click", copyInsuranceAppealLetter);
  dom.downloadAppealButton?.addEventListener("click", downloadInsuranceAppealLetter);
  dom.exportCasesButton?.addEventListener("click", exportInsuranceCases);
  dom.caseSearch?.addEventListener("input", scheduleCasesRender);
  dom.caseSearch?.addEventListener("search", () => renderInsuranceCases(undefined, { force: true }));

  for (const control of dom.dataControls) {
    control.addEventListener("input", scheduleGuidanceRender);
    control.addEventListener("change", flushGuidanceRender);
  }

  for (const checkbox of dom.docCheckboxes) {
    checkbox.addEventListener("change", flushGuidanceRender);
  }

  dom.caseList?.addEventListener("click", (event) => {
    const openButton = event.target.closest("[data-open-insurance-case]");
    const deleteButton = event.target.closest("[data-delete-insurance-case]");

    if (openButton) {
      openInsuranceCase(openButton.dataset.openInsuranceCase);
    }

    if (deleteButton) {
      deleteInsuranceCase(deleteButton.dataset.deleteInsuranceCase);
    }
  });

  setDefaultInsuranceFields();
  insurance.dataset.insuranceReady = "true";
  renderInsuranceGuidance(false);
  renderInsuranceCases();
}

function setDefaultInsuranceFields() {
  const { controls } = getInsuranceDomCache();
  const date = controls.serviceDate;
  const member = controls.memberName;

  if (date && !date.value) {
    date.value = formatDateForInput(new Date());
  }

  if (member && !member.value) {
    member.value = elements.profileName?.value || defaultProfile.name;
  }
}

