    claimNumber: controls.claimNumber?.value.trim() || "",
    provider: controls.provider?.value.trim() || "",
    serviceDate: controls.serviceDate?.value || formatDateForInput(new Date()),
    amount: controls.amount?.value.trim() || "",
    issue: controls.issue?.value.trim() || "",
    denialReason: controls.denialReason?.value.trim() || "",
    appealDeadline: controls.appealDeadline?.value || "",
    submissionDeadline: controls.submissionDeadline?.value || "",
    externalReviewDeadline: controls.externalReviewDeadline?.value || "",
