    finalBillAmount: controls.finalBillAmount?.value.trim() || "",
    eobText: controls.eobText?.value.trim() || "",
    annualPremium: controls.annualPremium?.value.trim() || "",
    deductible: controls.deductible?.value.trim() || "",
