function buildInsuranceSampleFileReferences(sampleCase = {}) {
  const caseSlug = String(sampleCase.claimNumber || sampleCase.id || "insurance-sample")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");

  return (sampleCase.documents || [])
    .slice(0, 8)
    .map((doc) => {
      const extension = doc === "doctor-note" ? "txt" : doc === "claim-form" ? "pdf" : "pdf";
      return `${insuranceDocumentLabels[doc] || doc}: ${doc}-${caseSlug}.${extension}`;
    })
    .join("\n");
}

function syncInsuranceSampleCasesToPatientRecords(sampleCases = []) {
  try {
    const profile = collectProfile();
    let records = loadPatientDataRecords();
    let selectedRecordId = "";

    for (const item of sampleCases) {
      const analysis = buildInsuranceAnalysis(item);
      const record = normalizePatientDataRecordForClient({
        id: `record-${item.id}`,
        createdAt: item.createdAt,
        updatedAt: item.updatedAt,
        patientName: item.memberName || profile.name || defaultProfile.name,
        age: profile.age || "",
        type: "insurance",
        date: item.serviceDate || formatDateForInput(new Date()),
        episode: formatInsuranceClaimType(item.claimType),
        tags: ["insurance", item.claimType, item.claimStatus, analysis.path?.label || ""].filter(Boolean).join(", "),
        source: "Insurance sample pack",
        documentCategory: "insurance-paper",
        documentName: `${formatInsuranceClaimType(item.claimType)} sample packet`,
        fileReferences: buildInsuranceSampleFileReferences(item),
        conditions: profile.conditions || "",
        allergies: profile.allergies || "",
        medicines: profile.medications || "",
        vitals: summarizeVitalsForRecord(collectVitals()),
        labs: [
          item.eobText ? compactText(item.eobText, 220) : "",
          `Provider ${formatInsuranceMoney(item.providerCharge || item.amount)}, allowed ${formatInsuranceMoney(item.allowedAmount)}, paid ${formatInsuranceMoney(item.paidAmount)}, patient ${formatInsuranceMoney(item.patientResponsibility)}.`
        ].filter(Boolean).join("\n"),
        notes: [
          item.issue ? `Issue: ${item.issue}` : "",
          item.denialReason ? `Reason: ${item.denialReason}` : "",
          item.documentNotes ? `Notes: ${item.documentNotes}` : "",
          analysis.missingDocs.length
            ? `Missing for this path: ${analysis.missingDocs.map((doc) => insuranceDocumentLabels[doc] || doc).join(", ")}.`
            : "Required documents for this sample path look complete."
        ].filter(Boolean).join("\n\n"),
        followUp: analysis.nextActions.slice(0, 3).join("\n"),
        versionNote: "Seeded from Insurance sample pack."
      });

      record.correctionHistory = buildRecordCorrectionHistory(null, record);
      records = [record, ...records.filter((existing) => existing.id !== record.id)].slice(0, 300);
      selectedRecordId = record.id;
    }

    savePatientDataRecordsLocal(records);

    if (selectedRecordId) {
      setSelectedPatientDataRecordId(selectedRecordId);
    }

    renderPatientDataRecords();

    if (selectedRecordId) {
      persistPatientDataRecords(records, selectedRecordId);
    }
  } catch {
    // The sample insurance cases remain usable in the Insurance tab even if Records mirroring is unavailable.
  }
}

function seedInsuranceSampleCases() {
  const sampleCases = buildInsuranceSampleCases();
  const sampleIds = new Set(sampleCases.map((item) => item.id));
  const existingCases = loadInsuranceCases();
  const mergedCases = [
    ...sampleCases,
    ...existingCases.filter((item) => !sampleIds.has(item.id))
  ];

  saveJson(storageKeys.insuranceCases, mergedCases);
  insuranceCasesRenderSignature = "";

  saveLocalStorageValue(storageKeys.selectedInsuranceCase, sampleCases[0].id);

  syncInsuranceSampleCasesToPatientRecords(sampleCases);
  applyInsuranceCase(sampleCases[0]);
  renderInsuranceCases(mergedCases, { force: true });
}

