function buildDashboardDoctorNote(history, context = {}) {
  const profile = context.profile || collectProfile();
  const vitals = context.vitals || collectVitals();
  const dataQuality = context.dataQuality || buildSummaryDataQuality(profile, vitals, history);
  const riskTrend = context.riskTrend || buildSummaryRiskTrend(history);
  const concern = getDashboardConcern(history) || "No current concern added.";
  const riskLabel = latestResult?.risk?.label || formatDashboardRiskLabel(history[0]?.risk) || "Ready";
  const routes = (latestResult?.agentResults || []).map((agent) => agent.name).slice(0, 5);
  const savedRoutes = getRouteNamesFromHistory(history[0]);
  const nextSteps = latestResult?.finalResponse?.whatToDoNow || [];
  const warnings = latestResult?.finalResponse?.warningSigns || [];
  const reasons = latestResult?.risk?.reasons || [];
  const nextAction = context.nextAction || buildSummaryNextAction(history, dataQuality, riskTrend);
  const medicineList = splitSummaryValues(profile.medications);
  const allergyList = splitSummaryValues(profile.allergies);
  const timeline = history.slice(0, 5).map((run) => `- ${formatDateTime(run.at)}: ${formatDashboardRiskLabel(run.risk)} - ${run.message}`);
  const lines = [
    `Care Nova AI summary - ${new Date().toLocaleString()}`,
    `Patient: ${buildPatientLabel(profile)}`,
    `Conditions: ${profile.conditions || "Not added"}`,
    `Medicines: ${profile.medications || "Not added"}`,
    `Allergies: ${profile.allergies || "Not added"}`,
    `Emergency contact: ${profile.emergencyContact || "Not added"}`,
    `Baseline BP: ${profile.baselineBp || "Not added"}`,
    `Current vitals: ${buildVitalsLabel(vitals)}`,
    `Summary quality: ${dataQuality.score}% complete`,
    `Risk trend: ${riskTrend.detail}`,
    "",
    "Latest concern:",
    concern,
    "",
    `Safety level: ${riskLabel}`,
    `Care helpers: ${(routes.length ? routes : savedRoutes).join(", ") || "Not run yet"}`,
    `Next best action: ${nextAction.detail}`,
    `Medicine reconciliation: ${medicineList.length ? medicineList.join(", ") : "Medicines not added"}; allergies: ${allergyList.length ? allergyList.join(", ") : "Allergies not added"}. No prescription or dose change was generated.`
  ];

  if (reasons.length) {
    lines.push("", "Why it was flagged:", ...reasons.slice(0, 4).map((reason) => `- ${reason}`));
  }

  if (nextSteps.length) {
    lines.push("", "Suggested next actions:", ...nextSteps.slice(0, 4).map((step) => `- ${step}`));
  }

  if (warnings.length) {
    lines.push("", "Warning signs to review:", ...warnings.slice(0, 4).map((warning) => `- ${warning}`));
  }

  if (timeline.length) {
    lines.push("", "What happened till now:", ...timeline);
  } else {
    lines.push("", "What happened till now:", "- No completed checks yet.");
  }

  if (dataQuality.missing.length) {
    lines.push("", "Missing context to add:", ...dataQuality.missing.slice(0, 5).map((item) => `- ${item.title}: ${item.detail}`));
  }

  lines.push("", "Boundary: educational summary only. Use a qualified clinician or emergency care for real medical decisions.");
  return lines.join("\n");
}

