function loadJson(key, fallback) {
  try {
    const value = localStorage.getItem(key);
    return value ? JSON.parse(value) : fallback;
  } catch {
    return fallback;
  }
}

function extractPatientIdFromScopedStorageKey(key, baseKey) {
  const scopedPrefix = `${baseKey}.`;

  if (key === baseKey) {
    return defaultProfile.id;
  }

  return key.startsWith(scopedPrefix)
    ? key.slice(scopedPrefix.length) || defaultProfile.id
    : "";
}

function resolveOfflineSyncStorageWrite(key, value, options = {}) {
  if (options.skipOfflineSync) {
    return null;
  }

  if (options.targetPatientId) {
    return {
      patientId: options.targetPatientId,
      reason: options.reason || "local-data-update"
    };
  }

  const scopedStorageRules = [
    { baseKey: storageKeys.history, reason: "history-update" },
    { baseKey: storageKeys.patientDataRecords, reason: "records-update" },
    { baseKey: storageKeys.vitalsDraft, reason: "vitals-draft-update" },
    { baseKey: storageKeys.vitalsBaseline, reason: "vitals-baseline-update" },
    { baseKey: storageKeys.vitalsTrendLog, reason: "vitals-update" },
    { baseKey: storageKeys.medicineVault, reason: "medicine-update" },
    { baseKey: storageKeys.medicineSideEffects, reason: "medicine-side-effect-update" },
    { baseKey: storageKeys.labReportsVault, reason: "lab-report-update" },
    { baseKey: storageKeys.wellnessProgress, reason: "wellness-update" }
  ];

  for (const rule of scopedStorageRules) {
    const patientStorageId = extractPatientIdFromScopedStorageKey(key, rule.baseKey);

    if (patientStorageId) {
      return {
        patientId: patientStorageId,
        reason: options.reason || rule.reason
      };
    }
  }

  const activePatientId = loadJson(storageKeys.activePatientId, patientId || defaultProfile.id) || patientId || defaultProfile.id;

  if (key === storageKeys.activePatientId) {
    return {
      patientId: String(value || activePatientId || defaultProfile.id),
      reason: options.reason || "active-patient-update"
    };
  }

  if (key === storageKeys.profile) {
    return {
      patientId: value?.id || activePatientId,
      reason: options.reason || "patient-profile-update"
    };
  }

  if (key === storageKeys.patientRecords) {
    return {
      patientId: activePatientId,
      reason: options.reason || "patient-profile-update"
    };
  }

  if (key === storageKeys.workspaceDrafts) {
    return {
      patientId: activePatientId,
      reason: options.reason || "workspace-draft-update"
    };
  }

  if (key === storageKeys.insuranceCases) {
    return {
      patientId: activePatientId,
      reason: options.reason || "insurance-update"
    };
  }

  if (key === storageKeys.visitQueue) {
    return {
      patientId: activePatientId,
      reason: options.reason || "visit-update"
    };
  }

  if (key === storageKeys.visitDraft) {
    return {
      patientId: activePatientId,
      reason: options.reason || "visit-draft-update"
    };
  }

  if (key === storageKeys.medicineDraft) {
    return {
      patientId: activePatientId,
      reason: options.reason || "medicine-draft-update"
    };
  }

  if (key === storageKeys.wellnessDraft) {
    return {
      patientId: activePatientId,
      reason: options.reason || "wellness-draft-update"
    };
  }

  if (key === storageKeys.labReportDraft) {
    return {
      patientId: activePatientId,
      reason: options.reason || "lab-report-draft-update"
    };
  }

  if (key === storageKeys.labReportContext) {
    return {
      patientId: activePatientId,
      reason: options.reason || "lab-report-context-update"
    };
  }

  if (key === storageKeys.selectedInsuranceCase) {
    return {
      patientId: activePatientId,
      reason: options.reason || "insurance-selection-update"
    };
  }

  if (key === storageKeys.safetyEvents) {
    return {
      patientId: activePatientId,
      reason: options.reason || "safety-update"
    };
  }

  if (key === storageKeys.localPrivacyMode) {
    return {
      patientId: activePatientId,
      reason: options.reason || "privacy-update"
    };
  }

  return null;
}

function queueOfflineSyncForStorageWrite(key, value, options = {}) {
  const offlineSyncTarget = resolveOfflineSyncStorageWrite(key, value, options);

  if (offlineSyncTarget) {
    queueBrowserStateSync(offlineSyncTarget.reason, {
      targetPatientId: offlineSyncTarget.patientId
    });
  }
}

function saveLocalStorageValue(key, value, options = {}) {
  const { syncValue = value, ...syncOptions } = options;

  try {
    localStorage.setItem(key, String(value ?? ""));
    queueOfflineSyncForStorageWrite(key, syncValue, syncOptions);
  } catch {
    // Local storage can be disabled; the demo still works without persistence.
  }
}

function removeLocalStorageValue(key, options = {}) {
  try {
    localStorage.removeItem(key);
    queueOfflineSyncForStorageWrite(key, null, options);
  } catch {
    // Local storage can be disabled; the demo still works without persistence.
  }
}

function saveJson(key, value, options = {}) {
  try {
    saveLocalStorageValue(key, JSON.stringify(value), {
      ...options,
      syncValue: value
    });
  } catch {
    // Local storage can be disabled; the demo still works without persistence.
  }
}

async function copyText(text) {
  if (!text) {
    return false;
  }

  try {
    if (navigator.clipboard?.writeText) {
      await navigator.clipboard.writeText(text);
      return true;
    }
  } catch {
    // Fall through to the textarea fallback.
  }

  try {
    const textarea = document.createElement("textarea");
    textarea.value = text;
    textarea.setAttribute("readonly", "");
    textarea.style.position = "fixed";
    textarea.style.left = "-9999px";
    textarea.style.top = "0";
    document.body.append(textarea);
    textarea.focus();
    textarea.select();
    textarea.setSelectionRange(0, textarea.value.length);
    const copied = document.execCommand("copy");
    textarea.remove();
    return copied;
  } catch {
    return false;
  }
}

function selectElementText(node) {
  if (!node) {
    return false;
  }

  try {
    const range = document.createRange();
    const selection = window.getSelection();

    range.selectNodeContents(node);
    selection.removeAllRanges();
    selection.addRange(range);
    return true;
  } catch {
    return false;
  }
}

function formatContextValue(value) {
  const labels = {
    "not-sure": "Duration not sure",
    "under-1-hour": "Under 1 hour",
    "1-6 hours": "1-6 hours",
    "1-3 days": "1-3 days",
    "more-than-3-days": "More than 3 days",
    understand: "Understand symptoms",
    "medicine-safety": "Medicine safety",
    "follow-up": "Plan follow-up",
    urgency: "Know urgency",
    "with-someone": "With someone",
    alone: "Alone now",
    "caregiver-nearby": "Caregiver nearby",
    "emergency-team": "Emergency team contacted",
    "needs-transport": "Needs transport help",
    unknown: "Not sure",
    "safe-ride": "Safe ride available",
    "no-ride": "No safe ride",
    "should-not-drive": "Should not drive",
    "chest-pain": "Chest pain",
    "breathing-trouble": "Breathing trouble",
    "stroke-signs": "Stroke signs",
    fainting: "Fainting",
    "one-sided-weakness": "One-sided weakness",
    "severe-allergy": "Severe allergy",
    "heavy-bleeding": "Heavy bleeding",
    seizure: "Seizure",
    confusion: "Confusion",
    "poison-overdose": "Poison or overdose",
    "self-harm-risk": "Self-harm risk",
    "blood-thinner": "Blood thinner",
    "insulin-or-diabetes": "Insulin or diabetes medicine",
    sedating: "Sedating medicine",
    opioid: "Strong pain medicine",
    antibiotic: "Antibiotic",
    steroid: "Steroid",
    "many-medicines": "Many medicines"
  };

  return labels[value] || value;
}

function compactText(value, maxLength) {
  const text = String(value || "").trim();

  if (text.length <= maxLength) {
    return text;
  }

  return `${text.slice(0, Math.max(0, maxLength - 3))}...`;
}

function toNumber(value) {
  if (value === null || value === undefined || value === "") {
    return null;
  }

  const number = Number(value);
  return Number.isFinite(number) ? number : null;
}

if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", initializeCareNovaApp, { once: true });
} else {
  initializeCareNovaApp();
}
